            {
                var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();

                if (!dbContext.ApplicationUsers.AnyAsync().Result)
                {
                    var usuario = new ApplicationUser
                    {
                        Username = "pedroccrl",
                        Nome = "Pedro Câmara",
                        Senha = "812110"
                    };

                    dbContext.ApplicationUsers.Add(usuario);

                    dbContext.SaveChanges();
                }
            }

