using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Infrastructure;
using RealtimeMatches.Infrastructure.Channels;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

protected override async Task ExecuteAsync(CancellationToken stoppingToken)
        {
            try
            {
                CrawlerItem item;
                var count = 0;
                var sw = Stopwatch.StartNew();

                do
                {
                    item = await _crawlerChannelQueue.Dequeue();

                    await _heartbeatService.Send();

                    if (item == null)
                    {
                        _localWebBrowserService.Close();
                        break;
                    }

                    var url = item.ChannelMessage.Request.Data.Url;
                    var pathToClick = item.ChannelMessage.Request.Data.PathToClick;
                    var isOrdered = item.ChannelMessage.Request.Data.OrderedPathsToClick?.Count > 0;

                    _logger.LogInformation($"Dequeued {item.Model} {url}");

                    _localWebBrowserService.Start();

                    if (isOrdered)
                    {
                        var first = item.ChannelMessage.Request.Data.OrderedPathsToClick.First();
                        var last = item.ChannelMessage.Request.Data.OrderedPathsToClick.Last();

                        var htmls = _localWebBrowserService.GetHtmlsPaginationOrdered(
                            url,
                            first,
                            last);

                        await _crawlerChannelQueue.EnqueueProccessed(item, htmls);

                        _logger.LogInformation($"Succefully proccessed ordered {item.Model} {item.ChannelMessage.Request.Data.Url} {htmls?.Count} htmls pages");
                    }
                    else
                    {

                        var html = _localWebBrowserService.GetHtml(url, pathToClick);

                        await _crawlerChannelQueue.EnqueueProccessed(item, html);

                        _logger.LogInformation($"Succefully proccessed {item.Model} {item.ChannelMessage.Request.Data.Url} {html?.Length}bytes");
                    }

                    count++;

                    if (count > _maxUrls)
                    {
                        _logger.LogWarning($"Limite de urls {count} do pod atigindo.");
                        break;
                    }

                    if (sw.Elapsed.TotalSeconds > _timeoutSec)
                    {
                        _logger.LogWarning($"Limite de tempo {sw.Elapsed.TotalSeconds}s do pod atigindo.");
                        break;
                    }

                } while (item != null);

                await Task.Delay(5000);

                _localWebBrowserService.Close();

                _applicationLifetime.StopApplication();
            }
            catch (System.Exception e)
            {
                _logger.LogError(e, "Erro");

                await Task.Delay(5 * 1 * 1000);
                _applicationLifetime.StopApplication();
            }
        }

