using Amazon;
using Amazon.EC2;
using Amazon.EC2.Model;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Threading.Tasks;

public async Task<bool> Restart()
        {
            var status = await GetStatus();
            if (status == "running")
            {
                await Stop();
            }

            _logger.LogInformation($"Restarting instance: {_instanceId}. Status: {status}");

            while (status != "stopped")
            {
                _logger.LogInformation($"Stoping instance: {_instanceId}. Status: {status}");
                status = await GetStatus();

                await Task.Delay(1000);
            }

            await Start();

            while (status != "running")
            {
                status = await GetStatus();
                _logger.LogInformation($"Starting instance: {_instanceId}. Status: {status}");

                await Task.Delay(1000);
            }

            _logger.LogInformation($"Started instance: {_instanceId}. Status: {status}");

            return true;
        }

