public class HeartbeatService
    {
        private readonly ICacheService _cacheService;
        private readonly IConfiguration _configuration;
        private readonly ILogger<HeartbeatService> _logger;

        const string _prefixKey = "Heartbeat";

        public HeartbeatService(
            ICacheService cacheService,
            IConfiguration configuration,
            ILogger<HeartbeatService> logger)
        {
            _cacheService = cacheService;
            _configuration = configuration;
            _logger = logger;
        }

        public async Task Send()
        {
            var serviceName = _configuration.GetValue<string>("ServiceName", "_");
            if (serviceName ==  "_")
            {
                _logger.LogError("ServiceName not defined.");
                return;
            }

            var check = new HeartbeatModel(serviceName);

            await _cacheService.HashSetAsync(_prefixKey, check.ServiceName, check);
        }

        public async Task<List<HeartbeatModel>> GetAllHeartbeat()
        {
            var healths = await _cacheService.HashGetAllObjects<HeartbeatModel>(_prefixKey);

            return healths;
        }

        public async Task<List<HeartbeatModel>> GetHeartbeatsNotUpdateInMinutes(int minutes)
        {
            var checks = await GetAllHeartbeat();

            var uncheckeds = checks.Where(c => (DateTime.UtcNow - c.LastUpdate).TotalMinutes >= minutes).ToList();

            return uncheckeds;
        }

        public async Task AlertSended(HeartbeatModel heartbeat)
        {
            heartbeat.LastAlert = DateTime.UtcNow;

            await _cacheService.HashSetAsync(_prefixKey, heartbeat.ServiceName, heartbeat);
        }
    }

