using RealtimeMatches.Domain.Entities;
using System.Net;
using System.Net.Http;
using System.Text;
using System.Threading.Tasks;

public class HttpClientService
{
    private readonly HttpClient _httpClient;

    public HttpClientService(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<(string, HttpStatusCode)> SendRequest(ChannelRequest request)
    {
        var data = request.Data;

        var method = HttpMethod.Get;
        if (!string.IsNullOrEmpty(data.Body))
        {
            method = new HttpMethod(data.Method);
        }

        var requestMessage = new HttpRequestMessage(method, data.Url);
        if (method == HttpMethod.Post)
            requestMessage.Content = new StringContent(data.Body, Encoding.UTF8, "application/json");

        if (data.Headers != null)
        {
            foreach (var item in data.Headers)
            {
                requestMessage.Headers.TryAddWithoutValidation(item.Key, item.Value);
            }
        }

        var response = await _httpClient.SendAsync(requestMessage);

        var body = await response.Content.ReadAsStringAsync();

        return (body, response.StatusCode);
    }
}

