public List<string> GetHtmlsPaginationOrdered(string url, string leftXPathClick, string rightXPathClick)
        {
            _logger.LogInformation("Crawling Htmls" + url);

            var htmls = new List<string>();

            try
            {
                _navigation.GoToUrl(url);

                var page = 0;

                do
                {
                    Task.Delay(1500).Wait();
                    var html = _driver.PageSource;

                } while (ClickXPathIfExists(leftXPathClick));

                do
                {
                    Task.Delay(1500).Wait();
                    var html = _driver.PageSource;

                    page++;

                    if (page > 0)
                        htmls.Add(html);

                } while (ClickXPathIfExists(rightXPathClick));

                return htmls;
            }
            catch (Exception e)
            {
                _logger.LogError(e, $"Erro inesperado ao buscar url {url}");
                return null;
            }
        }

