            x.UsingAmazonSqs((context, cfg) =>
            {
                cfg.Host(busConfig.AmazonSqs.Region, h =>
                {
                    h.AccessKey(busConfig.AmazonSqs.AccessKey);
                    h.SecretKey(busConfig.AmazonSqs.SecretKey);

                    h.Scope(scopePrefix);

                    h.EnableScopedTopics();
                });

                cfg.ConfigureEndpoints(context, new DefaultEndpointNameFormatter($"{ENDPOINT}-{scopePrefix}-", false));
            });
        });

        return services;
    }

    public static IServiceCollection AddInMemoryBus(this IServiceCollection services)
    {
        services.AddMassTransit(x =>
        {
            x.UsingInMemory((context, cfg) =>
            {
                cfg.ConfigureEndpoints(context);
            });
        });

        return services;
    }
}

