// Namespace: RealtimeMatches.Worker
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using System;
using System.Threading;
using System.Threading.Tasks;

public class CacheExpurgeWorker : BackgroundService
{
    private readonly IPartidaCacheService _partidaCacheService;
    private readonly ICacheService _cacheService;
    private readonly ILogger<CacheExpurgeWorker> _logger;

    public CacheExpurgeWorker(
        IPartidaCacheService partidaCacheService,
        ICacheService cacheService,
        ILogger<CacheExpurgeWorker> logger)
    {
        _partidaCacheService = partidaCacheService;
        _cacheService = cacheService;
        _logger = logger;
    }

    protected async override Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (true)
        {
            var daysWithNoData = 0;
            var agendaCacheDate = DateTime.UtcNow.AddDays(-30);
            while (daysWithNoData < 7)
            {
                var partidaIds = await _partidaCacheService.ListPartidasDate(agendaCacheDate);
                foreach (var id in partidaIds.Value)
                {
                    var deleted = await _partidaCacheService.DeletePartida(id, agendaCacheDate);
                    if (deleted)
                    {
                        _logger.LogWarning($"Partida {id} deletada pelo Expurge.");
                    }
                }

                await _cacheService.DeleteAsync($"{PartidaCacheService.PrefixKey}:{agendaCacheDate:yyyyMMdd}");
                await _cacheService.DeleteAsync($"{PartidaCacheService.PrefixKey}:Partida:{agendaCacheDate:yyyyMMdd}:*");

                if (partidaIds.Value.Count == 0)
                {
                    daysWithNoData++;
                }
                else
                {
                    daysWithNoData = 0;
                }

                agendaCacheDate = agendaCacheDate.AddDays(-1);
            }

            await Task.Delay(1000 * 60 * 60 * 12);
        }
    }
}

