// Namespace: RealtimeMatches.Worker
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Infrastructure;
using System;
using System.Threading;
using System.Threading.Tasks;

public class MonitorWorker : BackgroundService
    {
        private readonly ILogger<MonitorWorker> _logger;
        private readonly HeartbeatService _heartbeatService;
        private readonly IAlertService _alertService;
        private readonly int _heartbeatInterval;
        private readonly int _alertInterval;

        public MonitorWorker(
            ILogger<MonitorWorker> logger,
            HeartbeatService heartbeatService,
            IAlertService alertService,
            IConfiguration configuration)
        {
            _logger = logger;
            _heartbeatService = heartbeatService;
            _alertService = alertService;
            _heartbeatInterval = configuration.GetValue("HeartbeatTimeoutInterval", 1);
            _alertInterval = configuration.GetValue("HeartbeatAlertInterval", 5);
        }

        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
        {
            while (!stoppingToken.IsCancellationRequested)
            {
                try
                {
                    var missingsHeartbeats = await _heartbeatService.GetHeartbeatsNotUpdateInMinutes(_heartbeatInterval);
                    foreach (var heartbeat in missingsHeartbeats)
                    {
                        if (!heartbeat.LastAlert.HasValue ||
                            (DateTime.UtcNow - heartbeat.LastAlert.Value).TotalMinutes >= _alertInterval)
                        {
                            var msg =
                                $"Missing heartbeat for service {heartbeat.ServiceName}. " +
                                $"Last updated {(DateTime.UtcNow - heartbeat.LastUpdate).TotalMinutes:0.00} minutes ago";

                            _logger.LogWarning(msg);

                            await _alertService.SendAlert(msg, true);
                            await _heartbeatService.AlertSended(heartbeat);
                        }
                    }

                    await Task.Delay(10000, stoppingToken);
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Erro no MonitorWorker");
                }
            }
        }
    }

