[Test]
	public async Task SaveAsync_GivenAnUpdatedProjection_ShouldDeleteOldIndexInCacheService()
	{
		var projection = _fixture.Create<FakeProjection>();
		var projectionCacheKey = "FakeProjection:" + projection.Id;
		var projectionOldIndexValue = projection.Indexes.First().Value;

		_cacheService
			.Setup(x => x.GetObjectAsync<FakeProjection>(It.Is<string>(key => key == projectionCacheKey)))
			.ReturnsAsync(projection);

		_cacheService
			.Setup(x =>
				x.HashGetAsync<List<string>>(
					It.Is<string>(key => key == FakeProjectionSecondaryIdIndexKey),
					It.Is<string>(field => field == projectionOldIndexValue))
				)
			.ReturnsAsync(new List<string> { projection.Id });

		var updatedProjection = _fixture
			.Build<FakeProjection>()
			.With(x => x.Id, projection.Id)
			.Create();

		await _cacheReadModel.SaveAsync(new ReadModelLocker(), updatedProjection);

		_cacheService
			.Verify(x =>
				x.HashSetAsync(
					It.Is<string>(key => key == FakeProjectionSecondaryIdIndexKey),
					It.Is<string>(field => field == projectionOldIndexValue),
					It.Is<List<string>>(ids => ids.Count == 0))
				, Times.Once);

		var projectionNewIndexValue = updatedProjection.Indexes.First().Value;

		_cacheService
			.Verify(x =>
				x.HashSetAsync(
					It.Is<string>(key => key == FakeProjectionSecondaryIdIndexKey),
					It.Is<string>(field => field == projectionNewIndexValue),
					It.Is<List<string>>(ids => ids.Contains(updatedProjection.Id)))
