    private readonly ServiceProvider _serviceProvider;

    public ProviderMappingDbSetTests()
    {
        var builder = new ConfigurationBuilder()
                .SetBasePath(Directory.GetCurrentDirectory())
                .AddJsonFile("appsettings.json", true, true)
                .AddEnvironmentVariables();

        var configuration = builder.Build();

        _services = new ServiceCollection();

        _services.AddSingleton<IConfiguration>(configuration);
        _services.AddLogging(configure => configure.AddDebug().AddConsole().SetMinimumLevel(LogLevel.Debug));

        _services.AddInfrastructure(configuration);

        _serviceProvider = _services.BuildServiceProvider();
    }

    [Test]
    public async Task SaveAsync_GivenAMappingWithMetadata_ShouldNotThrowException()
    {
        var mapping = ProviderMapping.CreateMapping<IgnorableEntityMapping>("Provider", Guid.NewGuid(), "123", "1", "2", "3", "4");

        var metadata = _fixture.Create<TestingMetadata>();
        mapping.IncludeMetadata(metadata);

        using var scope = _serviceProvider.CreateScope();

        var dbContext = scope.ServiceProvider.GetService<ApplicationDbContext>();

        dbContext.ProviderMappings.Add(mapping);
        await dbContext.SaveChangesAsync();

        var resultMapping = await dbContext.ProviderMappings.FirstAsync(x => x.Id == mapping.Id);

        Assert.IsNotNull(resultMapping);

        var resultMetadata = resultMapping.Metadata as TestingMetadata;

        resultMetadata.Should().NotBeNull().And.BeEquivalentTo(metadata);

        dbContext.ProviderMappings.Remove(mapping);
        await dbContext.SaveChangesAsync();
    }

    public class TestingMetadata
