public class EventMessage
{
    [JsonProperty]
    public string IdempotencyKey { get; set; }

    [JsonProperty]
    public DateTime PublishedAt { get; set; }

    [JsonProperty]
    public string EventName { get; set; }

    [JsonProperty]
    public object EventBody { get; set; }

    public static EventMessage BuildEventMessage(INotification notification)
    {
        var type = notification.GetType().FullName;

        var eventMessage = new EventMessage
        {
            IdempotencyKey = $"{notification.GetType().Name}:{DateTime.UtcNow.Ticks}:{Guid.NewGuid():N}",
            PublishedAt = DateTime.Now,
            EventName = type,
            EventBody = notification
        };

        return eventMessage;
    }
}

// File: RealtimeMatches.Infrastructure.Bus/Messaging/EventsConsumer.cs
// Namespace: RealtimeMatches.Infrastructure.Bus.Messaging
using MassTransit;
using MediatR;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System.Reflection;
using System.Text.Json;

public class EventsConsumer : IConsumer<EventMessage>
{
    private readonly IMediator _mediator;
    private readonly ILogger<EventsConsumer> _logger;
    private readonly IApmService _apmService;

    public EventsConsumer(IMediator mediator, ILogger<EventsConsumer> logger, IApmService apmService)
    {
        _mediator = mediator;
        _logger = logger;
        _apmService = apmService;
    }

    public async Task Consume(ConsumeContext<EventMessage> context)
    {
        var message = context.Message;

        var messageAttributes = new Dictionary<string, object>
        {
            { "EventName", message.EventName }
        };
        // ToDo: Tratar chave de idempotencia
        try
        {
            var type = Assembly.Load("Providers.Shared.Events").GetType(message.EventName);

            var notification = ((JsonElement)message.EventBody).Deserialize(type, new JsonSerializerOptions { PropertyNameCaseInsensitive = true });

            var provider = notification.GetType().GetProperty("Provider")?.GetValue(notification, null)?.ToString();

            messageAttributes.Add("Provider", provider);

            _apmService.RecordCustomEvent("EventIntegrationConsumed", messageAttributes);

            await _mediator.Publish(notification);

            _apmService.RecordCustomEvent("EventIntegrationProcessed", new Dictionary<string, object>(messageAttributes)
            {
                { "EventIntegrationType", notification.GetType().Name }
            });
        }
        catch (Exception e)
        {
            _apmService.RecordCustomEvent("EventIntegrationConsumedError", new Dictionary<string, object>(messageAttributes)
            {
                { "Error", e.Message },
                { "StackTrace", e.StackTrace }
            });

            _logger.LogError(e, e.Message);
        }
    }
}

