public async Task<List<T>> GetListObjectsAsync<T>(string key, int page, int qty)
        {
            var pag = (page - 1) * qty;
            var qtd = qty - 1;

            var values = await Database.ListRangeAsync(key, pag, qtd);
            var list = new List<T>();

            foreach (var json in values)
            {
                list.Add(JsonConvert.DeserializeObject<T>(json));
            }

            return list;
        }

