public async Task Enqueue(CrawlerItem item)
        {
            var key = $"{item.ProviderId}_{item.Model}";

            await _cacheService.HashSetAsync($"{Queuekey}:Set", key, item);

            var itemsInQueue = await _cacheService.GetListObjectsAsync<string>($"{Queuekey}:List", 0, 100);
            if (itemsInQueue.Where(x=>x == key)?.Count() < 2) 
              await _cacheService.ListRightPushAsync($"{Queuekey}:List", key);
        }

