using CSharpFunctionalExtensions;
using Newtonsoft.Json;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Enums;
using System;

public class CrawlerItem
    {
        [JsonProperty]
        public Guid ProviderId { get; private set; }

        [JsonProperty]
        public string Model { get; private set; }

        [JsonProperty]
        public ProviderMessageType MessageType { get; private set; }

        public ChannelMessage ChannelMessage { get; set; }

        public DateTime CreatedAt { get; set; }

        [JsonConstructor]
        private CrawlerItem() { }

        private CrawlerItem(ChannelMessage message)
        {
            ProviderId = message.Request.ProviderId;
            Model = message.Request.Model;
            MessageType = message.Request.MessageType;

            ChannelMessage = message;

            CreatedAt = DateTime.UtcNow;
        }

        public static Result<CrawlerItem> Create(ChannelMessage message)
        {
            if (message.Request.Data.Type == ProviderType.Crawler)
            {
                var item = new CrawlerItem(message);

                return Result.Success(item);
            }

            return Result.Failure<CrawlerItem>($"ChannelData is not of Crawler type");
        }
    }

