using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Concurrent;
using System.Threading.Tasks;

public async Task PublishRequest(ChannelRequest channelRequest)
        {
            if (channelRequest.Data.Type != ProviderType.Crawler)
            {
                _logger.LogError($"Request Data nao era um formato valido.  Model: {channelRequest.Model}, {channelRequest.ProviderId}, {channelRequest.Data.GetType().Name}");
                return;
            }

            if (string.IsNullOrEmpty(channelRequest.Data.Url))
            {
                _logger.LogWarning($"Url nao pode ser nula. Model: {channelRequest.Model}, {channelRequest.ProviderId}");
                return;
            }

            var message = new ChannelMessage(channelRequest);

            var itemResult = CrawlerItem.Create(message);
            if (itemResult.IsFailure)
            {
                _logger.LogError(itemResult.Error);
                return;
            }

            var item = itemResult.Value;

            await _crawlerChannelQueue.Enqueue(item);
        }

