using Amazon.EC2.Model;
using MediatR;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using RealtimeMatches.Application.Channels;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Infrastructure.Caching;
using System;
using System.Net;

public Task PublishRequest(ChannelRequest request)
        {
            if (request.Data.Type != ProviderType.RestApi)
            {
                return Task.CompletedTask;
            }

            Task.Run(async () =>
            {
                using var scope = _scopeFactory.CreateScope();
                var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();
                var configuration = scope.ServiceProvider.GetRequiredService<IConfiguration>();

                var localConn = configuration.GetConnectionString("RedisLocal") ?? configuration.GetConnectionString("RedisConnection");
                var cacheServie = RedisService.NewConnection(localConn);

                var data = request.Data;
                var cacheKey = $"RealtimeMatches:RestApi:{request.ProviderId}:{data.CacheKey}";

                var message = new ChannelMessage(request);

                var command = new RestApiChannelResponseHandler.Contract
                {
                    ChannelMessage = message
                };

                var renewCache = false;

                if (data.CacheTime.HasValue && await cacheServie.KeyExists(cacheKey))
                {
                    var cacheBody = await cacheServie.GetObjectAsync<string>(cacheKey);

                    command.Body = cacheBody;
                    command.StatusCode = (int)HttpStatusCode.NotModified;
                }
                else
                {
                    var response = await _httpClient.SendRequest(request);

                    command.Body = response.Item1;
                    command.StatusCode = (int)response.Item2;

                    renewCache = true;
                }

                var result = await mediator.Send(command);
                if (result.IsSuccess && renewCache && data.CacheTime.HasValue)
                {
                    await cacheServie.SetObjectAsync(cacheKey, command.Body, data.CacheTime.Value);
                }
            }).ConfigureAwait(false);

            return Task.CompletedTask;
        }

