using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using NewRelic.LogEnrichers.Serilog;
using Serilog;

public static class LogExtension
{
    public static IServiceCollection AddLogging(this IServiceCollection services, IConfiguration configuration)
    {
        var loggerBuilder = new LoggerConfiguration()
                      .Enrich.FromLogContext()
                      .Enrich.WithNewRelicLogsInContext()
                      .ReadFrom.Configuration(configuration)
                      .WriteTo.Console();

        var logger = loggerBuilder.CreateLogger();

        services.AddLogging(x => x.AddSerilog(logger));

        return services;
    }

    public static IServiceCollection AddFunctionLogging(this IServiceCollection services, IConfiguration configuration, string functionName)
    {
        var loggerBuilder = new LoggerConfiguration()
                      .Enrich.FromLogContext()
                      .Enrich.WithNewRelicLogsInContext()
                      .ReadFrom.Configuration(configuration)
                      .WriteTo.Console();

        var newRelicSettings = configuration.GetSection("NewRelic").Get<NewRelicSettings>();

        loggerBuilder.WriteTo.NewRelicLogs(
            applicationName: functionName + "Function",
            licenseKey: newRelicSettings.LicenseKey,
            restrictedToMinimumLevel: Serilog.Events.LogEventLevel.Information);

        var logger = loggerBuilder.CreateLogger();

        services.AddLogging(x => x.AddSerilog(logger));

        return services;
    }
}

