using Newtonsoft.Json.Serialization;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System;
using System.Collections.Generic;

public async Task<TResponse> Send<TResponse>(Command<TResponse> request, CancellationToken cancellationToken = default)
    {
        var commandAttributes = new Dictionary<string, object>
        {
            { "CorrelationKey", request.CorrelationKey },
            { "LockKey", request.LockKey },
            { "AggregateId", request.AggregateId },
            { "CommandName", request.GetType().Name },
            { "Metadata", JsonConvert.SerializeObject(request, _jsonSerializerSettings) }
        };

        var response = default(TResponse);

        await Task.Run(async () =>
        {
            try
            {
                var sw = Stopwatch.StartNew();

                using var scope = _scopeFactory.CreateScope();

                var mediator = scope.ServiceProvider.GetService<IMediator>();

                response = await mediator.Send<TResponse>(request, cancellationToken);

                sw.Stop();

                _apmService.RecordCustomEvent("CommandProcessed", new(commandAttributes)
                {
                    { "ProcessingMilliseconds", sw.ElapsedMilliseconds },
                    { "ResponseType", response.GetType().Name }
                });
            }
            catch (Exception e)
            {
                Catch(e, request, commandAttributes);
            }

        }, cancellationToken).ConfigureAwait(false);

        return response;
    }

