using Amazon.Runtime.Internal.Util;
using MassTransit;
using MediatR;
using Microsoft.Extensions.Logging;
using Providers.Shared.Requests.Messaging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Integrations.ResponseHandlers;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System;
using System.Collections.Generic;

public async Task Consume(ConsumeContext<IResourceReplied> context)
    {
        var message = context.Message;

        var messageAttributes = new Dictionary<string, object>
        {
            { "Provider", message.Provider },
            { "MappingId", message.MappingId },
            { "ResourceId", message.ResourceId },
            { "ResourceType", message.ResourceType.ToString() },
            { "ResourceName", message.ResourceName },
        };

        _apmService.RecordCustomEvent("ResourceReplyReceived", messageAttributes);

        try
        {
            var providersDomain = Assembly.Load("Providers.Domain");

            var resourceType = providersDomain.GetType(message.ResourceName);

            var resourceObj = (JsonElement)message.Resource;

            var resource = resourceObj.Deserialize(resourceType, new JsonSerializerOptions
            {
                PropertyNameCaseInsensitive = true,
                IncludeFields = true,

            });

            var notificationType = typeof(ResourceReplyNotification<>).MakeGenericType(resourceType);

            var notification = Activator.CreateInstance(notificationType, resource, message);

            var sw = Stopwatch.StartNew();

            await _mediator.Publish(notification);

            sw.Stop();

            _apmService.RecordCustomEvent("ResourceReplyProcessed", new Dictionary<string, object>(messageAttributes)
            {
                { "NotificationType", notification.GetType().Name },
                { "ElapsedMilliseconds", sw.ElapsedMilliseconds }
            });
        }
        catch (Exception e)
        {
            var exceptionMessageAttributes = new Dictionary<string, object>(messageAttributes)
            {
                { "Message", e.Message },
                { "StackTrace", e.StackTrace },
                {"ExceptionType", e.GetType().Name }
            }; ;

            _apmService.RecordCustomEvent("ResourceReplyError", exceptionMessageAttributes);
        }
    }

