using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Events;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Entities.Fantasia;
using RealtimeMatches.Infrastructure.Persistence.Converters;

public override async Task<int> SaveChangesAsync(CancellationToken cancellationToken = default)
    {
        var appEventsToPublish = new List<ApplicationEvent>();

        var changeSet = ChangeTracker.Entries<Entity>().ToList();
        foreach (var entityEntry in changeSet)
        {
            switch (entityEntry.State)
            {
                case EntityState.Modified:
                    entityEntry.Entity.UpdatedAt = DateTime.UtcNow;
                    break;
                case EntityState.Added:
                    entityEntry.Entity.CreatedAt = DateTime.UtcNow;
                    if (entityEntry.Entity.Id == Guid.Empty)
                    {
                        entityEntry.Entity.Id = Guid.NewGuid();
                    }
                    break;
            }

            if (entityEntry.Entity is ProviderMapping mapping && mapping.Events?.Count > 0)
            {
                appEventsToPublish.AddRange(mapping.Events);
            }
        }

        try
        {
            var i = await base.SaveChangesAsync(cancellationToken);

            foreach (var mappingEvent in appEventsToPublish)
            {
                using var scope = _scopeFactory.CreateScope();

                var mediator = scope.ServiceProvider.GetService<IMediator>();

                await mediator.Publish(mappingEvent, cancellationToken).ConfigureAwait(false);
            }

            return i;
        }
        catch (DbUpdateConcurrencyException ex)
        {
            foreach (var entry in ex.Entries)
            {
                if (entry.Entity is Transmissao)
                {
                    var proposedValues = entry.CurrentValues;
                    var databaseValues = entry.GetDatabaseValues();

                    foreach (var property in proposedValues.Properties)
                    {
                        var proposedValue = proposedValues[property];

                        // TODO: decide which value should be written to database
                        proposedValues[property] = proposedValue;
                    }

                    // Refresh original values to bypass next concurrency check
                    entry.OriginalValues.SetValues(proposedValues);
                }
                else if (entry.Entity is Canal)
                {
                    var proposedValues = entry.CurrentValues;
                    var databaseValues = entry.GetDatabaseValues();

                    foreach (var property in proposedValues.Properties)
                    {
                        var proposedValue = proposedValues[property];

                        // TODO: decide which value should be written to database
                        proposedValues[property] = proposedValue;
                    }

                    // Refresh original values to bypass next concurrency check
                    entry.OriginalValues.SetValues(proposedValues);
                }
                else if (entry.Entity is Agenda agenda)
                {
                    var proposedValues = entry.CurrentValues;
                    var databaseValues = entry.GetDatabaseValues();

                    foreach (var property in proposedValues.Properties)
                    {
                        var proposedValue = proposedValues[property];

                        // TODO: decide which value should be written to database
                        proposedValues[property] = proposedValue;
                    }

                    // Refresh original values to bypass next concurrency check
                    entry.OriginalValues.SetValues(proposedValues);
                }
                else
                {
                    throw new NotSupportedException(
                        "Don't know how to handle concurrency conflicts for "
                        + entry.Metadata.Name);
                }
            }

            return 0;
        }
        catch (DbUpdateException e)
        {
            foreach (var entry in e.Entries)
            {
                if (entry.Entity is Agenda agenda ||
                    entry.Entity is Cobertura cobertura)
                {
                    var proposedValues = entry.CurrentValues;
                    var databaseValues = entry.GetDatabaseValues();

                    foreach (var property in proposedValues.Properties)
                    {
                        var proposedValue = proposedValues[property];

                        // TODO: decide which value should be written to database
                        proposedValues[property] = proposedValue;
                    }

                    // Refresh original values to bypass next concurrency check
                    entry.OriginalValues.SetValues(proposedValues);
                }
                else throw;
            }

            return 0;
        }
        catch (Exception e)
        {
            _logger.LogError(e, "Error publishing ProviderMapping events");

            return 0;
        }
    }

