using Microsoft.EntityFrameworkCore.Metadata.Builders;
using RealtimeMatches.Domain.Entities;
using System;
using System.Text;

public static class ApplicationUserMapConfig
    {
        internal static Action<EntityTypeBuilder<ApplicationUser>> ConfigureMap()
        {
            return entity =>
            {
                entity.HasKey(x => x.Id);

                entity.HasIndex(x => x.Username).IsUnique();

                entity.Property(x => x.Senha)
                    .HasConversion(x => CreateMD5(x),
                                   x => x)
                    .IsRequired();
            };
        }

        public static string CreateMD5(string input)
        {
            // Use input string to calculate MD5 hash
            using System.Security.Cryptography.MD5 md5 = System.Security.Cryptography.MD5.Create();
            byte[] inputBytes = Encoding.ASCII.GetBytes(input);
            byte[] hashBytes = md5.ComputeHash(inputBytes);

            // Convert the byte array to hexadecimal string
            var sb = new StringBuilder();
            for (int i = 0; i < hashBytes.Length; i++)
            {
                sb.Append(hashBytes[i].ToString("X2"));
            }
            return sb.ToString();
        }
    }

