using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Abstractions;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Linq.Expressions;
using System.Threading.Tasks;

/// <summary>
    /// Verificar existencia de antiga projection
    /// Caso tenha, obter indexes
    /// Caso indexes antigos sejam diferentes, deletar
    /// Salvar no hash por id. ex: PartidaProjection:Id:12312312<br></br>
    /// Salvar indexes<br></br>
    ///  - 
    /// </summary>
    /// <param name="locker"></param>
    /// <param name="projection"></param>
    /// <returns></returns>
    public async Task<bool> SaveAsync(ReadModelLocker locker, TProjection projection)
    {
        var newIndexes = projection.Indexes;

        var oldProjection = await _cacheService.GetObjectAsync<TProjection>(GetProjectionKey(projection.Id));
        if (oldProjection != null && oldProjection.Indexes != null)
        {
            var oldIndexes = oldProjection.Indexes;
            foreach (var index in oldIndexes)
            {
                var indexKey = $"{ProjectionIndexKey}:{index.Key}";

                if (index.Value != null && newIndexes.ContainsKey(index.Key) && newIndexes[index.Key] != index.Value)
                {
                    var ids = await _cacheService.HashGetAsync<List<string>>(indexKey, index.Value);
                    ids?.Remove(projection.Id);

                    await _cacheService.HashSetAsync(indexKey, index.Value, ids);
                }
            }
        }

        await _cacheService.SetObjectAsync(GetProjectionKey(projection.Id), projection, TimeSpan.FromDays(3 * 30));

        if (projection.Indexes != null)
        {
            foreach (var index in projection.Indexes)
            {
                var indexKey = $"{ProjectionIndexKey}:{index.Key}";

                var ids = await _cacheService.HashGetAsync<List<string>>(indexKey, index.Value);
                ids ??= new List<string>();

                if (ids.Contains(projection.Id) is false)
                {
                    ids.Add(projection.Id);
                }

                await _cacheService.HashSetAsync(indexKey, index.Value, ids);
            }
        }
        return true;
    }

