public async Task<List<TProjection>> FindAll<TProperty>(System.Linq.Expressions.Expression<Func<TProjection, TProperty>> navigationPropertyPath, TProperty value)
    {
        var expression = (MemberExpression)navigationPropertyPath.Body;
        string name = expression.Member.Name;

        var indexKey = $"{ProjectionIndexKey}:{name}";
        var ids = await _cacheService.HashGetAsync<List<string>>(indexKey, value.ToString());
        if (ids == null)
            return default;

        var getProjections = ids.Select(id => GetByIdAsync(id));

        var projections = await Task.WhenAll(getProjections);

        return projections.Where(x => x != null).ToList();
    }

