using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Abstractions;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Linq.Expressions;
using System.Threading.Tasks;

private async Task<List<string>> GetIdsConditions()
    {
        var joinIds = new List<string>();

        foreach (var condition in _conditions)
        {
            var indexKey = $"{ProjectionIndexKey}:{condition.Key}";

            var ids = await _cacheService.HashGetAsync<List<string>>(indexKey, condition.Value);
            if (ids == null)
            {
                continue;
            }

            if (joinIds.Count == 0)
            {
                joinIds.AddRange(ids);
            }
            else
            {
                var idsToRemove = new List<string>();
                foreach (var id in joinIds)
                {
                    if (!ids.Contains(id))
                    {
                        idsToRemove.Add(id);
                    }
                }

                foreach (var id in idsToRemove)
                {
                    joinIds.Remove(id);
                }
            }
        }

        _conditions = new();

        return joinIds.GroupBy(x => x).Select(x => x.Key).ToList();
    }

