// Namespace: RealtimeMatches.Infrastructure.Persistence.Repositories
// Class: RepositoriesDbContext
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Storage;
using Microsoft.EntityFrameworkCore.Storage.ValueConversion;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Models.Events;
using RealtimeMatches.Application.Common.Repositories;

protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.MapTabelas();

        // Integrations
        modelBuilder.Entity<ProviderMapping>(entity =>
        {
            entity.HasIndex(x => x.EntityId);
            entity.HasIndex(x => x.Type);
            entity.HasIndex(x => new { x.ProviderId, x.ExternalId, x.Type }).IsUnique();

            entity.Property(x => x.Metadata).HasConversion<MetadataConverter>();

            entity.Ignore(x => x.Events);
        });

        modelBuilder.Entity<AggregateEventEntity>(entity =>
        {
            entity.Property(p => p.Metadata).HasColumnType("json");

            entity.HasIndex(x => x.AggregateId);
            entity.HasIndex(x => x.Name);
        });

        // Campeonatos
        modelBuilder.Entity<Campeonato>(entity =>
        {
            entity
                .Property(x => x.Organizacao)
                .HasConversion(new EnumToStringConverter<CampeonatoOrganizacao>())
                .IsRequired();

            entity.Navigation(x => x.Participacoes).AutoInclude();
        });

        modelBuilder.Entity<Participacao>(entity =>
        {
            entity.HasKey(x => new { x.CampeonatoId, x.TimeId });

            entity.HasMany(x => x.Titulos).WithOne(x => x.Participacao).HasForeignKey(x => new { x.CampeonatoId, x.TimeId });

            entity.Navigation(x => x.Titulos).AutoInclude();
        });

        modelBuilder.Entity<Titulo>(entity =>
        {
            entity.HasKey(x => new { x.CampeonatoId, x.TimeId, x.Temporada });
        });

        // Temporadas
        modelBuilder.Entity<Temporada>(entity =>
        {
            entity.HasMany(x => x.Participantes);

            entity.Navigation(x => x.Palcos).AutoInclude();
            entity.Navigation(x => x.Participantes).AutoInclude();
        });

        modelBuilder.Entity<Participante>(entity =>
        {
            entity.HasKey(x => new { x.TemporadaId, x.TimeId });

            entity
                .HasMany(x => x.Jogadores)
                .WithOne(x => x.Participante)
                .HasForeignKey(x => new
                {
                    x.TemporadaId,
                    x.TimeId
                });

            entity.Navigation(x => x.Jogadores).AutoInclude();
        });

        modelBuilder.Entity<JogadorParticipante>(entity =>
        {
            entity.HasKey(x => new { x.JogadorId, x.TemporadaId, x.TimeId });

            entity.OwnsOne(x => x.TimeSecundario, od =>
            {
                od.ToTable("JogadorParticipanteTimeSecundario");

                od.Property(x => x.Tipo).HasConversion(new EnumToStringConverter<TimeTipo>());
            });

            entity.Property(x => x.TimeId).IsRequired();
            entity.Property(x => x.TemporadaId).IsRequired();
            entity.Property(x => x.JogadorId).IsRequired();

            entity.Navigation(x => x.TimeSecundario).AutoInclude();
        });

        modelBuilder.Entity<Rodada>(entity =>
        {
            entity.Navigation(x => x.Times).AutoInclude();

            entity.Property(x => x.MataMata).HasConversion(new EnumToStringConverter<MataMataChave>());

            entity.Ignore(x => x.Tipo);
        });

        modelBuilder.Entity<RodadaTime>(entity =>
        {
            entity.HasKey(x => new { x.RodadaId, x.TimeId });
        });

        modelBuilder.Entity<PalcoTemporada>(entity =>
        {
            entity.HasKey(x => new { x.TemporadaId, x.EstadioId });
        });

        // Partidas
        modelBuilder.Entity<Partida>(entity =>
        {
            entity.OwnsOne(x => x.Placar);
            entity.OwnsOne(x => x.DisputaPenaltis);

            entity
                .OwnsOne(x => x.Situacao)
                .Property(x => x.Status)
                .HasConversion(new EnumToStringConverter<SituacaoStatus>())
                .IsRequired();

            entity.OwnsOne(x => x.Palco, od => { od.ToTable(nameof(Palco)); });

            entity.HasOne(x => x.Mandante).WithOne("MandantePartida").HasForeignKey<Equipe>("MandantePartidaId").OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(x => x.Visitante).WithOne("VisitantePartida").HasForeignKey<Equipe>("VisitantePartidaId").OnDelete(DeleteBehavior.Cascade);

            entity.OwnsMany(x => x.Lances, od =>
            {
                od.ToTable("PartidaLances");

                od.WithOwner().HasForeignKey(x => x.PartidaId);

                od.Property(x => x.Tipo)
                  .HasConversion(new EnumToStringConverter<TipoLance>())
                  .IsRequired(true);

                od.OwnsOne(x => x.JogadorPrincipal);
                od.OwnsOne(x => x.JogadorSecundario);
                od.OwnsOne(x => x.Momento);

                od.Navigation(x => x.JogadorPrincipal).IsRequired();
                od.Navigation(x => x.JogadorSecundario).IsRequired();
                od.Navigation(x => x.Momento).IsRequired();
            });

            entity.Navigation(x => x.Mandante).AutoInclude();
            entity.Navigation(x => x.Visitante).AutoInclude();
        });

        modelBuilder.Entity<Equipe>(entity =>
        {
            entity.Ignore(x => x.PartidaId);

            entity.HasMany(x => x.Titulares).WithOne("Equipe").HasForeignKey("EquipeId");
            entity.HasMany(x => x.Reservas).WithOne("Equipe").HasForeignKey("EquipeId");

            entity.HasOne(x => x.Comandante).WithOne();

            entity.Navigation(x => x.Titulares).AutoInclude();
            entity.Navigation(x => x.Reservas).AutoInclude();
            entity.Navigation(x => x.Comandante).AutoInclude();
        });

        modelBuilder.Entity<JogadorRelacionado>(entity =>
        {
            entity
                .HasDiscriminator<string>("Tipo")
                .HasValue<Titular>("Titular")
                .HasValue<Reserva>("Reserva");

            entity.Property(x => x.EquipeId).IsRequired();

            entity.Property(x => x.Posicao)
                  .HasConversion(new EnumToStringConverter<PosicaoAtuante>());

            entity.OwnsOne(x => x.Scout);
            entity.OwnsOne(x => x.Pessoa).Property(x => x.Nome).IsRequired();

            entity.Navigation(x => x.Pessoa).IsRequired();
        });

        modelBuilder.Entity<Comandante>(entity =>
        {
            entity.OwnsOne(x => x.Pessoa).Property(x => x.Nome).IsRequired();

            entity.Navigation(x => x.Pessoa).IsRequired();
        });

        // Times
        modelBuilder.Entity<Time>(entity =>
        {
            entity.HasMany(x => x.NomesAlternativos).WithOne(x => x.Time).HasForeignKey(x => x.TimeId);
        });

        modelBuilder.Entity<TimeNomeAlternativo>(entity =>
        {
            entity.HasKey(x => new { x.TimeId, x.Nome });
        });

        // Profissionais
        modelBuilder.Entity<Profissional>(entity =>
        {
            entity
                .HasDiscriminator<string>("Profissao")
                .HasValue<Jogador>("Jogador")
                .HasValue<Treinador>("Treinador")
                .HasValue<Arbitro>("Arbitro");

            entity.OwnsOne(x => x.Pessoa).Property(x => x.Nome).IsRequired();
            entity.OwnsOne(x => x.Nascimento);

            entity.Ignore(x => x.Nome);
            entity.Ignore(x => x.Foto);

            entity.Navigation(x => x.Nascimento).IsRequired();
        });

        modelBuilder.Entity<Jogador>(entity =>
        {
            entity.Property(x => x.Pe).HasConversion(new EnumToStringConverter<Pe>());
            entity.Property(x => x.Posicao).HasConversion(new EnumToStringConverter<PosicaoAtuante>());

            entity.OwnsOne(x => x.Medidas);

            entity.Navigation(x => x.Medidas).IsRequired();
        });

        // Estadios
        modelBuilder.Entity<Estadio>(entity =>
        {
            entity
                .Property(x => x.Campo)
                .HasConversion(new EnumToStringConverter<EstadioCampo>())
                .IsRequired(false);

            entity.OwnsMany(x => x.Imagens, od => { od.ToTable("EstadioImagens"); });

