public Task<Rodada> FindRodada(Guid temporadaId, int? numero, string grupo, MataMataChave? mataMata, bool amistoso)
    {
        var query = Rodadas.Where(x => x.TemporadaId == temporadaId);

        if (amistoso)
        {
            query = query.Where(x => x.Amistoso == amistoso);
        }

        if (numero.HasValue)
        {
            query = query.Where(x => x.Numero == numero);
        }

        if (!string.IsNullOrEmpty(grupo))
        {
            query = query.Where(x => x.Grupo == grupo);
        }

        if (mataMata.HasValue)
        {
            query = query.Where(x => x.MataMata == mataMata);
        }

        return query.FirstOrDefaultAsync();
    }

