using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Storage;
using Microsoft.EntityFrameworkCore.Storage.ValueConversion;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Models.Events;
using RealtimeMatches.Application.Common.Repositories;

public override async Task<int> SaveChangesAsync(CancellationToken cancellationToken = default)
    {
        var applicationEvents = new List<ApplicationEvent>();
        var domainEvents = new List<DomainEvent>();
        var aggregateEvents = new List<AggregateEventEntity>();
        var aggregateId = string.Empty;

        var changeSet = ChangeTracker.Entries<Domain.Entities.Entity>().ToList();
        foreach (var entityEntry in changeSet)
        {
            switch (entityEntry.State)
            {
                case EntityState.Modified:
                    entityEntry.Entity.UpdatedAt = DateTime.UtcNow;
                    break;
                case EntityState.Added:
                    entityEntry.Entity.CreatedAt = DateTime.UtcNow;
                    if (entityEntry.Entity.Id == Guid.Empty)
                    {
                        entityEntry.Entity.Id = Guid.NewGuid();
                    }

                    break;
                case EntityState.Deleted:
                    if (entityEntry.Entity is AggregateRoot aggregate)
                    {
                        AggregateEvents.RemoveRange(AggregateEvents.Where(x => x.AggregateId == aggregate.Id));
                    }

                    break;
            }

            foreach (var @event in entityEntry.Entity.DomainEvents)
            {
                domainEvents.Add(@event);

                if (entityEntry.Entity is AggregateRoot aggregate)
                {
                    aggregateId = aggregate.Id.ToString();

                    var aggregateevent = new AggregateEventEntity(aggregate, @event);
                    if (AggregateEvents.Any(x => x.Id == aggregateevent.Id))
                    {
                        continue;
                    }

                    if (@event is not LanceRegistrado)
                    {
                        AggregateEvents.Add(aggregateevent);
                        aggregateEvents.Add(aggregateevent);
                    }
                }
            }

            if (entityEntry.Entity is ProviderMapping mapping && mapping.Events?.Count > 0)
            {
                applicationEvents.AddRange(mapping.Events);
            }
        }

        var i = await base.SaveChangesAsync(cancellationToken);

        if (!string.IsNullOrEmpty(aggregateId))
        {
            var prefixKey = "LockedRequestBehaviour:";
            var lockKey = prefixKey + aggregateId;

            await _cacheService.DeleteAsync(lockKey);
        }

        foreach (var domainEvent in domainEvents)
        {
            try
            {
                using var scope = _scopeFactory.CreateScope();

                var eventBus = scope.ServiceProvider.GetService<IEventBus>();

                await eventBus.Publish(domainEvent, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception e)
            {
                _logger.LogError(e, "Error handling event " + domainEvent);
            }

            var aggregateEvent = aggregateEvents.Find(x => x.Id == domainEvent.Id);
            if (aggregateEvent != null)
            {
                aggregateEvent.PublishedAt = DateTime.UtcNow;
                await base.SaveChangesAsync(cancellationToken);
            }
        }

        foreach (var mappingEvent in applicationEvents)
        {
            using var scope = _scopeFactory.CreateScope();

            var mediator = scope.ServiceProvider.GetService<IEventBus>();

            await mediator.Publish(mappingEvent, cancellationToken).ConfigureAwait(false);
        }

        return i;
    }

