using Newtonsoft.Json;
using RealtimeMatches.Domain.Entities.Aggregates;
using RealtimeMatches.Domain.Events;
using System;

public class AggregateEventEntity
{
    private readonly static JsonSerializerSettings _jsonSerializerSettings = new()
    {
        NullValueHandling = NullValueHandling.Ignore,
        ReferenceLoopHandling = ReferenceLoopHandling.Ignore
    };

    public Guid Id { get; set; }
    public DateTime DateOcurred { get; set; }
    public DateTime? PublishedAt { get; set; }
    public Guid AggregateId { get; set; }
    public string Name { get; set; }
    public string Type { get; set; }
    public string Metadata { get; set; }

    public AggregateEventEntity(AggregateRoot aggregate, DomainEvent @event)
    {
        Id = @event.Id;

        DateOcurred = @event.DateOccurred;
        AggregateId = aggregate.Id;
        Name = @event.GetType().Name;
        Type = @event.GetType().FullName;

        Metadata = JsonConvert.SerializeObject(@event, _jsonSerializerSettings);
    }

    private AggregateEventEntity()
    {

    }

    public DomainEvent ToDomainEvent()
    {
        var assembly = typeof(AggregateRoot).Assembly;

        var domainEventType = assembly.GetType(Type);

        var domainEvent = JsonConvert.DeserializeObject(Metadata, domainEventType) as DomainEvent;

        return domainEvent;
    }
}

