public static ModelBuilder MapTabelas(this ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Tabela>(entity =>
        {
            entity
                .HasDiscriminator<string>("Tipo")
                .HasValue<TabelaFases>("Fases")
                .HasValue<TabelaPontosCorridos>("PontosCorridos");

            entity.HasIndex(x => x.TemporadaId).IsUnique();
        });

        modelBuilder.Entity<TabelaFases>(entity =>
        {
            entity.HasMany(x => x.Fases).WithOne(x => x.Tabela).HasForeignKey(x => x.TabelaId);

            entity.Navigation(x => x.Fases).AutoInclude();
        });

        modelBuilder.Entity<Fase>(entity =>
        {
            entity
                .HasDiscriminator<string>("Tipo")
                .HasValue<FaseGrupos>("Grupo")
                .HasValue<FaseMataMata>("MataMata");
        });

        modelBuilder.Entity<FaseGrupos>(entity =>
        {
            entity.HasMany(x => x.Grupos);

            entity.HasOne(x => x.Regulamento).WithOne().HasForeignKey<RegulamentoFaseGrupos>(x => x.FaseGrupoId);

            entity.Navigation(x => x.Grupos).AutoInclude();
            entity.Navigation(x => x.Regulamento).AutoInclude();
        });

        modelBuilder.Entity<RegulamentoFaseGrupos>(entity =>
        {
            entity.HasKey(x => x.Id);

            entity.HasIndex(x => x.FaseGrupoId).IsUnique();

            entity.Property(x => x.ProximaFase)
                .HasConversion(new EnumToStringConverter<FaseTipo>())
                .IsRequired();

            entity.HasMany(x => x.Classificados).WithOne().HasForeignKey(x => x.RegulamentoFaseGruposId);

            entity.Navigation(x => x.Classificados).AutoInclude();
        });

        modelBuilder.Entity<RegulamentoGrupoClassificados>(entity =>
        {
            entity.HasKey(x => new { x.RegulamentoFaseGruposId, x.ClassificadosId });

            entity.OwnsOne(x => x.GrupoTime1Classificado, od =>
            {
                od.Property(x => x.Grupo).HasConversion(new EnumToStringConverter<GrupoNome>()).IsRequired();
                od.Property(x => x.Posicao).IsRequired();
            });

            entity.OwnsOne(x => x.GrupoTime2Classificado, od =>
            {
                od.Property(x => x.Grupo).HasConversion(new EnumToStringConverter<GrupoNome>()).IsRequired();
                od.Property(x => x.Posicao).IsRequired();
            });

            entity.Navigation(x => x.GrupoTime1Classificado).IsRequired();
            entity.Navigation(x => x.GrupoTime2Classificado).IsRequired();
        });

        modelBuilder.Entity<FaseMataMata>(entity =>
        {
            entity
                .Property(x => x.Chave)
                .HasConversion(new EnumToStringConverter<MataMataChave>())
                .IsRequired();

            entity.OwnsMany(x => x.Partidas, od =>
            {
                od.ToTable("FaseMataMataPartidas");

                od.HasKey(x => new { x.FaseMataMataId, x.PartidaId, x.ChaveNome, x.Tipo });

                od
                    .Property(x => x.Tipo)
                    .HasConversion(new EnumToStringConverter<TipoPartidaMataMata>())
                    .IsRequired();

                od.Property(x => x.PartidaId).IsRequired();
            });

            entity.OwnsOne(x => x.Regulamento, od =>
            {
                od.ToTable("RegulamentoFaseMataMata");

                od
                    .Property(x => x.ModoClassificacao)
                    .HasConversion(new EnumToStringConverter<ModoClassificacaoFaseMataMata>())
                    .IsRequired();
            });

            entity.Navigation(x => x.Regulamento).IsRequired();
        });

        modelBuilder.Entity<Grupo>(entity =>
        {
            entity.HasKey(x => new { x.FaseGruposId, x.Nome });

            entity
                .Property(x => x.Nome)
                .HasConversion(new EnumToStringConverter<GrupoNome>())
                .IsRequired();

            entity.HasMany(x => x.Classificacao).WithOne(x => x.Grupo).HasForeignKey(x => new { x.FaseGruposId, x.GrupoNome }).OnDelete(DeleteBehavior.Cascade);

            entity.Navigation(x => x.Classificacao).AutoInclude();
        });

        modelBuilder.Entity<GrupoTimeClassificacao>(entity =>
        {
            entity.HasKey(x => new { x.FaseGruposId, x.GrupoNome, x.TimeId });

            entity
                .Property(x => x.GrupoNome)
                .HasConversion(new EnumToStringConverter<GrupoNome>())
                .IsRequired();
        });

        modelBuilder.Entity<TabelaTopScorers>(entity =>
        {
            entity.HasMany(x => x.TopScorers).WithOne().HasForeignKey(x => x.TemporadaId);

            entity.Navigation(x => x.TopScorers).AutoInclude();
        });

        modelBuilder.Entity<TopScorer>(entity =>
        {
            entity.HasKey(x => new { x.TemporadaId, x.JogadorId });

            entity.OwnsOne(x => x.Pessoa, builder =>
            {
                builder.Property(x => x.Nome).HasColumnName(nameof(Pessoa.Nome));
                builder.Property(x => x.Foto).HasColumnName(nameof(Pessoa.Foto));
            });

            entity.OwnsOne(x => x.Scout, builder =>
            {
                builder.Property(x => x.Gols).HasColumnName(nameof(Scout.Gols));
                builder.Property(x => x.CartoesAmarelo).HasColumnName(nameof(Scout.CartoesAmarelo));
                builder.Property(x => x.CartoesVermelho).HasColumnName(nameof(Scout.CartoesVermelho));
                builder.Property(x => x.Assistencias).HasColumnName(nameof(Scout.Assistencias));
            });

            entity.Property(x => x.Posicao)
                  .HasConversion(new EnumToStringConverter<PosicaoAtuante>());

            entity.Navigation(x => x.Pessoa).IsRequired();
            entity.Navigation(x => x.Scout).IsRequired();
        });

        return modelBuilder;
    }

