using MediatR;
using Microsoft.AspNetCore.Http;
using RealtimeMatches.Application.Presentation.Calendarios.CalendarioDaTemporada;
using RealtimeMatches.Application.Presentation.Championships.Calendar;
using RealtimeMatches.Application.Presentation.Championships.Matches;
using RealtimeMatches.Application.Presentation.Championships.Stadiums;
using RealtimeMatches.Application.Presentation.Championships.Tables;
using RealtimeMatches.Application.Presentation.Championships.Teams;
using RealtimeMatches.Application.Presentation.Middlewares;
using RealtimeMatches.Application.Presentation.Partidas.PartidaDetalhe;

public async Task<object> CreateRequest(IQueryCollection query, string temporadaSlug, List<ChampionshipResource> resources)
    {
        var name = resources.First().Name;
        var value = resources.First().Parameter;

        var resource = name[..1].ToUpper() + name[1..].ToLower() + "Request";

        var response = default(object);

        switch (resource)
        {
            case nameof(CalendarRequest):
                response = await _mediator.Send(new CalendarioTemporadaRequest { Slug = temporadaSlug });

                break;

            case nameof(MatchesRequest):
                var queryData = query.FirstOrDefault(q => q.Key.Equals(nameof(MatchesRequest.Date), StringComparison.OrdinalIgnoreCase));

                if (!string.IsNullOrEmpty(value) && Guid.TryParse(value, out var partidaId))
                {
                    var partidaDetalheRequest = new PartidaDetalheRequest
                    {
                        TemporadaSlug = temporadaSlug,
                        PartidaId = partidaId
                    };

                    response = await _mediator.Send(partidaDetalheRequest);
                }

                if (!string.IsNullOrEmpty(queryData.Key))
                {
                    var partidaRequest = new PartidasDoDiaRequest
                    {
                        TemporadaSlug = temporadaSlug,
                        Data = DateTime.Parse(queryData.Value)
                    };

                    response = await _mediator.Send(partidaRequest);
                }



                break;

            case nameof(StadiumsRequest):
                response = await _mediator.Send(new PalcosTemporadaRequest { Slug = temporadaSlug });

                break;

            case nameof(TableRequest):
                if (value == "top-scorers")
                {
                    response = await _mediator.Send(new TabelaTopScorersRequest { TemporadaSlug = temporadaSlug });
                }
                else
                {
                    response = await _mediator.Send(new TabelaTemporadaRequest { TemporadaSlug = temporadaSlug });
                }
                break;

            case nameof(TeamsRequest):
                if (!string.IsNullOrEmpty(value) && resources[1].Name.Equals("players", StringComparison.OrdinalIgnoreCase))
                {
                    var timeId = Guid.Parse(value);

                    response = await _mediator.Send(new JogadoresParticipantesRequest { Slug = temporadaSlug, TimeId = timeId });
                }
                else
                {
                    response = await _mediator.Send(new ParticipantesRequest { Slug = temporadaSlug });
                }

                break;

            default:
                break;
        }

        return response;
    }

