using MediatR;
using Microsoft.AspNetCore.Http;
using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;
using RealtimeMatches.Application.Presentation.Factories;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System.Text;

public async Task InvokeAsync(HttpContext context)
    {
        var path = context.Request.Path.Value.Replace("//", "/");

        if (!path.Contains(ChampionshipRoute))
        {
            await _next(context);
            return;
        }

        var paths = path.Replace(ChampionshipRoute, string.Empty).Split('/').Where(x => !string.IsNullOrEmpty(x)).ToList();

        var temporadaSlug = paths[0];
        var resources = new List<ChampionshipResource>();

        for (int i = 1; i < paths.Count; i++)
        {
            var resource = default(ChampionshipResource);

            if (i % 2 != 0)
            {
                resource = new() { Name = paths[i] };
            }
            else
            {
                resources.Last().Parameter = paths[i];

            }

            if (resource != null)
            {
                resources.Add(resource);
            }
        }

        object response = null;
        var statusCode = 200;

        try
        {
            response = await _championshipRequestsFactory.CreateRequest(context.Request.Query, temporadaSlug, resources);
        }
        catch (Exception e)
        {
            response = new { error = "Opa. Bola fora. Nossa equipe já foi alertada para resolver o mais breve possível. ;)" };
            statusCode = 503;

            _apmService.RecordCustomEvent("ChampionshipsRequestsFailure", new()
            {
                { "Path", path },
                { "Error", e.Message },
                { "StackTrace", e.StackTrace }
            });
        }

        var json = JsonConvert.SerializeObject(response, _jsonSerializerSettings);
        var bytes = Encoding.UTF8.GetBytes(json);

        context.Response.ContentType = "application/json; charset=utf-8";
        context.Response.StatusCode = statusCode;

        await context.Response.Body.WriteAsync(bytes);
    }

