using MediatR;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Projections.Partidas;
using RealtimeMatches.Domain.Projections.Temporadas;

public class CalendarioTemporadaRequestHandler : IRequestHandler<CalendarioTemporadaRequest, CalendarioTemporadaResponse>
{
    private readonly IReadModelRepository<TemporadaProjection> _temporadaRepository;
    private readonly IReadModelRepository<PartidaProjection> _partidaRepository;

    public CalendarioTemporadaRequestHandler(
        IReadModelRepository<TemporadaProjection> temporadaRepository,
        IReadModelRepository<PartidaProjection> partidaRepository)
    {
        _temporadaRepository = temporadaRepository;
        _partidaRepository = partidaRepository;
    }

    public async Task<CalendarioTemporadaResponse> Handle(CalendarioTemporadaRequest request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.Find(x => x.Slug, request.Slug);

        var partidasRodadasTask = temporada.Rodadas.Select(rodada => _partidaRepository.FindAll(x => x.RodadaId, rodada.Id));

        var partidasRodadas = await Task.WhenAll(partidasRodadasTask);

        var datas = partidasRodadas
            .Where(x => x != null)
            .SelectMany(x => x)
            .Where(x => x?.Data.HasValue is true)
            .OrderBy(x => x.Data)
            .GroupBy(x => x.Data.Value.Date)
            .Select(x => new CalendarioData(x.Key));

        return new CalendarioTemporadaResponse
        {
            Datas = datas
        };
    }
}

