using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Application.Presentation.Temporadas.JogadoresParticipantes.Requests;
using RealtimeMatches.Application.Presentation.Temporadas.JogadoresParticipantes.Responses;
using RealtimeMatches.Domain.Projections.Temporadas;

public class JogadoresParticipantesRequestHandler : IRequestHandler<JogadoresParticipantesRequest, JogadoresParticipantesResponse>
{
    private readonly IMapper _mapper;
    private readonly IReadModelRepository<TemporadaProjection> _temporadaRepository;
    private readonly IReadModelRepository<ParticipanteProjection> _participantesRepository;

    public JogadoresParticipantesRequestHandler(
        IMapper mapper,
        IReadModelRepository<TemporadaProjection> temporadaRepository,
        IReadModelRepository<ParticipanteProjection> participantesRepository)
    {
        _mapper = mapper;
        _temporadaRepository = temporadaRepository;
        _participantesRepository = participantesRepository;
    }

    public async Task<JogadoresParticipantesResponse> Handle(JogadoresParticipantesRequest request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.Find(x => x.Slug, request.Slug);
        var query = _participantesRepository.Where(x => x.TemporadaId, Guid.Parse(temporada.Id));

        var participantes = await query.ToListAsync();

        if (request.TimeId.HasValue)
        {
            participantes = participantes.Where(x => x.TimeId == request.TimeId.Value).ToList();
        }

        var response = new JogadoresParticipantesResponse();
        foreach (var participante in participantes)
        {
            if (participante.Jogadores == null)
            {
                continue;
            }

            foreach (var jogador in participante.Jogadores.OrderBy(x => x.Posicao.HasValue ? (int)x.Posicao.GetValueOrDefault() : 99))
            {
                var jogadorResponse = _mapper.Map<JogadorParticipanteResponse>(jogador);
                if (jogador.TimeSecundario != null)
                {
                    jogadorResponse.Escudo = jogador.TimeSecundario.Escudo;
                    jogadorResponse.Time = jogador.TimeSecundario.Nome;
                }
                else
                {
                    jogadorResponse.Escudo = participante.Escudo;
                    jogadorResponse.Time = participante.Nome;
                    jogadorResponse.TimeId = participante.TimeId.ToString();
                }

                response.Add(jogadorResponse);
            }
        }

        return response;
    }
}

