public class ParticipantesRequestHandler : IRequestHandler<ParticipantesRequest, ParticipantesResponse>
{
    private readonly IMapper _mapper;
    private readonly IReadModelRepository<TemporadaProjection> _temporadaRepository;
    private readonly IReadModelRepository<ParticipanteProjection> _participanteRepository;
    private readonly IReadModelRepository<ParticipacaoProjection> _participacaoRepository;

    public ParticipantesRequestHandler(
        IMapper mapper,
        IReadModelRepository<TemporadaProjection> temporadaRepository,
        IReadModelRepository<ParticipanteProjection> participanteRepository,
        IReadModelRepository<ParticipacaoProjection> participacaoRepository)
    {
        _mapper = mapper;
        _temporadaRepository = temporadaRepository;
        _participanteRepository = participanteRepository;
        _participacaoRepository = participacaoRepository;
    }

    public async Task<ParticipantesResponse> Handle(ParticipantesRequest request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.Find(x => x.Slug, request.Slug);
        var temporadaId = Guid.Parse(temporada.Id);

        var response = new ParticipantesResponse(new List<Participante>());
        var participantes = await _participanteRepository.FindAll(x => x.TemporadaId, temporadaId);

        foreach (var participanteProjection in participantes)
        {
            var participante = _mapper.Map<Participante>(participanteProjection);

            var participacao = await _participacaoRepository.GetByParentAndIdAsync(temporada.CampeonatoId.ToString(), participanteProjection.TimeId.ToString());
            if (participacao != null)
            {
                participante.Titulos = participacao.Titulos.ToArray();
            }

            response.Add(participante);
        }

        return new ParticipantesResponse(response);
    }
}

