        var fase = _mapper.Map<FaseResponse>(faseProjection);

        fase.Grupos = fase.Grupos.OrderBy(x => x.Nome).ToList();
        fase.AoMenosUmTimeDefinido = true;

        foreach (var grupo in fase.Grupos)
        {
            grupo.Nome = $"Grupo {grupo.Nome}";
            foreach (var timeClassificacao in grupo.Classificacao.Ranking)
            {
                var time = await _timeRepository.GetByIdAsync(timeClassificacao.TimeId.ToString());

                timeClassificacao.Time = time.Nome;
                timeClassificacao.Escudo = time.Escudo;
            }
        }

        return fase;
    }
}

