public async Task<FaseResponse> CreateFaseMataMata(FaseProjection faseAnterior, FaseProjection faseProjection)
    {
        var faseChave = faseProjection.Chave.Value;

        var faseResponse = new FaseResponse
        {
            Chave = faseChave,
            Nome = faseChave.FriendlyName(true),
            Type = FaseTypeResponse.MataMata,
            Chaveamento = new()
        };

        foreach (var partidasChave in faseProjection.Partidas.OrderBy(x => x.ChaveId).GroupBy(x => x.ChaveId))
        {
            var chave = new ChaveResponse
            {
                Chave = partidasChave.First().ChaveNome,
                Partidas = new()
            };

            foreach (var partidaFaseMataMata in partidasChave)
            {
                var partida = await _partidaRepository.GetByIdAsync(partidaFaseMataMata.PartidaId.ToString());

                var partidaResponse = new PartidaChaveResponse(partida)
                {
                    Rodada = partidaFaseMataMata.ChaveNome,
                    ConfrontoDefinido = partidaFaseMataMata.ConfrontoDefinido,
                };

                if (!partidaFaseMataMata.ConfrontoDefinido)
                {
                    if (faseAnterior.RegulamentoFaseGrupos?.ProximaFase == faseChave.ToFaseTipo())
                    {
                        var classificado = faseAnterior.RegulamentoFaseGrupos.Classificados.First(x => x.ClassificadosId == partidaFaseMataMata.ChaveId);

                        partidaResponse.Mandante = new PartidaChaveTimeResponse(classificado.GrupoTime1Classificado);
                        partidaResponse.Visitante = new PartidaChaveTimeResponse(classificado.GrupoTime2Classificado);
                    }
                }

                if (faseAnterior != null && !faseAnterior.IsGrupo)
                {
                    var (possiveisMandante, possiveisVisitantes) = await PossiveisEquipes(faseAnterior, partidaFaseMataMata, partida);

                    partidaResponse.SetPossiveisMandantes(possiveisMandante);
                    partidaResponse.SetPossiveisVisitantes(possiveisVisitantes);
                }

                if (partida.Mandante != null && partida.Mandante.TimeId != Guid.Empty)
                {
                    partidaResponse.SetMandante(await _timeRepository.GetByIdAsync(partida.Mandante.TimeId.ToString()));
                    faseResponse.AoMenosUmTimeDefinido = true;
                }

                if (partida.Visitante != null && partida.Visitante.TimeId != Guid.Empty)
                {
                    partidaResponse.SetVisitante(await _timeRepository.GetByIdAsync(partida.Visitante.TimeId.ToString()));
                    faseResponse.AoMenosUmTimeDefinido = true;
                }

                partidaResponse.SetPlacar(partida.Placar, partida.DisputaPenaltis);

                chave.Partidas.Add(partidaResponse);
            }

            faseResponse.Chaveamento.Add(chave);
        }

        return faseResponse;
    }

