using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Application.Presentation.Tabelas.TabelaTemporada.Contracts.Responses;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.MataMataFases;
