using RealtimeMatches.Domain.Projections.Partidas;
using RealtimeMatches.Domain.Projections.Tabelas;
using RealtimeMatches.Domain.Projections.Times;

public async Task<(string[], string[])> PossiveisEquipes(FaseProjection faseAnterior, PartidaFaseMataMata partida, PartidaProjection partidaProjection)
    {
        try
        {
            if (faseAnterior.RegulamentoFaseMataMata.ModoClassificacao == Domain.Enums.ModoClassificacaoFaseMataMata.Sequencial)
            {
                var partida1 = default(PartidaProjection);
                var partida2 = default(PartidaProjection);
                switch (partida.ChaveId)
                {
                    case 1:
                        partida1 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(1).PartidaId.ToString());
                        partida2 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(2).PartidaId.ToString());
                        break;
                    case 2:
                        partida1 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(3).PartidaId.ToString());
                        partida2 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(4).PartidaId.ToString());
                        break;
                    case 3:
                        partida1 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(5).PartidaId.ToString());
                        partida2 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(6).PartidaId.ToString());
                        break;
                    case 4:
                        partida1 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(7).PartidaId.ToString());
                        partida2 = await _partidaRepository.GetByIdAsync(faseAnterior.GetPartidaFaseMataMata(8).PartidaId.ToString());
                        break;
                    default:
                        break;
                }

                var equipes1 = await GetTimesPartida(partida1);
                var equipes2 = await GetTimesPartida(partida2);

                return (equipes1, equipes2);
            }

            throw new NotImplementedException("Modo Sorteio nao implementado");
        }
        catch (Exception e)
        {
            _logger.LogError(e, $"Error ao obter possíveis nomes");

            return new (Array.Empty<string>(), Array.Empty<string>());
        }
        
    }

