// Namespace: RealtimeMatches.Application.Presentation.Tabelas.TabelaTemporada
// Class: TabelaTemporadaRequestHandler
using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Application.Presentation.Tabelas.Factories;
using RealtimeMatches.Application.Presentation.Tabelas.TabelaTemporada.Contracts.Requests;
using RealtimeMatches.Application.Presentation.Tabelas.TabelaTemporada.Contracts.Responses;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using RealtimeMatches.Domain.Projections.Campeonatos;
using RealtimeMatches.Domain.Projections.Tabelas;
using RealtimeMatches.Domain.Projections.Temporadas;

public async Task<TabelaTemporadaResponse> Handle(TabelaTemporadaRequest request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.Find(x => x.Slug, request.TemporadaSlug);
        var campeonato = await _campeonatoRepository.GetByIdAsync(temporada.CampeonatoId.ToString());
        var tabela = await _readModel.Find(x => x.TemporadaId, Guid.Parse(temporada.Id));

        var tabelaResponse = _mapper.Map<TabelaTemporadaResponse>(tabela);
        tabelaResponse.Ano = int.Parse(temporada.Nome);
        tabelaResponse.Nome = campeonato.Nome + " " + temporada.Nome;
        tabelaResponse.Fases = new();

        RegulamentoFaseGrupos regulamentoFaseGrupos = null;
        var faseAnterior = default(FaseProjection);

        var fases = new List<FaseProjection>();

        foreach (var faseId in tabela.Fases)
        {
            var faseProjection = await _faseRepository.GetByIdAsync(faseId);

            fases.Add(faseProjection);
        }

        foreach (var faseProjection in fases.OrderBy(x => x.Ordem))
        {
            FaseResponse faseResponse = null;

            if (faseProjection.IsGrupo)
            {
                faseResponse = await _faseGruposResponseFactory.CreateFaseGrupo(faseProjection);

                regulamentoFaseGrupos = faseProjection.RegulamentoFaseGrupos;
            }

            if (faseProjection.Chave.HasValue)
            {
                if (faseAnterior.Chave == Domain.Enums.MataMataChave.Disputa3Lugar)
                {
                    break;
                }

                faseResponse = await _mataMataResponseFactory.CreateFaseMataMata(faseAnterior, faseProjection);
                if (tabelaResponse.Fases.LastOrDefault()?.AoMenosUmTimeDefinido == false)
                {
                    break;
                }
                
                if (faseProjection.Chave.Value == Domain.Enums.MataMataChave.Disputa3Lugar)
                {
                    tabelaResponse.Fases.Add(faseResponse);

                    var faseFinalProjection = fases.FirstOrDefault(x => x.Chave == Domain.Enums.MataMataChave.Final);
                    if (faseFinalProjection != null)
                    {
                        var faseFinalResponse = await _mataMataResponseFactory.CreateFaseMataMata(faseAnterior, faseFinalProjection);
                        if (faseFinalResponse != null)
                        {
                            tabelaResponse.Fases.Add(faseFinalResponse);
                        }
                    }

                    break;
                }
            }

            if (faseResponse != null)
            {
                tabelaResponse.Fases.Add(faseResponse);
            }
            else
            {
                break;
            }

            faseAnterior = faseProjection;
        }

        return tabelaResponse;
    }

