internal class TabelaTopScorersRequestHandler : IRequestHandler<TabelaTopScorersRequest, TabelaTopScorersResponse>
{
    private readonly IMapper _mapper;
    private readonly IReadModelRepository<TemporadaProjection> _temporadaRepository;
    private readonly IReadModelRepository<TabelaTopScorersProjection> _readModel;

    public TabelaTopScorersRequestHandler(
        IMapper mapper,
        IReadModelRepository<TemporadaProjection> temporadaRepository,
        IReadModelRepository<TabelaTopScorersProjection> readModel)
    {
        _mapper = mapper;
        _temporadaRepository = temporadaRepository;
        _readModel = readModel;
    }

    public async Task<TabelaTopScorersResponse> Handle(TabelaTopScorersRequest request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.Find(x => x.Slug, request.TemporadaSlug);

        var tabela = await _readModel.GetByIdAsync(temporada.Id);

        var response = new TabelaTopScorersResponse();

        foreach (var topScorer in tabela.TopScorers.OrderByDescending(x => x.Scout.Gols).ThenByDescending(x => x.Scout.Assistencias))
        {
            var topScorerResponse = _mapper.Map<TopScorerResponse>(topScorer);

            response.Add(topScorerResponse);
        }

        return response;
    }
}

