// Class: PartidaDetalheRequestHandler
using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Application.Presentation.Partidas.PartidaDetalhe.Responses;
using RealtimeMatches.Application.Presentation.Partidas.Responses;
using RealtimeMatches.Domain.Enums.Partidas;
using RealtimeMatches.Domain.Projections.Campeonatos;
using RealtimeMatches.Domain.Projections.Partidas;
using RealtimeMatches.Domain.Projections.Partidas.Escalacoes;
using RealtimeMatches.Domain.Projections.Partidas.Lances;

public async Task<PartidaDetalheResponse> Handle(PartidaDetalheRequest request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.Find(x => x.Slug, request.TemporadaSlug);
        if (temporada == null)
        {
            return null;
        }

        var campeonato = await _campeonatoRepository.GetByIdAsync(temporada.CampeonatoId.ToString());

        var partida = await _partidaRepository.GetByIdAsync(request.PartidaId.ToString());
        var rodada = temporada.Rodadas.First(x => x.Id == partida.RodadaId);

        var partidaResponse = new PartidaDetalheResponse(partida, campeonato, rodada);

        var partidaLances = await _lanceRepository.GetByIdAsync(partida.Id);
        if (partidaLances != null)
        {
            var lancesResponse = new List<LanceResponse>();
            foreach (var lance in partidaLances.Lances)
            {
                var time = default(TimeProjection);

                if (lance.TimeId.HasValue && lance.TimeId != Guid.Empty)
                {
                    var equipe = new List<EquipeProjection> { partida.Mandante, partida.Visitante }.First(x => x.TimeId == lance.TimeId.Value);
                    time = new TimeProjection
                    {
                        Id = equipe.TimeId.ToString(),
                        Nome = equipe.Nome,
                        Escudo = equipe.Escudo
                    };
                }

                lancesResponse.Add(new LanceResponse(lance, time));
            }

            partidaResponse.Lances = lancesResponse;
        }

        var partidaEscalacao = await _escalacaoRepository.GetByIdAsync(partida.Id);
        if (partidaEscalacao != null)
        {
            partidaResponse.Mandante.Escalacao = _mapper.Map<TimeEscalacaoResponse>(partidaEscalacao.Mandante);
            partidaResponse.Visitante.Escalacao = _mapper.Map<TimeEscalacaoResponse>(partidaEscalacao.Visitante);

            if (partidaResponse.Lances != null && partidaResponse.Lances.Count > 0)
            {
                var lancesMandante = partidaResponse.Lances.Where(x => x.IsLanceTime(partida.Mandante.TimeId));
                var lancesVisitante = partidaResponse.Lances.Where(x => x.IsLanceTime(partida.Visitante.TimeId));

                partidaResponse.Mandante.Escalacao.AtualizarScouts(lancesMandante);
                partidaResponse.Mandante.Escalacao.AtualizarSubstituicoes(lancesMandante);

                partidaResponse.Visitante.Escalacao.AtualizarScouts(lancesVisitante);
                partidaResponse.Visitante.Escalacao.AtualizarSubstituicoes(lancesVisitante);
            }
        }

        return partidaResponse;
    }

