using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Application.Presentation.Partidas.PartidasDoDia.Requests;
using RealtimeMatches.Application.Presentation.Partidas.PartidasDoDia.Responses;
using RealtimeMatches.Domain.Projections.Campeonatos;
using RealtimeMatches.Domain.Projections.Partidas;
using RealtimeMatches.Domain.Projections.Temporadas;

public class PartidasDoDiaRequestHandler : IRequestHandler<PartidasDoDiaRequest, PartidasDoDiaCollectionResponse>
{
    private readonly IReadModelRepository<TemporadaProjection> _temporadaRepository;
    private readonly IReadModelRepository<PartidaProjection> _partidaRepository;
    private readonly IReadModelRepository<CampeonatoProjection> _campeonatoRepository;
    private readonly IMapper _mapper;

    public PartidasDoDiaRequestHandler(
        IReadModelRepository<TemporadaProjection> temporadaRepository,
        IReadModelRepository<PartidaProjection> partidaRepository,
        IReadModelRepository<CampeonatoProjection> campeonatoRepository,
        IMapper mapper)
    {
        _temporadaRepository = temporadaRepository;
        _partidaRepository = partidaRepository;
        _campeonatoRepository = campeonatoRepository;
        _mapper = mapper;
    }

    public async Task<PartidasDoDiaCollectionResponse> Handle(PartidasDoDiaRequest request, CancellationToken cancellationToken)
    {
        var data = request.Data ?? DateTime.UtcNow;

        var temporada = await _temporadaRepository.Find(x => x.Slug, request.TemporadaSlug);
        var campeonato = await _campeonatoRepository.GetByIdAsync(temporada.CampeonatoId.ToString());

        var list = new List<PartidaDoDia>();
        foreach (var rodada in temporada.Rodadas)
        {
            var partidas = await _partidaRepository.FindAll(x => x.Data, data);
            if (partidas == null)
            {
                continue;
            }

            var partidasResponse = partidas
                .Where(x => x.RodadaId == rodada.Id)
                .Select(partida => new PartidaDoDia(partida, campeonato, rodada));

            list.AddRange(partidasResponse);
        }

        list = list.OrderBy(x => x.OrderKey).ToList();

        return new PartidasDoDiaCollectionResponse(list);
    }
}

