using RealtimeMatches.Application.Presentation.Partidas.PartidaDetalhe.Responses;
using RealtimeMatches.Domain.Enums.Partidas;

public class TimeEscalacaoResponse
{
    public string Tecnico { get; set; }
    public string TecnicoFoto { get; set; }
    public string Esquema { get; set; }
    public List<JogadorRelacionadoResponse> Jogadores { get; set; }
    public List<JogadorRelacionadoResponse> Reservas { get; set; }

    public void AtualizarSubstituicoes(IEnumerable<LanceResponse> lances)
    {
        var lancesSubst = lances.Where(x => x.Indicador == TipoLance.Substituicao);

        foreach (var lance in lancesSubst)
        {
            var titularIndex = Jogadores.FindIndex(x => x.Is(lance.Substituicao.JogadorSai));
            if (titularIndex == -1)
            {
                continue;
            }

            var reserva = Reservas.FirstOrDefault(x => x.Is(lance.Substituicao.JogadorEntra));
            if (reserva == null)
            {
                continue;
            }

            var titular = Jogadores[titularIndex];
            titular.SubstituicaoTipo = SubstituicaoTipo.Sai;

            reserva.SubstituicaoTipo = SubstituicaoTipo.Entra;

            Jogadores.Insert(titularIndex + 1, reserva);

            Reservas.Remove(reserva);
        }
    }

    public void AtualizarScouts(IEnumerable<LanceResponse> lances)
    {
        var jogadores = new List<JogadorRelacionadoResponse>(Jogadores);
        jogadores.AddRange(Reservas);

        foreach (var jogador in jogadores)
        {
            var lancesJogador = lances.Where(x => x.Jogador != null && (x.Jogador.Id.HasValue ? x.Jogador.Id == jogador.Id : x.Jogador.Nome == jogador.Nome));

            jogador.Scouts = new ScoutResponse
            {
                Gol = lancesJogador.Where(x => x.TipoLance == TipoLance.Gol).Count(),
                CartaoAmarelo = lancesJogador.Where(x => x.TipoLance == TipoLance.CartaoAmarelo).Count(),
                CartaoVermelho = lancesJogador.Where(x => x.TipoLance == TipoLance.CartaoVermelho).Count(),
                GolContra = lancesJogador.Where(x => x.TipoLance == TipoLance.GolContra).Count()
            };
        }
    }
}

