// Namespace: RealtimeMatches.Application.Presentation.Partidas.PartidaDetalhe.Responses
// Class: LanceResponse
using RealtimeMatches.Domain.Enums.Partidas;
using RealtimeMatches.Domain.Projections.Partidas.Lances;
using RealtimeMatches.Domain.Projections.Times;

public LanceResponse(LanceProjection lance, TimeProjection time)
    {
        TipoLance = lance.Tipo;
        Indicador = lance.Tipo;
        Minuto = lance.Momento.Tempo.ToString();
        if (lance.Momento.Extra.HasValue)
        {
            Minuto += "+" + lance.Momento.Extra.ToString();
        }

        if (Indicador != TipoLance.Substituicao && lance.JogadorPrincipal != null && !string.IsNullOrEmpty(lance.JogadorPrincipal.Nome))
        {
            var jog = lance.JogadorPrincipal;

            Jogador = new JogadorLanceResponse(jog, time);
        }

        if (Indicador == TipoLance.Substituicao)
        {
            Substituicao = new()
            {
                JogadorSai = new JogadorLanceResponse(lance.JogadorPrincipal, time),
                JogadorEntra = new JogadorLanceResponse(lance.JogadorSecundario, time)
            };
        }

        if (Indicador == TipoLance.Gol)
        {
            Titulo = "GOOOL!!";
        }

        Titulo = Indicador switch
        {
            TipoLance.InicioDeJogo => "Início de jogo",
            TipoLance.FimDeJogo => "Fim de jogo!",
            TipoLance.Gol => "GOOOL!!",
            TipoLance.Substituicao => $"Substituição no {time.Nome}",
            TipoLance.CartaoAmarelo => "Cartão amarelo!",
            TipoLance.CartaoVermelho => "EXPULSO!",
            TipoLance.GolContra => "GOL CONTRA!",
            TipoLance.PenaltiPerdido => "Pênalti Perdido!",
            TipoLance.VarGolAnulado => "[VAR] Gol anulado.",
            TipoLance.VarPenaltiMarcado => "[VAR] Penalti marcado.",
            TipoLance.PenaltiMarcado => "Penalti marcado.",
            TipoLance.ConverteuDisputaPenalti => "Penalti convertido!",
            TipoLance.ErrouDisputaPenalti => "Penalti perdido!",
            _ => Titulo
        };

        if (Indicador == TipoLance.PenaltiPerdido)
        {
            Descricao = $"{Jogador.Nome} perde pênalti";
        }

        if (Indicador == TipoLance.VarGolAnulado ||
            Indicador == TipoLance.ErrouDisputaPenalti)
        {
            Indicador = TipoLance.PenaltiPerdido;
        }

        if (Indicador == TipoLance.ConverteuDisputaPenalti)
        {
            Indicador = TipoLance.Gol;
        }
    }

