public class ProviderClient : IProviderClient
{
	const string ApiVersion = "api";
	const string SubscriptionPath = $"{ApiVersion}/Subscriptions";
	const string SubscriptionPartidasPath = $"{ApiVersion}/Subscriptions/Partidas";
	const string SubscriptionDiasPath = $"{ApiVersion}/Subscriptions/Dias";

	private readonly HttpClient _client;

	public ProviderClient(HttpClient client, ProviderApiConfig config)
	{
		client.BaseAddress = new Uri(config.BaseUrl);
		_client = client;
	}

	public async Task Subscribe(TaskSubscriptionRequest request)
	{
		var uri = $"{SubscriptionPath}";
		var response = await _client.PostAsJsonAsync(uri, request);

		response.EnsureSuccessStatusCode();
	}

	public async Task<List<PartidaSubscriptionResponse>> GetPartidaSubscriptions()
	{
		var uri = $"{SubscriptionPartidasPath}";
		var response = await _client.GetFromJsonAsync<List<PartidaSubscriptionResponse>>(uri);

		return response;
	}

	public async Task<List<DaySubscriptionResponse>> GetDaysSubscriptions()
	{
		var uri = $"{SubscriptionDiasPath}";
		var response = await _client.GetFromJsonAsync<List<DaySubscriptionResponse>>(uri);

		return response;
	}
}

