using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Partidas;
using RealtimeMatches.Application.Integrations.Builders.Commands;
using RealtimeMatches.Application.Partidas.Commands.Lances.Contracts;
using LanceProvider = Providers.Domain.Models.Partidas.Lance;

public class LancesCommandFactory : ILancesCommandFactory
{
    private readonly ILancesCommandBuilder _builder;

    public LancesCommandFactory(ILancesCommandBuilder builder)
    {
        _builder = builder;
    }

    public async Task<LanceCommand> CreateAsync(DataProvider provider, Guid partidaId, Guid mandanteId, Guid visitanteId, LanceProvider lance)
    {
        _builder
            .Create(provider, partidaId, lance.Momento)
            .WithIndicador(lance.Indicador);

        if (lance.Side.HasValue)
        {
            var timeId = lance.Side.Value == LanceSide.Mandante ? mandanteId : visitanteId;

            _builder.WithTime(timeId);
        }

        if (lance.Jogador1 != null)
        {
            await _builder.WithJogadorPrincipal(lance.Jogador1);
        }

        if (lance.Jogador2 != null)
        {
            await _builder.WithJogadorSecundario(lance.Jogador2);
        }

        return _builder.Build();    
    }
}

