// Class: PartidasCommandFactory
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Integrations.Profiles;
using RealtimeMatches.Application.Partidas.Commands.Atualizacoes;
using RealtimeMatches.Domain.Entities.Aggregates.Partidas;
using RealtimeMatches.Domain.Enums.Partidas;
using RealtimeMatches.Domain.ValueObjects.Partidas;
using PartidaProvider = Providers.Domain.Models.Partidas.Partida;

public List<Command> CreateAtualizacoes(Partida partida, PartidaProvider partidaProvider)
    {
        var commands = new List<Command>();

        var expectedSituacao = PartidasProfile.Map(partidaProvider.Status);

        if (partida.Situacao?.Status != expectedSituacao)
        {
            switch (expectedSituacao)
            {
                case SituacaoStatus.AoVivo:
                    commands.Add(new IniciarPartida(partida.Id));
                    break;
                case SituacaoStatus.Encerrada:
                    commands.Add(new EncerrarPartida(partida.Id));
                    break;
                case SituacaoStatus.Interrompida:
                    commands.Add(new InterromperPartida(partida.Id));
                    break;
                case SituacaoStatus.AdiadaSemDataDefinida:
                case SituacaoStatus.AdiadaComDataDefinida:
                    // ToDo: verificar se adiada vem a nova data.
                    commands.Add(new AdiarPartida(partida.Id, null));
                    break;
                default:
                    break;
            }
        }

        if (partida.Data != partidaProvider.Data && partidaProvider.Data.HasValue)
        {
            commands.Add(new AtualizarDataPartida(partida.Id, partidaProvider.Data.Value));
        }

        var placarProvider = partidaProvider.Placar;
        if (placarProvider != null)
        {
            if (partida.Placar?.Mandante != placarProvider.GolsMandante ||
                partida.Placar.Visitante != placarProvider.GolsVisitante)
            {
                commands.Add(new AtualizarPlacar(partida.Id, placarProvider.GolsMandante, placarProvider.GolsVisitante));
            }
        }

        var disputaPenaltiProvider = partidaProvider.DisputaPenaltis;
        if (disputaPenaltiProvider != null)
        {
            if (partida.DisputaPenaltis?.Mandante != disputaPenaltiProvider.PenaltisConvertidosMandante ||
                partida.DisputaPenaltis?.Visitante != disputaPenaltiProvider.PenaltisConvertidosVisitante)
            {
                var disputaPenaltis = new DisputaPenaltis
                {
                    Mandante = (ushort)disputaPenaltiProvider.PenaltisConvertidosMandante,
                    Visitante = (ushort)disputaPenaltiProvider.PenaltisConvertidosVisitante
                };

                commands.Add(new AtualizarDisputaPenaltis(partida.Id, disputaPenaltis));
            }
        }

        return commands;
    }

