using AutoMapper;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Partidas;
using Providers.Domain.Models.Resources;
using RealtimeMatches.Domain.Entities.Aggregates.Partidas;
using RealtimeMatches.Domain.Entities.Aggregates.Profissionais;
using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.ValueObjects;
using RealtimeMatches.Domain.ValueObjects.Partidas;
using ScoutProvider = Providers.Domain.Models.ValueObjects.Scout;

public class JogadorResourceProfile : Profile
{
    public JogadorResourceProfile()
    {
        CreateMap<JogadorResource, Jogador>()
            .ForMember(x => x.Pessoa, x => x.MapFrom(y => GetPessoa(y)))
            .ForMember(x => x.Nascimento, x => x.MapFrom(y => GetNascimento(y)))
            .ForMember(x => x.Medidas, x => x.MapFrom(y => GetMedidasCorpo(y)))
            .ForMember(x => x.Posicao, x => x.MapFrom(y => GetPosicaoAtuante(y.Posicao)));

        CreateMap<JogadorEscalacao, Titular>()
            .ForPath(x => x.Id, x => x.Ignore())
            .ForPath(x => x.Pessoa.Nome, x => x.MapFrom(y => y.Nome))
            .ForPath(x => x.Pessoa.Foto, x => x.MapFrom(y => y.Foto))
            .ForMember(x => x.Posicao, x => x.MapFrom(y => GetPosicaoAtuante(y.Posicao)));

        CreateMap<JogadorEscalacao, Reserva>()
            .ForPath(x => x.Id, x => x.Ignore())
            .ForPath(x => x.Pessoa.Nome, x => x.MapFrom(y => y.Nome))
            .ForPath(x => x.Pessoa.Foto, x => x.MapFrom(y => y.Foto))
            .ForMember(x => x.Posicao, x => x.MapFrom(y => GetPosicaoAtuante(y.Posicao)));

        CreateMap<ScoutProvider, Scout>();
    }

    private Nascimento GetNascimento(JogadorResource jogadorResource)
        => new()
        {
            Pais = jogadorResource.Nacionalidade,
            Localidade = jogadorResource.LocalNascimento,
            Data = jogadorResource.DataNascimento
        };

    private Pessoa GetPessoa(JogadorResource jogadorResource)
        => new(jogadorResource.NomeCompleto, jogadorResource.FotoUri);

    private MedidasCorpo GetMedidasCorpo(JogadorResource jogadorResource)
        => new()
        {
            AlturaCm = jogadorResource.AlturaCm,
            PesoKg = jogadorResource.PesoKg,
        };

    public static PosicaoAtuante? GetPosicaoAtuante(JogadorPosicao? posicao)
        => posicao switch
        {
            JogadorPosicao.Goleiro => PosicaoAtuante.Goleiro,
            JogadorPosicao.Defensor => PosicaoAtuante.Zagueiro,
            JogadorPosicao.Meiocampo => PosicaoAtuante.MeioCampo,
            JogadorPosicao.Atacante => PosicaoAtuante.Atacante,
            _ => null
