using MassTransit;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Abstractions;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Repositories.Exceptions;

public async Task<(T, ProviderMapping)> GetMappedEntity<T>(string provider, string type, Guid entityId) where T : Domain.Entities.Entity
	{
		T entity = default;

		var mapping = await _context
			.ProviderMappings
			.FirstOrDefaultAsync(x => x.ProviderName == provider && x.Type == type && x.EntityId == entityId);

		switch (type)
		{
			case ProviderMapping.CAMPEONATO_TYPE:
				entity = await _campeonatoRepository.Campeonatos.FirstOrDefaultAsync(x => x.Id == entityId) as T;
				break;
			case ProviderMapping.TEMPORADA_TYPE:
				entity = await _temporadaRepository.Temporadas.FirstOrDefaultAsync(x => x.Id == entityId) as T;
				break;
			case ProviderMapping.TIME_TYPE:
				//entity = await _applicationContext.TimesProvider.Include(x => x.timid)
				break;
			case ProviderMapping.PARTIDA_TYPE:
				entity = await _partidaRepository.GetPartidaById(entityId) as T;
				break;
		}

		return (entity, mapping);
	}

