public async Task<List<string>> FilterNotMappedsExternalIds(string type, string provider, IEnumerable<string> externalIds)
	{
		var mappeds = await _context.ProviderMappings
			.Where(x => x.Type == type && x.ProviderName == provider && x.EntityId.HasValue && externalIds.Contains(x.ExternalId))
			.Select(x => x.ExternalId)
			.ToListAsync();

		var notMappeds = new List<string>();

		foreach (var externalId in externalIds)
		{
			if (mappeds.Contains(externalId))
			{
				continue;
			}

			notMappeds.Add(externalId);
		}

		return notMappeds;
	}

