using RealtimeMatches.Application.Integrations.Services;
using RealtimeMatches.Domain.Entities.Aggregates.Campeonatos;

public async Task Handle(PartidaCriada notification, CancellationToken cancellationToken)
    {
        var providers = await _mappingRepository.GetIntegrationProviders();
        foreach (var provider in providers)
        {
            var providerName = provider.Nome;

            var (partida, mapping) = await _mappingRepository.GetMappedEntity<Partida>(providerName, ProviderMapping.PARTIDA_TYPE, notification.PartidaId);
            if (mapping is null)
            {
                continue;
            }

            if (partida.Data.HasValue && partida.Data.Value.Date >= DateTime.UtcNow.Date)
            {
                var isSubscribed = await _partidaSubscriptionsService.IsPartidaSubscribed(providerName, mapping.ExternalId);
                if (isSubscribed)
                {
                    return;
                }

                // ToDo: Entender pq o Provider não aceitava o horario de braisl da data
                var data = partida.Data.Value.AddHours(3);
                var startDate = data.AddMinutes(-30);
                var endDate = data.AddHours(3);
                var interval = TimeSpan.FromSeconds(30);

                var identifier = partida.GetReadableIdentifier();

                await _partidaSubscriptionsService.Subscribe(providerName, mapping.ExternalId, startDate, endDate, interval, identifier);
            }
        }
    }

