public async Task Handle(ParticipanteAdicionado notification, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.GetTemporadaById(notification.TemporadaId);       

        var providers = await _mappingRepository.GetIntegrationProviders();
        foreach (var provider in providers)
        {
            var providerName = provider.Nome;
            var (time, timeMapping) = await _mappingRepository.GetMappedEntity<Time>(providerName, ProviderMapping.TIME_TYPE, notification.TimeId);
            var (campeonato, campeonatoMapping) = await _mappingRepository.GetMappedEntity<Campeonato>(providerName, ProviderMapping.CAMPEONATO_TYPE, temporada.CampeonatoId);

            var parameter = new TaskSubscriptionRequest
            {
                Type = ScheduleTaskType.ParticipanteTemporada,
                EndDate = DateTime.UtcNow.AddDays(30),
                IntervalSeconds = 60 * 60 * 6,
                Provider = Enum.Parse<DataProvider>(provider.Nome),
                Data = new Dictionary<string, string>
                {
                    { "season", temporada.Nome },
                    { "timeId", timeMapping.ExternalId },
                    { "timeNome", time?.Nome ?? timeMapping.Info1},
                    { "ligaId", campeonatoMapping.ExternalId }
                }
            };

            await _providerClient.Subscribe(parameter);
        }
    }

