public class PartidaSubscriptionsService : IPartidaSubscriptionsService
{
    private readonly IProviderClient _client;

    public PartidaSubscriptionsService(IProviderClient client)
    {
        _client = client;
    }

    public async Task Subscribe(string provider, string externalId, DateTime startDate, DateTime endDate, TimeSpan interval, string identifier)
    {
        var request = new TaskSubscriptionRequest
        {
            Provider = Enum.Parse<DataProvider>(provider),
            Type = ScheduleTaskType.Partida,
            Data = new Dictionary<string, string>
            {
                { "partidaId", externalId },
                { "identifier", identifier }
            },
            IntervalSeconds = interval.Seconds,
            StartDate = startDate,
            EndDate = endDate
        };

        await _client.Subscribe(request);
    }

    public async Task<bool> IsPartidaSubscribed(string provider, string externalId)
    {
        var subscriptions = await _client.GetPartidaSubscriptions();

        var dataProvider = Enum.Parse<DataProvider>(provider);

        var exists = subscriptions.Any(x => x.Provider == dataProvider && x.PartidaId == externalId);

        return exists;
    }
}

