        if (string.IsNullOrWhiteSpace(idExterno) || string.IsNullOrWhiteSpace(nome))
        {
            return null;
        }

        var providerName = await GetProviderIntegrationName(providerId);
        var mapping = await GetMapping(providerId, idExterno, ProviderMapping.ESTADIO_TYPE);
        if (mapping == null)
        {
            mapping = ProviderMapping.CreateMapping<Estadio>(providerName, providerId, idExterno, nome);

            _integrationsContext.ProviderMappings.Add(mapping);
            await _integrationsContext.SaveChangesAsync();

            return new Estadio
            {
                Nome = nome,
            };
        }

        var estadio = new Estadio
        {
            Nome = mapping.Info1,
            Imagem = mapping.Info2,
            Cidade = mapping.Info4
        };

        if (!string.IsNullOrEmpty(mapping.Info3) && int.TryParse(mapping.Info3, out int capacidade))
        {
            estadio.Capacidade = capacidade;
        }

        return estadio;
    }

