            await _applicationContext.SaveChangesAsync();

            return dto.ToJogador();
        }

        var jogador = new Jogador
        {
            Apelido = mapping.Info1,
            Foto = mapping.Info2,
            Posicao = new Domain.ValueObjects.Posicao { Nome = mapping.Info3, Abreviado = mapping.Info4 }
        };

        if (mapping.EntityId.HasValue)
        {
            //jogador = await _applicationContext.Jogadores.FirstOrDefaultAsync(x => x.Id == mapping.EntityId.Value);
        }

        return jogador;
    }

