using MediatR;
using Providers.Domain.Models.Resources;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Integrations.Models.Events.Campeonatos;
using RealtimeMatches.Application.Integrations.Repositories;

public class CampeonatoResourceResponseHandler : IResourceResponseHandler<CampeonatoResource>
{
    private readonly IProviderMappingRepository _repository;
    private readonly IEventBus _eventBus;

    public CampeonatoResourceResponseHandler(
        IProviderMappingRepository repository,
        IEventBus eventBus)
    {
        _repository = repository;
        _eventBus = eventBus;
    }

    public async Task Handle(ResourceReplyNotification<CampeonatoResource> notification, CancellationToken cancellationToken)
    {
        var reply = notification.Message;

        var campeonatoMapping = await _repository.GetById(reply.MappingId);

        var campeonato = notification.Resource;

        var providerName = reply.Provider;
        var providerId = await _repository.GetProviderIdByIntegrationName(providerName);

        if (campeonatoMapping.EntityId.HasValue)
        {
            var campeonatoId = campeonatoMapping.EntityId.Value;

            var temporadasUpdated = new TemporadaResourceCollectionUpdated
            {
                CampeonatoId = campeonatoId,
                ProviderId = providerId,
                Temporadas = campeonato.Temporadas
            };

            await _eventBus.Publish(temporadasUpdated, cancellationToken);
        }
    }
}

