using AutoMapper;
using Microsoft.EntityFrameworkCore;
using Providers.Domain.Models.Resources;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Integrations.Abstractions;
using RealtimeMatches.Application.Profissionais.Commands.AtualizarJogador;
using RealtimeMatches.Domain.Entities.Aggregates.Profissionais;

internal class JogadorResourceResponseHandler : IResourceResponseHandler<JogadorResource>
{
    private readonly IMapper _mapper;
    private readonly ICommandBus _bus;
    private readonly IApplicationIntegrationContext _context;

    public JogadorResourceResponseHandler(
        IMapper mapper,
        ICommandBus bus,
        IApplicationIntegrationContext context)
    {
        _mapper = mapper;
        _bus = bus;
        _context = context;
    }

    public async Task Handle(ResourceReplyNotification<JogadorResource> notification, CancellationToken cancellationToken)
    {
        var jogador = _mapper.Map<Jogador>(notification.Resource);

        var mapping = await _context.ProviderMappings.FirstOrDefaultAsync(x => x.Id == notification.Message.MappingId);
        if (mapping.EntityId.HasValue)
        {
            var atualizarJogador = new AtualizarJogador(mapping.EntityId.Value)
            {
                Apelido = jogador.Apelido,
                Foto = jogador.Foto,
                Nome = jogador.Nome,
                MedidasCorpo = jogador.Medidas,
                Nascimento = jogador.Nascimento,
                Posicao = jogador.Posicao
            };

            await _bus.Send(atualizarJogador);
        }

        mapping.Update(jogador);
        mapping.IncludeMetadata(notification.Resource);

        await _context.SaveChangesAsync(cancellationToken);
    }
}

