using RealtimeMatches.Application.Common.Models.Events;
using RealtimeMatches.Application.Integrations.Models.Events;
using RealtimeMatches.Domain.Entities;

public static string GetType<T>()
    {
        var entity = typeof(T);

        if (entity == typeof(Jogador) || entity == typeof(Domain.Entities.Aggregates.Profissionais.Jogador))
        {
            return JOGADOR_TYPE;
        }

        if (entity == typeof(Estadio))
        {
            return ESTADIO_TYPE;
        }

        if (entity == typeof(Campeonato) || entity == typeof(Domain.Entities.Aggregates.Campeonatos.Campeonato))
        {
            return CAMPEONATO_TYPE;
        }

        if (entity == typeof(Time) || entity == typeof(Domain.Entities.Aggregates.Times.Time))
        {
            return TIME_TYPE;
        }

        if (entity == typeof(Domain.Entities.Aggregates.Temporadas.Temporada))
        {
            return TEMPORADA_TYPE;
        }

        if (entity == typeof(Domain.Entities.Aggregates.Temporadas.Rodada))
        {
            return RODADA_TYPE;
        }

        if (entity == typeof(Domain.Entities.Aggregates.Partidas.Partida))
        {
            return PARTIDA_TYPE;
        }

        if (entity == typeof(Domain.Entities.Aggregates.Estadios.Estadio))
        {
            return ESTADIO_TYPE;
        }

        if (entity == typeof(IgnorableEntityMapping))
        {
            return IGNORE_TYPE;
        }

        throw new ArgumentException("Entity not mapped.");
    }

