// Namespace: RealtimeMatches.Application.Integrations.EventHandlers.Partidas
// Class: PartidaCollectionDiaUpdatedEventHandler
using MediatR;
using Providers.Domain.Models.Resources;
using Providers.Shared.Events.Partidas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Factories;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Models.Events.Partidas;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;

public async Task Handle(PartidaCollectionDiaUpdated notification, CancellationToken cancellationToken)
    {
        var provider = notification.Provider.ToString();

        foreach (var partidasCampeonato in notification.PartidaCollection.GroupBy(x => x.Campeonato.ResourceId))
        {
            var campeonatoResource = partidasCampeonato.First().Campeonato;
            var campeonatoMapping = await _mappingRepository.Find(ProviderMapping.CAMPEONATO_TYPE, provider, campeonatoResource.ResourceId);
            if (campeonatoMapping?.EntityId.HasValue is false)
            {
                continue;
            }

            var campeonato = await _campeonatoRepository.GetAsync(campeonatoMapping.EntityId.Value);

            foreach (var partida in partidasCampeonato)
            {
                var mandanteMapping = await _mappingRepository.Find(ProviderMapping.TIME_TYPE, provider, partida.Mandante.ResourceId);
                mandanteMapping ??= await CreateTimeMapping(provider, partida.Mandante);

                var visitanteMapping = await _mappingRepository.Find(ProviderMapping.TIME_TYPE, provider, partida.Visitante.ResourceId);
                visitanteMapping ??= await CreateTimeMapping(provider, partida.Visitante);

                if ((mandanteMapping.EntityId.HasValue && visitanteMapping.EntityId.HasValue) is false)
                {
                    // ToDo: Lançar exception
                    //throw new TimeResourceNotMappedException
                    //{
                    //    Time = mandanteMapping.EntityId.HasValue ? partida.Visitante : partida.Mandante
                    //};

                    continue;
                }

                var mandante = await _timeRepository.GetAsync(mandanteMapping.EntityId.Value);
                var visitante = await _timeRepository.GetAsync(visitanteMapping.EntityId.Value);

                var temporada = await _temporadaRepository.FindTemporada(campeonato.Id, partida.Temporada.Ano, true);

                Rodada rodada = null;
                switch (partida.Rodada.Tipo)
                {
                    case global::Providers.Domain.Models.Enums.RodadaTipo.Numerada:
                        var rodadaId = await _mappingRepository.GetEntityId(ProviderMapping.RODADA_TYPE, provider, partida.Rodada.ResourceId);
                        if (rodadaId.HasValue is false)
                        {
                            throw new NullReferenceException("Rodada não encontrada.");
                        }

                        rodada = temporada.Rodadas.FirstOrDefault(x => x.Id == rodadaId.Value);

                        break;
                    case global::Providers.Domain.Models.Enums.RodadaTipo.Grupo:
                        rodada = _partidaRodadaFactory.CreateRodadaGrupo(temporada, mandante, visitante);
                        break;
                    case global::Providers.Domain.Models.Enums.RodadaTipo.Fase:
                        rodada = _partidaRodadaFactory.CreateRodadaFase(temporada, (Domain.Enums.MataMataChave)partida.Rodada.MataMataChave);
                        break;
                    case global::Providers.Domain.Models.Enums.RodadaTipo.Amistoso:
                        break;
                    default:
                        break;
                }

                if (rodada is null)
                {
                    // ToDo: tomar alguma decisão
                    continue;
                }

                var partidaUpdatedOnProvider = new PartidaUpdatedOnProvider(provider, rodada.Id, mandante.Id, visitante.Id, partida);

                await _eventBus.Publish(partidaUpdatedOnProvider);
            }
        }
    }

