using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;

public async Task<ProviderMapping> CreateTimeMapping(string provider, TimeResource timeResource)
    {
        var providerId = await _mappingRepository.GetProviderIdByIntegrationName(provider);

        var mapping = ProviderMapping.CreateMapping<Time>(provider, providerId, timeResource.ResourceId);

        var time = new Time(timeResource.Nome, timeResource.Escudo)
        {
            Pais = timeResource.Pais,
            AnoFundacao = timeResource.AnoFundacao
        };

        mapping.Update(time);

        _mappingRepository.Add(mapping);
        await _mappingRepository.SaveChangesAsync();

        return mapping;
    }

