using AutoMapper;
using MediatR;
using Providers.Domain.Models.Partidas;
using Providers.Shared.Events.Partidas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Profiles;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Profissionais.Commands.CriarJogador;

public async Task Handle(PartidaCoverageUpdated notification, CancellationToken cancellationToken)
    {
        _provider = notification.Provider.ToString();
        _providerId = await _mappingRepository.GetProviderIdByIntegrationName(_provider);

        var mapping = await _mappingRepository.Find(ProviderMapping.PARTIDA_TYPE, _provider, notification.Id);
        if (mapping.EntityId.HasValue is false)
        {
            // ToDo: Verificar necessidade de lançar exception.
            return;
        }

        var partida = await _partidaRepository.GetPartidaById(mapping.EntityId.Value);

        var jogadoresProvider = new List<JogadorEscalacao>();
        jogadoresProvider.AddRange(notification.Mandante.Jogadores);
        jogadoresProvider.AddRange(notification.Mandante.Reservas);
        jogadoresProvider.AddRange(notification.Visitante.Jogadores);
        jogadoresProvider.AddRange(notification.Visitante.Reservas);

        await EnsureAllJogadoresAreMappedAndCreated(jogadoresProvider);

        var mandanteId = partida.Mandante.TimeId.Value;
        var visitanteId = partida.Visitante.TimeId.Value;

        var escalacaoMandante = await GetEscalacao(mandanteId, notification.Mandante);
        var escalacaoVisitante = await GetEscalacao(visitanteId, notification.Visitante);

        partida.AtualizarEscalacao(mandanteId, escalacaoMandante.Item1, escalacaoMandante.Item2, escalacaoMandante.Item3, notification.Mandante.Esquema);
        partida.AtualizarEscalacao(visitanteId, escalacaoVisitante.Item1, escalacaoVisitante.Item2, escalacaoVisitante.Item3, notification.Visitante.Esquema);

        await _partidaRepository.SaveChangesAsync(cancellationToken);
    }

