using AutoMapper;
using MediatR;
using Providers.Domain.Models.Partidas;
using Providers.Shared.Events.Partidas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Profiles;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Profissionais.Commands.CriarJogador;

private async Task<(List<Titular>, List<Reserva>, Comandante)> GetEscalacao(Guid equipeId, Escalacao escalacao)
    {
        var titulares = new List<Titular>();
        foreach (var jogador in escalacao.Jogadores.Where(x => x.SubstituicaoTipo != SubstituicaoTipo.Entra))
        {
            var titular = await GetTitular(equipeId, jogador);

            titulares.Add(titular);
        }

        var reservasEscalacao = escalacao.Jogadores.Where(x => x.SubstituicaoTipo == SubstituicaoTipo.Entra).ToList();
        reservasEscalacao.AddRange(escalacao.Reservas);

        var reservas = new List<Reserva>();
        foreach (var jogador in reservasEscalacao)
        {
            var reserva = await GetReserva(equipeId, jogador);

            reservas.Add(reserva);
        }

        // ToDo: Mapear treinador
        var treinador = escalacao.Tecnico;

        var comandante = new Comandante(equipeId, new Pessoa(treinador.Nome, treinador.Foto));

        return (titulares, reservas, comandante);
    }

