using AutoMapper;
using MediatR;
using Providers.Domain.Models.Partidas;
using Providers.Shared.Events.Partidas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Profiles;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Profissionais.Commands.CriarJogador;

private async Task EnsureAllJogadoresAreMappedAndCreated(List<JogadorEscalacao> jogadores)
    {
        var mappings = await _mappingRepository.FindAllExternalIds(ProviderMapping.JOGADOR_TYPE, _provider, jogadores.Where(x => !string.IsNullOrEmpty(x.Id)).Select(x => x.Id));
        foreach (var mapping in mappings.Where(x => x.EntityId.HasValue == false))
        {
            var jogadorProvider = jogadores.First(x => x.Id == mapping.ExternalId);

            var jogador = await CreateJogador(jogadorProvider);

            mapping.Update(jogador);
            mapping.SetEntity(jogador.Id);

            _mappingRepository.Update(mapping);
        }

        await _mappingRepository.SaveChangesAsync();

        var notMappeds = jogadores.Where(x => !mappings.Any(y => y.ExternalId == x.Id));

        foreach (var jogadorProvider in notMappeds)
        {
            var mapping = ProviderMapping.CreateMapping<Jogador>(_provider, _providerId, jogadorProvider.Id);

            var jogador = await CreateJogador(jogadorProvider);

            mapping.Update(jogador);
            mapping.SetEntity(jogador.Id);

            _mappingRepository.Add(mapping);
        }

        await _mappingRepository.SaveChangesAsync();
    }

