using MediatR;
using Microsoft.EntityFrameworkCore;
using Providers.Shared.Events.Partidas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Factories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Partidas.Commands.Lances.Contracts;

public async Task Handle(PartidaCoverageUpdated notification, CancellationToken cancellationToken)
    {
        if (notification.Lances == null)
        {
            return;
        }

        _provider = notification.Provider.ToString();

        var mapping = await _mappingRepository.Find(ProviderMapping.PARTIDA_TYPE, _provider, notification.Id);
        if (mapping.EntityId.HasValue is false)
        {
            // ToDo: Verificar necessidade de lançar exception.
            return;
        }

        var partida = await _partidaRepository.GetPartidaLancesCountSummary(mapping.EntityId.Value);

        if (notification.Lances.Count == 0)
        {
            if (partida.LancesCount == 0)
            {
                return;
            }

            var limparLances = new LimparLances(partida.Id);
            await _bus.Send(limparLances);

            return;
        }

        var commands = new List<LanceCommand>();

        foreach (var lance in notification.Lances)
        {
            var lanceCommand = await _lancesCommandFactory.CreateAsync(notification.Provider, partida.Id, partida.MandanteId, partida.VisitanteId, lance);
            if (lanceCommand == null)
            {
                continue;
            }

            commands.Add(lanceCommand);
        }

        var registrarLances = new RegistrarLanceCollection(partida.Id, commands);

        await _bus.Send(registrarLances);
    }

