using MediatR;
using Providers.Domain.Enums;
using Providers.Domain.Models.Resources;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Estadios.Commands.CriarEstadio;
using RealtimeMatches.Application.Integrations.Commands.AssociarResource;
using RealtimeMatches.Application.Integrations.Factories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Models.Events.Partidas;

public async Task Handle(PartidaUpdatedOnProvider notification, CancellationToken cancellationToken)
    {
        var provider = notification.Provider;
        var partidaProvider = notification.Partida;

        var rodadaId = notification.RodadaId;
        var mandanteId = notification.MandanteId;
        var visitanteId = notification.VisitanteId;

        var providerId = await _mappingRepository.GetProviderIdByIntegrationName(provider);
        var partida = await _partidaRepository.FindPartida(rodadaId, mandanteId, visitanteId);

        if (partida == null)
        {
            var createPartida = new CreatePartida
            {
                Data = partidaProvider.Data,
                RodadaId = rodadaId,
                MandanteId = mandanteId,
                VisitanteId = visitanteId,
            };

            var partidaId = await _commandBus.Send(createPartida);
            partida = await _partidaRepository.GetPartidaById(partidaId);
        }

        var mappedEstadio = await _mappingRepository.Find(ProviderMapping.ESTADIO_TYPE, provider, partidaProvider.Estadio.ResourceId);
        if (mappedEstadio == null && string.IsNullOrEmpty(partidaProvider.Estadio.ResourceId) is false)
        {
            var estadioId = await CreateEstadio(partidaProvider.Estadio);
            var createMapping = new CreateProviderMappingWithEntity(ResourceType.Estadio, providerId, estadioId, partidaProvider.Estadio.ResourceId);
            var mappingId = await _commandBus.Send(createMapping);

            mappedEstadio = await _mappingRepository.GetById(mappingId);
        }

        var estadioResource = partidaProvider.Estadio;
        var expectedPalco = new Palco
        {
            EstadioId = mappedEstadio?.EntityId,
            Nome = estadioResource.Nome,
            Capacidade = estadioResource.Capacidade,
            Cidade = estadioResource.Cidade,
            Endereco = estadioResource.Endereco,
            Imagem = estadioResource.Imagem,
            Pais = estadioResource.Pais
        };

        if (expectedPalco.EstadioId.HasValue is false && string.IsNullOrEmpty(expectedPalco.Imagem))
        {
            var estadio = await _estadioRepository.FindEstadioByNome(estadioResource.Nome);
            if (estadio != null)
            {
                expectedPalco = new Palco(estadio);
            }
        }

        if ((partida.Palco == null || partida.Palco.EstadioId.HasValue is false) && (
                partida.Palco?.EstadioId != mappedEstadio?.EntityId ||
                partida.Palco?.Nome != expectedPalco.Nome ||
                partida.Palco?.Imagem != expectedPalco.Imagem ||
                partida.Palco?.Capacidade != expectedPalco.Capacidade)
           )
        {
            await _commandBus.Send(new AtualizarPalcoPartida(partida.Id, expectedPalco));
        }

        var commands = _commandFactory.CreateAtualizacoes(partida, partidaProvider);
        foreach (var command in commands)
        {
            await _commandBus.Send(command);
        }

        var mappedPartida = await _mappingRepository.Find(ProviderMapping.PARTIDA_TYPE, providerId, partidaProvider.Id);
        if (mappedPartida == null)
        {
            mappedPartida = ProviderMapping.CreateMapping<Partida>(provider, providerId, partidaProvider.Id);
            mappedPartida.Update(partida);

            mappedPartida.SetEntity(partida.Id);
            mappedPartida.MapeamentoCompleto();

            _mappingRepository.Add(mappedPartida);
            await _mappingRepository.SaveChangesAsync();
        }
        else if (!mappedPartida.EntityId.HasValue ||
                  mappedPartida.EntityId.Value != partida.Id)
        {
            mappedPartida.SetEntity(partida.Id);
            mappedPartida.MapeamentoCompleto();

            await _mappingRepository.SaveChangesAsync();
        }
    }

