using AutoMapper;
using MediatR;
using Providers.Shared.Events.Temporadas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Tabelas.Commands.AtualizarTopScorers;
using RealtimeMatches.Application.Tabelas.Dtos;
using RealtimeMatches.Domain.ValueObjects.Partidas;

public class TabelaTopScorersUpdatedEventHandler : INotificationHandler<TopScorersLigaUpdated>
{
    private readonly IMapper _mapper;
    private readonly IProviderMappingRepository _mappingRepository;
    private readonly ICampeonatoRepository _campeonatoRepository;
    private readonly ITemporadaRepository _temporadaRepository;
    private readonly ICommandBus _bus;

    public TabelaTopScorersUpdatedEventHandler(
        IMapper mapper,
        IProviderMappingRepository mappingRepository,
        ICampeonatoRepository campeonatoRepository,
        ITemporadaRepository temporadaRepository,
        ICommandBus bus)
    {
        _mapper = mapper;
        _mappingRepository = mappingRepository;
        _campeonatoRepository = campeonatoRepository;
        _temporadaRepository = temporadaRepository;
        _bus = bus;
    }

    public async Task Handle(TopScorersLigaUpdated notification, CancellationToken cancellationToken)
    {
        var provider = notification.Provider.ToString();
        var campeonatoResource = notification.Campeonato;

        var campeonatoMapping = await _mappingRepository.Find(ProviderMapping.CAMPEONATO_TYPE, provider, campeonatoResource.ResourceId);
        if (campeonatoMapping?.EntityId.HasValue is false)
        {
            return;
        }

        var campeonato = await _campeonatoRepository.GetAsync(campeonatoMapping.EntityId.Value);
        var temporada = await _temporadaRepository.FindTemporada(campeonato.Id, notification.Temporada.Ano, true);

        var topScorerDtos = new List<TopScorerDto>();

        foreach (var topScorer in notification.TopScorers)
        {
            var jogadorResource = topScorer.Jogador;

            var jogadorMapping = await _mappingRepository.Find(ProviderMapping.JOGADOR_TYPE, provider, jogadorResource.ResourceId);
            if (jogadorMapping.EntityId.HasValue is false)
            {
                continue;
            }

            topScorerDtos.Add(new TopScorerDto
            {
                JogadorId = jogadorMapping.EntityId.Value,
                Scout = _mapper.Map<Scout>(topScorer.Scouts)
            });
        }

        await _bus.Send(new AtualizarTopScorers(temporada.Id, topScorerDtos));
    }
}

