// Namespace: RealtimeMatches.Application.Integrations.EventHandlers.Temporadas
// Class: ParticipanteLigaEventHandler
using AutoMapper;
using MediatR;
using Providers.Shared.Events.Temporadas;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Commands.CreateProviderMappingsWithJogadores;
using RealtimeMatches.Application.Integrations.Commands.UpdateJogadoresWithResource;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Integrations.Repositories.Exceptions;

public async Task Handle(ParticipanteLigaUpdated notification, CancellationToken cancellationToken)
    {
        var provider = notification.Provider.ToString();
        var campeonatoResource = notification.Campeonato;

        var campeonatoMapping = await _repository.Find(ProviderMapping.CAMPEONATO_TYPE, provider, campeonatoResource.ResourceId);
        if (campeonatoMapping?.EntityId.HasValue is false)
        {
            throw new EntityNotMappedException(typeof(Campeonato));
        }

        var campeonatoOrg = await _campeonatoRepository.GetCampeonatoOrganizacaoAsync(campeonatoMapping.EntityId.Value);

        var timeMapping = await _repository.Find(ProviderMapping.TIME_TYPE, provider, notification.Time.ResourceId);
        if (timeMapping?.EntityId.HasValue is false)
        {
            throw new EntityNotMappedException(typeof(Time));
        }

        var timeId = timeMapping.EntityId.Value;

        var temporada = await _temporadaRepository.FindTemporada(campeonatoMapping.EntityId.Value, notification.Temporada.Ano, false);
        if (temporada.Participantes.Any(x => x.TimeId == timeId) is false)
        {
            var adicionarParticipante = new AdicionarParticipante(temporada.Id, timeId);

            await _bus.Send(adicionarParticipante);
        }

        var jogadoresExternalIds = notification.Jogadores.Select(x => x.ResourceId);
        var resourcesIdToMap = await _repository.FilterNotMappedsExternalIds(ProviderMapping.JOGADOR_TYPE, provider, jogadoresExternalIds);

        var createJogadorMappings = new CreateProviderMappingsWithJogadores
        {
            Jogadores = notification.Jogadores.Where(x => resourcesIdToMap.Contains(x.ResourceId)),
            Provider = notification.Provider,
        };

        await _bus.Send(createJogadorMappings);

        var jogadoresMappings = await _repository.FindAllExternalIds(ProviderMapping.JOGADOR_TYPE, provider, notification.Jogadores.Select(x => x.ResourceId));
        foreach (var mapping in jogadoresMappings.Where(x => x.EntityId.HasValue == false))
        {
            var jogadorResource = notification.Jogadores.First(x => x.ResourceId == mapping.ExternalId);

            var jogador = _mapper.Map<Jogador>(jogadorResource);

            var criarJogador = new CriarJogador
            {
                Apelido = jogador.Apelido,
                Nome = jogador.Nome,
                Foto = jogador.Foto,
                MedidasCorpo = jogador.Medidas,
                Nascimento = jogador.Nascimento,
                Posicao = jogador.Posicao
            };

            jogador.Id = await _bus.Send(criarJogador);

            mapping.Update(jogador);
            mapping.SetEntity(jogador.Id);

            _repository.Update(mapping);
        }

        if (jogadoresMappings.Any(x => x.EntityId.HasValue is false))
        {
            throw new ArgumentNullException("Nem todos jogadores foram devidamente mapeados.");
        }

        var updateJogadoresWithResource = new UpdateJogadoresWithResource
        {
            Provider = notification.Provider,
            Jogadores = notification.Jogadores.ToList()
        };

        await _bus.Send(updateJogadoresWithResource);

        var jogadoresParticipantesDto = new List<JogadorParticipanteDto>();
        if (campeonatoOrg == CampeonatoOrganizacao.Selecoes)
        {
            foreach (var jogadorMapping in jogadoresMappings)
            {
                var clube = notification.Jogadores.FirstOrDefault(x => x.ResourceId == jogadorMapping.ExternalId)?.Clube;
                var dto = new JogadorParticipanteDto
                {
                    JogadorId = jogadorMapping.EntityId.Value
                };

                if (clube != null)
                {
                    dto.TimeSecundario = new TimeValueObject(clube.Nome, clube.Escudo, TimeTipo.Clube);
                }

                jogadoresParticipantesDto.Add(dto);
            }
        }
        else
        {
            jogadoresParticipantesDto = jogadoresMappings.Select(x => new JogadorParticipanteDto { JogadorId = x.EntityId.Value }).ToList();
        }

        var adicionarJogadoresParticipantes = new AdicionarJogadoresParticipante(temporada.Id, timeId, jogadoresParticipantesDto);

        await _bus.Send(adicionarJogadoresParticipantes);
    }

