using MediatR;
using Providers.Domain.Enums;
using Providers.Domain.Models.Enums;
using RealtimeMatches.Application.Campeonatos.Commands.CreateTemporada;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Commands.AssociarResource;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Models.Events.Campeonatos;

public async Task Handle(TemporadaResourceCollectionUpdated notification, CancellationToken cancellationToken)
    {
        var campeonatoId = notification.CampeonatoId;
        var providerId = notification.ProviderId;

        foreach (var temporadaResource in notification.Temporadas)
        {
            Guid? temporadaId;

            var temporadaMapping = await _repository.Find(ProviderMapping.TEMPORADA_TYPE, notification.ProviderId, temporadaResource.ResourceId);
            if (temporadaMapping == null || !temporadaMapping.EntityId.HasValue)
            {
                var temporada = await _temporadaRepository.FindTemporada(campeonatoId, temporadaResource.Ano);
                if (temporada == null)
                {
                    temporadaId = await _commandBus.Send<Guid>(new CreateTemporada(campeonatoId, temporadaResource.Ano));
                }
                else
                {
                    temporadaId = temporada.Id;
                }

                if (temporadaMapping is null)
                {
                    var temporadaMappingId = await _commandBus.Send<Guid>(new CreateProviderMappingWithEntity
                    {
                        ProviderId = providerId,
                        EntityId = temporadaId.Value,
                        ExternalId = temporadaResource.ResourceId,
                        Type = ResourceType.Temporada
                    });
                }
                else
                {
                    temporadaMapping.SetEntity(temporadaId.Value);
                    await _repository.SaveChangesAsync();
                }
            }
            else
            {
                temporadaId = temporadaMapping.EntityId;
            }

            var rodadasUpdated = new RodadaResourceCollectionUpdated
            {
                TemporadaId = temporadaId.Value,
                ProviderId = providerId,
                Rodadas = temporadaResource.Rodadas
            };

            await _eventBus.Publish(rodadasUpdated);
        }
    }

// File: RealtimeMatches.Application.Integrations/EventHandlers/Temporadas/TemporadaResourceEventHandler.cs
// Namespace: RealtimeMatches.Application.Integrations.EventHandlers.Temporadas
// Class: TemporadaResourceEventHandler
using MediatR;
using Providers.Domain.Enums;
using Providers.Domain.Models.Enums;
using RealtimeMatches.Application.Campeonatos.Commands.CreateTemporada;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Commands.AssociarResource;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Models.Events.Campeonatos;

public async Task Handle(RodadaResourceCollectionUpdated notification, CancellationToken cancellationToken)
    {
        var temporadaId = notification.TemporadaId;
        var providerId = notification.ProviderId;

        foreach (var rodadaResource in notification.Rodadas)
        {
            Guid? rodadaId;

            var rodadaMapping = await _repository.Find(ProviderMapping.RODADA_TYPE, providerId, rodadaResource.ResourceId);
            if (rodadaMapping == null || !rodadaMapping.EntityId.HasValue)
            {
                Rodada rodada;
                Command<Guid> createRodadaCommand;

                switch (rodadaResource.Tipo)
                {
                    case RodadaTipo.Numerada:
                        var numero = rodadaResource.NumeroRodada.Value;
                        rodada = await _temporadaRepository.FindRodada(temporadaId, numero, null, null, false);

                        createRodadaCommand = new CreateRodadaNumerada(temporadaId)
                        {
                            Numero = numero
                        };

                        break;
                    case RodadaTipo.Grupo:
                        rodada = await _temporadaRepository.FindRodada(temporadaId, null, rodadaResource.TipoNome, null, false);

                        createRodadaCommand = new CreateRodadaGrupo(temporadaId)
                        {
                            Grupo = rodadaResource.TipoNome
                        };

                        break;
                    case RodadaTipo.Fase:
                        var matamata = Enum.Parse<Domain.Enums.MataMataChave>(rodadaResource.TipoNome);

                        rodada = await _temporadaRepository.FindRodada(temporadaId, null, null, matamata, false);

                        createRodadaCommand = new CreateRodadaFase(temporadaId)
                        {
                            Fase = matamata
                        };

                        break;
                    case RodadaTipo.Amistoso:
                        rodada = await _temporadaRepository.FindRodada(temporadaId, null, null, null, true);

                        createRodadaCommand = new CreateRodadaAmistoso(temporadaId);

                        break;
                    default:
                        throw new NotImplementedException();
                }

                if (rodada == null)
                {
                    rodadaId = await _commandBus.Send<Guid>(createRodadaCommand);
                }
                else
                {
                    rodadaId = rodada.Id;
                }

                if (rodadaMapping is null)
                {
                    var rodadaMappingId = await _commandBus.Send(new CreateProviderMappingWithEntity
                    {
                        Type = ResourceType.Rodada,
                        EntityId = rodadaId.Value,
                        ExternalId = rodadaResource.ResourceId,
                        ProviderId = providerId
                    });
                }
                else
                {
                    rodadaMapping.SetEntity(rodadaId.Value);
                    await _repository.SaveChangesAsync();
                }
            }
        }
    }

