// File: RealtimeMatches.Application.Integrations/Commands/CreateProviderMapping/CreateProviderMappingWithEntityHandler.cs
// Namespace: RealtimeMatches.Application.Integrations.Commands.AssociarResource
// Class: CreateProviderMappingWithEntityHandler
using MediatR;
using Microsoft.EntityFrameworkCore;
using Providers.Domain.Enums;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Domain.Entities.Aggregates.Campeonatos;
using RealtimeMatches.Domain.Entities.Aggregates.Estadios;
using RealtimeMatches.Domain.Entities.Aggregates.Profissionais;
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;

public async Task<Guid> Handle(CreateProviderMappingWithEntity request, CancellationToken cancellationToken)
    {
        var providerName = await _mappingRepository.GetProviderIntegrationNameById(request.ProviderId);

        ProviderMapping mapping = null;

        switch (request.Type)
        {
            case ResourceType.Campeonato:
                var campeonato = await _campeonatoRepository.Campeonatos.FirstOrDefaultAsync(x => x.Id == request.EntityId);

                mapping = ProviderMapping.CreateMapping<Campeonato>(providerName, request.ProviderId, request.ExternalId);
                mapping.Update(campeonato);

                break;

            case ResourceType.Temporada:
                var temporada = await _temporadaRepository.Temporadas.FirstOrDefaultAsync(x => x.Id == request.EntityId);

                mapping = ProviderMapping.CreateMapping<Temporada>(providerName, request.ProviderId, request.ExternalId);
                mapping.Update(temporada);

                break;

            case ResourceType.Rodada:
                var rodada = await _temporadaRepository.Rodadas.FirstOrDefaultAsync(x => x.Id == request.EntityId);

                mapping = ProviderMapping.CreateMapping<Rodada>(providerName, request.ProviderId, request.ExternalId);
                mapping.Update(rodada);

                break;

            case ResourceType.Jogador:
                var jogador = await _profissionalRepository.GetJogadorAsync(request.EntityId);

                mapping = ProviderMapping.CreateMapping<Jogador>(providerName, request.ProviderId, request.ExternalId);
                mapping.Update(jogador);

                break;

            case ResourceType.Estadio:
                var estadio = await _estadioRepository.GetEstadioById(request.EntityId);

                mapping = ProviderMapping.CreateMapping<Estadio>(providerName, request.ProviderId, request.ExternalId);
                mapping.Update(estadio);

                break;
            default:
                break;
        }

        mapping.SetEntity(request.EntityId);

        _mappingRepository.Add(mapping);
        await _mappingRepository.SaveChangesAsync();

        return mapping.Id;
    }

