using AutoMapper;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Providers.Domain.Models.Enums;
using RealtimeMatches.Application.Integrations.Abstractions;
using RealtimeMatches.Application.Integrations.Exceptions;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Domain.Entities.Aggregates.Profissionais;
using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.ValueObjects;

public class CreateProviderMappingsWithJogadoresHandler : IRequestHandler<CreateProviderMappingsWithJogadores>
{
    private readonly IMapper _mapper;
    private readonly ITransactionalAggregateMappingContext _context;

    public CreateProviderMappingsWithJogadoresHandler(
        IMapper mapper,
        ITransactionalAggregateMappingContext context)
    {
        _mapper = mapper;
        _context = context;
    }

    public async Task<Unit> Handle(CreateProviderMappingsWithJogadores request, CancellationToken cancellationToken)
    {
        await _context.BeginTransactionAsync(cancellationToken).ConfigureAwait(false);

        var provider = await _context.Providers.FirstOrDefaultAsync(x => x.Nome == request.Provider.ToString());

        try
        {
            var jogadorDbSet = _context.GetAggregatesDbSet<Jogador>();

            foreach (var jogadorResource in request.Jogadores)
            {
                var jogador = _mapper.Map<Jogador>(jogadorResource);

                jogadorDbSet.Add(jogador);

                var mapping = ProviderMapping.CreateMapping<Jogador>(provider.Nome, provider.Id, jogadorResource.ResourceId);

                mapping.Update(jogador);
                mapping.SetEntity(jogador.Id);

                mapping.MapeamentoCompleto();

                _context.ProviderMappings.Add(mapping);
            }

            await _context.SaveChangesAsync(cancellationToken);

            await _context.CommitTransactionAsync(cancellationToken);
        }
        catch (Exception)
        {
            throw new CreateProviderMappingWithAggregateException($"Error commiting transaction of aggregate '{typeof(Jogador)}'");
        }

        return Unit.Value;
    }
}

