using AutoMapper;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Integrations.Models.Entities;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Application.Profissionais.Commands.AtualizarJogador;
using RealtimeMatches.Domain.Entities.Aggregates.Profissionais;

public class UpdateJogadoresWithResourceHandler : IRequestHandler<UpdateJogadoresWithResource>
{
    private readonly IMapper _mapper;
    private readonly IProviderMappingRepository _mappingRepository;
    private readonly IProfissionalRepository _profissionalRepository;
    private readonly ICommandBus _bus;

    public UpdateJogadoresWithResourceHandler(
        IMapper mapper,
        IProviderMappingRepository mappingRepository,
        IProfissionalRepository profissionalRepository,
        ICommandBus bus)
    {
        _mapper = mapper;
        _mappingRepository = mappingRepository;
        _profissionalRepository = profissionalRepository;
        _bus = bus;
    }

    public async Task<Unit> Handle(UpdateJogadoresWithResource request, CancellationToken cancellationToken)
    {
        var provider = request.Provider.ToString();

        var jogadoresMappings = await _mappingRepository.FindAllExternalIds(ProviderMapping.JOGADOR_TYPE, provider, request.Jogadores.Select(x => x.ResourceId));
        var jogadoresid = jogadoresMappings.Select(x => x.EntityId.Value);

        var jogadoresToUpdate = await _profissionalRepository
            .Jogadores
            .AsNoTracking()
            .Where(x => jogadoresid.Contains(x.Id) && (x.Medidas == null || x.Medidas.PesoKg == null || x.Posicao == null))
            .Select(x => x.Id)
            .ToListAsync();

        foreach (var jogadorId in jogadoresToUpdate)
        {
            var resource = request.Jogadores.First(x => x.ResourceId == jogadoresMappings.First(x => x.EntityId == jogadorId).ExternalId);

            var jogadorMapped = _mapper.Map<Jogador>(resource);
            if (jogadorMapped.Posicao == null)
            {
                continue;
            }

            var atualizarJogador = new AtualizarJogador(jogadorId)
            {
                MedidasCorpo = jogadorMapped.Medidas,
                Posicao = jogadorMapped.Posicao,
                Nascimento = jogadorMapped.Nascimento
            };

            await _bus.Send(atualizarJogador);
        }

        return Unit.Value;
    }
}

