using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Infrastructure.Persistence.Repositories;
using System;
using System.Linq;
using System.Threading.Tasks;

[HttpPost("publish")]
	public async Task<IActionResult> PublishEvents(string eventName, Guid? aggregateId, DateTime? fromDateOcurred)
	{
		var query = _context.AggregateEvents.AsQueryable();

		if (!string.IsNullOrEmpty(eventName))
		{
			query = query.Where(x => x.Name == eventName);
		}

        if (aggregateId.HasValue)
        {
            query = query.Where(x => x.AggregateId == aggregateId);
        }

		if (fromDateOcurred.HasValue)
		{
			query = query.Where(x => x.DateOcurred >= fromDateOcurred.Value);
		}

		var aggreagateEvents = await query.Select(x => new { x.Name, x.AggregateId }).ToListAsync();
		foreach (var aggreagateEventGroup in aggreagateEvents.GroupBy(x => new {x.Name, x.AggregateId}))
		{
			var name = aggreagateEventGroup.Key.Name;
			var groupAggregateId = aggreagateEventGroup.Key.AggregateId;

			var aggreagateEvent = await _context
				.AggregateEvents
				.Where(x => x.AggregateId == groupAggregateId && x.Name == name)
				.OrderByDescending(x => x.DateOcurred)
				.FirstAsync();

            var domainEvent = aggreagateEvent.ToDomainEvent();

			await _eventBus.Publish(domainEvent);

			aggreagateEvent.PublishedAt = DateTime.UtcNow;
            await _context.SaveChangesAsync();
        }

        return Accepted();
	}

