[Route("api/[controller]")]
[ApiController]
public class ProviderMappingsController : ControllerBase
{
    private readonly IApplicationIntegrationContext _context;
    private readonly IPublishEndpoint _publish;
    private readonly IMediator _mediator;

    public ProviderMappingsController(
        IApplicationIntegrationContext context,
        IPublishEndpoint publish,
        IMediator mediator)
    {
        _context = context;
        _publish = publish;
        _mediator = mediator;
    }

    [HttpPost("request/{id}")]
    public async Task<IActionResult> PublishMappping([FromRoute] Guid id)
    {
        var mapping = await _context.ProviderMappings.FirstOrDefaultAsync(x => x.Id == id);

        var message = new ResourceAsyncRequestMessageBuilder(mapping).Build();

        await _publish.Publish(message);

        return Ok();
    }

    [HttpPost("{type}/{provider}")]
    public async Task<IActionResult> PublishMapppings(
        [FromRoute] string type,
        [FromRoute] string provider,
        [FromBody] PublishMappingRequest request)
    {
        var mappings = await _context
            .ProviderMappings
            .Where(x => x.Type == type && x.ProviderName == provider && request.ExternalIds.Contains(x.ExternalId))
            .ToListAsync();

        foreach (var mapping in mappings)
        {
            var message = new ResourceAsyncRequestMessageBuilder(mapping).Build();

            await _publish.Publish(message);
        }

        return Ok();
    }

    public Task<IActionResult> CreateMapping([FromBody] CreateProviderMappingWithEntity request)
        => _mediator.HandleRequest<Guid>(request);
}

