// File: RealtimeMatches.Api/Middlewares/CommandEndpointsMiddleware.cs
// Namespace: RealtimeMatches.Api.Middlewares
// Class: CommandEndpointsMiddleware
using MediatR;
using Microsoft.AspNetCore.Http;
using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Partidas.Commands.Base;
using RealtimeMatches.Application.Partidas.Commands.Lances.Contracts;
using System;
using System.Collections.Generic;
using System.Linq;

public async Task InvokeAsync(HttpContext context)
	{
		var path = context.Request.Path;

		if (context.Request.Method != "POST" || !path.Value.StartsWith(CommandPrefix))
		{
			await _next(context);
			return;
		}

        var response = default(object);

        var routeValues = path.Value.Split('/').Where(x => !string.IsNullOrEmpty(x));

		var commandName = routeValues.ElementAt(1);
		var commandType = default(Type);

		var commands = _appAssembly
			.GetTypes()
			.Where(x => !x.IsAbstract && (x.BaseType == typeof(Command) || x.BaseType == typeof(Command<Guid>) || x.BaseType == typeof(LanceCommand) || x.BaseType == typeof(AtualizarPartidaBaseCommand)))
			.ToList();

		if (commandName.Equals("schemas", StringComparison.OrdinalIgnoreCase))
		{
			response = commands.Select(cmdType => new { Name = cmdType.Name, Schema = CreateCommandSchema(cmdType) });
        }
		else
		{
			commandType = commands.FirstOrDefault(x => x.Name.Equals(commandName, StringComparison.OrdinalIgnoreCase));
			if (commandType == null)
			{
				context.Response.StatusCode = 404;
				return;
			}

            if (routeValues.Count() > 2 && routeValues.ElementAt(2).Equals("schema", StringComparison.OrdinalIgnoreCase))
            {
                response = CreateCommandSchema(commandType);
            }
            else
            {
                var request = context.Request;

                request.EnableBuffering();
                var buffer = new byte[Convert.ToInt32(request.ContentLength)];
                await request.Body.ReadAsync(buffer, 0, buffer.Length);

                var json = Encoding.UTF8.GetString(buffer);

                var command = JsonConvert.DeserializeObject(json, commandType);

                var mediator = context.RequestServices.GetService(typeof(IMediator)) as IMediator;

                if (command is Command<Guid> commandGuid)
                {
                    var responseGuid = await mediator.Send<Guid>(commandGuid);
                    response = new { id = responseGuid };
                }
                else
                {
                    response = await mediator.Send(command);
                }
            }
        }

		var responseJson = JsonConvert.SerializeObject(response, _jsonSerializerSettings);
		var bytes = Encoding.UTF8.GetBytes(responseJson);

		context.Response.ContentType = "application/json";
		context.Response.StatusCode = 200;

		await context.Response.Body.WriteAsync(bytes);
	}

