// Namespace: RealtimeMatches.Api.Middlewares
// Class: CommandEndpointsMiddleware
using MediatR;
using Microsoft.AspNetCore.Http;
using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Partidas.Commands.Base;
using RealtimeMatches.Application.Partidas.Commands.Lances.Contracts;
using System;
using System.Collections.Generic;
using System.Linq;

private object CreateCommandSchema(Type commandType)
	{
		//var commandSchema = Activator.CreateInstance(commandType);
		var commandSchema = System.Runtime.Serialization.FormatterServices.GetUninitializedObject(commandType);

        var childObjects = commandType
            .GetProperties()
            .Where(x => x.PropertyType.IsClass &&
                        !x.PropertyType.IsPrimitive &&
                        x.PropertyType != typeof(Decimal) &&
                        x.PropertyType != typeof(String) &&
                        !x.PropertyType.IsArray);

        foreach (var child in childObjects)
        {
            var childInstance = System.Runtime.Serialization.FormatterServices.GetUninitializedObject(child.PropertyType);
            child.SetValue(commandSchema, childInstance);
        }

		return commandSchema;
    }

