[HttpGet("grupo/generate")]
	public async Task<IActionResult> GenerateGrupoTable([Required] Guid tabelaId, [Required] string grupo)
	{
		var grupoNome = Enum.Parse<GrupoNome>(grupo.ToUpper());

		var tabela = await _tabelaRepository.GetTabelaTopScorersById(tabelaId);

		var rodadaGrupo = await _temporadaRepository.GetGrupoRodada(tabela.TemporadaId, grupoNome);

		var partidasRodada = await _partidaRepository.GetPartidasRodada(rodadaGrupo);

		var table = _tabelaGrupoGenerator.GenerateGrupoClassificacao(grupoNome, partidasRodada).OrderByDescending(x => x.Pontos);

		return Ok(table);
	}

