[Route("api/v1/[controller]")]
[ApiController]
public class TemporadasController : ControllerBase
{
    private readonly ITemporadaRepository _repository;
    private readonly IMediator _mediator;

    public TemporadasController(
        ITemporadaRepository repository,
        IMediator mediator)
    {
        _repository = repository;
        _mediator = mediator;
    }

    [HttpGet("{ano}")]
    public async Task<IActionResult> GetTemporada([FromRoute] string ano, [FromQuery] Guid campeonatoId)
    {
        var temporada = await _repository
            .Temporadas
            .Include(x => x.Rodadas)
            .FirstOrDefaultAsync(x => x.CampeonatoId == campeonatoId && x.Nome == ano);

        return Ok(temporada);
    }

    [HttpGet("participante/jogadores")]
    public async Task<IActionResult> GetJogadoresParticipantes([FromQuery] JogadoresParticipantesRequest request)
    {
        var response = await _mediator.Send(request);

        return Ok(response);
    }
}

