using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Net.Http;
using System.Net.Http.Json;
using System.Threading.Tasks;

public class ChampionshipsApiService
{
    private readonly HttpClient _client;
    private readonly ILogger<ChampionshipsApiService> _logger;
    private readonly string _baseUrl;

    public ChampionshipsApiService(HttpClient client,
                                   IConfiguration configuration,
                                   ILogger<ChampionshipsApiService> logger)
    {
        _client = client;
        _logger = logger;
        _baseUrl = configuration.GetValue<string>("ChampionshipApiBaseUrl", "https://api.championships.tech.pedroccrl.com");
    }

    public async Task AtualizarEscudoTime(Guid timeId, string escudoUrl)
    {
        try
        {
            var uri = $"{_baseUrl}/cmd/AtualizarEscudoTime";
            var response = await _client.PostAsJsonAsync(uri, new
            {
                aggregateId = timeId,
                escudo = escudoUrl
            });
        }
        catch (Exception e)
        {
            _logger.LogError(e, "Erro ao atualizar escudo time " + escudoUrl);
        }
    }
}

