public class IndexModel : PageModel
    {
        private readonly IMediator _mediator;

        [BindProperty]
        public DateTime? Date { get; set; }

        public List<DateTime> Dates { get; set; }

        public List<GetAgendaComCoberturaByDate.AgendaCobertura> Agenda { get; set; }

        public IndexModel(
            IMediator mediator)
        {
            Dates = new List<DateTime>();
            _mediator = mediator;

            for (int i = -3; i < 0; i++)
            {
                Dates.Add(DateTime.UtcNow.AddHours(-3).AddDays(i));
            }

            Dates.Add(DateTime.UtcNow.AddHours(-3));

            for (int i = 1; i <= 3; i++)
            {
                Dates.Add(DateTime.UtcNow.AddHours(-3).AddDays(i));
            }
        }

        public async Task OnGetAsync(DateTime? date)
        {
            date ??= DateTime.UtcNow.AddHours(-3);

            Date = date;

            Agenda = await _mediator.Send(new GetAgendaComCoberturaByDate.Contract { Date = Date.Value });

        }

        public async Task OnPostAsync(IFormCollection form)
        {
            var data = form["data"].First().Split(':');

            var partidaUniqueKey = data[0];
            var coberturaId = Guid.Parse(data[1]);

            var fixarResult = await _mediator.Send(new FixarCoberturaPartida.Contract
            {
                PartidaUniqueKey = partidaUniqueKey,
                CoberturaId = coberturaId,
            });

            Agenda = await _mediator.Send(new GetAgendaComCoberturaByDate.Contract { Date = Date.Value });
        }
    }

