using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Enums;
using System;
using System.ComponentModel.DataAnnotations;
using System.Linq;

// To protect from overposting attacks, enable the specific properties you want to bind to.
        // For more details, see https://aka.ms/RazorPagesCRUD.
        public async Task<IActionResult> OnPostAsync()
        {
            if (_campeonato == null)
                _campeonato = await _context.Campeonatos.FirstOrDefaultAsync(m => m.Id == Campeonato.Id);

            _campeonato.Id = Campeonato.Id;
            _campeonato.UpdatedAt = DateTime.UtcNow.AddHours(-3);
            _campeonato.Nome = Campeonato.Nome;
            _campeonato.RodadaAtual = Campeonato.RodadaAtual;
            _campeonato.Ativo = Campeonato.Ativo;
            _campeonato.Importancia = Campeonato.Importancia;
            _campeonato.SempreMostrarTabela = Campeonato.SempreMostrarTabela;
            _campeonato.Logo ??= Campeonato.Logo;
            _campeonato.Ano = Campeonato.Ano;
            _campeonato.Pais ??= Campeonato.Pais;
            _campeonato.OrderingKey = Campeonato.OrderingKey;

            try
            {
                await _context.SaveChangesAsync();
            }
            catch (DbUpdateConcurrencyException)
            {
                if (!CampeonatoExists(_campeonato.Id))
                {
                    return NotFound();
                }
                else
                {
                    throw;
                }
            }

            return RedirectToPage("./Index");
        }

