public class IndexModel : PageModel
    {
        private readonly IApplicationContext _context;

        public IndexModel(IApplicationContext context)
        {
            _context = context;
            Date = DateTime.UtcNow.AddHours(-3).Date;
        }

        [BindProperty(SupportsGet = true)]
        public DateTime? Date { get; set; }

        [BindProperty(SupportsGet = true)]
        public Guid? CampeonatoId { get; set; }

        public IList<PartidaAgregada> Partida { get; set; }
        public SelectList CampeonatoList { get; set; }

        public async Task OnGetAsync()
        {
            var query = _context
                .Partidas
                .IgnoreQueryFilters()
                .Include(p => p.Provider)
                .Include(p => p.Mandante)
                .Include(p => p.Visitante)
                .Include(p => p.Campeonato)
                .AsNoTracking()
                .AsQueryable();

            if (Date != null)
                query = query.Where(p => p.Data.Date == Date.Value.Date);

            if (CampeonatoId != null && CampeonatoId != Guid.Empty)
                query = query.Where(p => p.Campeonato.Id == CampeonatoId.Value);

            Partida = await query
                .Include(x => x.Campeonato)
                .OrderByDescending(p => p.Data)
                .ToListAsync();

            var campeonatosList = Partida.GroupBy(x => new { x.Campeonato.Id, x.Campeonato.Nome }).Select(x => x.Key).ToList();
            campeonatosList.Insert(0, new { Id = default(Guid), Nome = "--- Escolha um ---" });
            CampeonatoList = new SelectList(campeonatosList, "Id", "Nome");
        }
    }

