using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class IndexModel : PageModel
    {
        private readonly IApplicationContext _context;
        private readonly string _bucketName;

        public IndexModel(
            IApplicationContext context,
            IConfiguration configuration)
        {
            _context = context;

            _bucketName = configuration.GetSection("Aws:BucketName").Value;
        }

        [BindProperty(SupportsGet = true)]
        public string SearchString { get; set; }

        [BindProperty(SupportsGet = true)]
        public bool EscudoToUpdate { get; set; }

        [BindProperty(SupportsGet = true)]
        public DateTime? PlayOn { get; set; }

        public IList<Time> Time { get; set; }

        public async Task OnGetAsync()
        {
            var query = _context.Times.AsQueryable();
            var limit = 30;

            if (!string.IsNullOrEmpty(SearchString))
            {
                query = query.Where(x => x.Nome.Contains(SearchString));
            }

            if (EscudoToUpdate)
            {
                query = query.Where(x => string.IsNullOrEmpty(x.Escudo) || !x.Escudo.Contains(_bucketName));
            }

            if (PlayOn != null)
            {
                var partidasHoje = await _context.Partidas
                    .Where(p => p.Data.Date == PlayOn.Value.Date)
                    .Select(p => new[] { p.Mandante.Id, p.Visitante.Id })
                    .ToListAsync();

                var timesId = partidasHoje.SelectMany(p => p);

                query = query.Where(t => timesId.Contains(t.Id));

                limit = 160;
            }

            Time = await query.Take(limit).ToListAsync();
        }
    }

