public class DeleteModel : PageModel
    {
        private readonly RealtimeMatches.Admin.Context _context;
        private readonly VideoCacheService _videoCacheService;

        public DeleteModel(Context context, VideoCacheService videoCacheService)
        {
            _context = context;
            _videoCacheService = videoCacheService;
        }

        [BindProperty]
        public Video Video { get; set; }

        public async Task<IActionResult> OnGetAsync(Guid? id)
        {
            if (id == null)
            {
                return NotFound();
            }

            Video = await _context.Videos
                .Include(v => v.Campeonato)
                .Include(v => v.Partida).FirstOrDefaultAsync(m => m.Id == id);

            if (Video == null)
            {
                return NotFound();
            }
            return Page();
        }

        public async Task<IActionResult> OnPostAsync(Guid? id)
        {
            if (id == null)
            {
                return NotFound();
            }

            Video = await _context.Videos.FindAsync(id);

            if (Video != null)
            {
                Video.DeletedAt = DateTime.UtcNow.AddHours(-3);
                await _context.SaveChangesAsync();

                await _videoCacheService.DeleteVideo(Video.Id, Video.PublishedAt);
            }

            return RedirectToPage("./Index");
        }
    }

