using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Newtonsoft.Json.Linq;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Domain.Entities;
using System;
using System.Linq;
using System.Net.Http;

public class YoutubeModel : PageModel
    {
        private readonly IApplicationContext _context;
        private readonly VideoCacheService _videoCacheService;

        public YoutubeModel(IApplicationContext context, VideoCacheService videoCacheService)
        {
            _context = context;
            _videoCacheService = videoCacheService;
        }

        [BindProperty]
        public string VideoUrl { get; set; }

        public async Task<IActionResult> OnPostAsync()
        {
            var videoId = VideoUrl.Split("=").Last();

            var url = $"https://www.googleapis.com/youtube/v3/videos?part=id,snippet&key=AIzaSyAyu_Tj-ESui9UAqIcpM9okfvNdRD_Zsec&maxResults=1&id={videoId}&regionCode=BR";

            var http = new HttpClient();
            var response = await http.GetAsync(url);
            if (response.IsSuccessStatusCode)
            {
                var json = await response.Content.ReadAsStringAsync();

                var jObj = JObject.Parse(json);

                var item = jObj["items"][0]["snippet"];

                var title = (string)item["title"];
                var description = (string)item["description"];
                var thumb = (string)item["thumbnails"]["high"]["url"];
                var channelId = (string)item["channelId"];
                var publishedAt = (string)item["publishedAt"];
                var channelTitle = (string)item["channelTitle"];

                var video = new Video(
                    title,
                    videoId,
                    thumb,
                    description,
                    channelId,
                    channelTitle,
                    VideoUrl,
                    DateTime.Parse(publishedAt).AddHours(-3));

                _context.Videos.Add(video);
                await _context.SaveChangesAsync();

                var videoCache = new VideoCache(video.Id, video.Titulo, videoId, video.Thumbnail, video.Descricao, video.CanalId, video.CanalNome, video.Url, video.PublishedAt);

                await _videoCacheService.SaveVideo(videoCache);
            }

            VideoUrl =string.Empty;

            return this.Page();
        }
    }

