public class EditModel : PageModel
    {
        private readonly IApplicationContext _context;

        public EditModel(IApplicationContext context)
        {
            _context = context;
        }

        [BindProperty(SupportsGet = true)]
        public Guid? Id { get; set; }

        [BindProperty(SupportsGet = true)]
        public string Query { get; set; }

        [BindProperty]
        public Guid? TimeId { get; set; }

        public TimeProvider Time { get; private set; }

        public async Task OnGetAsync(Guid? id)
        {
            id ??= Id;

            Time = await _context
                .TimesProvider
                .Include(t => t.Provider)
                .Where(x => x.Id == id)
                .FirstOrDefaultAsync();

            Id = Time.Id;

            if (string.IsNullOrEmpty(Query))
            {
                Query = Time.Nome.Split(' ').Where(x => x.Length > 2).First().RemoveAccents();
            }

            var possiveisTimes = await _context.Times.Where(x => x.Nome.Contains(Query)).ToListAsync();

            ViewData["Time"] = new SelectList(possiveisTimes, "Id", "Nome");
        }

        public async Task<IActionResult> OnPostAsync()
        {
            Time = await _context
                .TimesProvider
                .Where(x => x.Id == Id)
                .FirstOrDefaultAsync();

            Time.TimeId = TimeId;

            await _context.SaveChangesAsync();

            return RedirectToPage("./Index");
        }
    }

