using MassTransit;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using Providers.Application.Common.Abstractions;
using Providers.Application.Services.Parameters;
using Providers.Domain.Models.Enums;
using Providers.Jobs.Extensions;
using Quartz;
using RealtimeMatches.Infrastructure.Bus.Messaging;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;

public async Task Execute(IJobExecutionContext context)
    {
        var job = context.JobDetail;
        var jobMap = job.JobDataMap;

        var parameters = jobMap.ToObject<TaskScheduleParameter>();
        switch (parameters.Type)
        {
            case ScheduleTaskType.PartidasDia:
                parameters.Data = jobMap.ToObject<PartidasDiaTaskData>();

                break;
            case ScheduleTaskType.Partida:
                parameters.Data = jobMap.ToObject<PartidaCoverageTaskData>();

                break;

            case ScheduleTaskType.ParticipanteTemporada:
                parameters.Data = jobMap.ToObject<ParticipanteTemporadaTaskData>();

                break;

            case ScheduleTaskType.TopScorersLiga:
                parameters.Data = jobMap.ToObject<LigaTemporadaTaskData>();

                break;
        }

        var attributes = new Dictionary<string, object>(jobMap.ToDictionary(p => p.Key, p => p.Value))
        {
            { "JobKey", job.Key}
        };

        var eventProducer = _eventProducers.FirstOrDefault(x => x.AppliesTo(parameters.Provider, parameters.Type));
        if (eventProducer is null)
        {
            _apmService.RecordCustomEvent("EventHandlerNotImplemented", attributes);

            return;
        }

        try
        {
            var @event = await eventProducer.ProduceEventAsync(parameters.Data);
            if (@event is null)
            {
                _apmService.RecordCustomEvent("EventUnproduced", attributes);

                return;
            }

            @event.Provider = parameters.Provider;
            @event.PublishedAt = DateTime.UtcNow;

            var eventMessage = EventMessage.BuildEventMessage(@event);

            await _publish.Publish(eventMessage);

            _apmService.RecordCustomEvent("EventProduced", new Dictionary<string, object>(attributes)
            {
                { "ProducedEventType", @event.GetType().Name }
            });

            var eventMetadata = JsonConvert.SerializeObject(@event);
            var eventType = @event.GetType().Name;

            _logger.LogInformation("EventProduced Type {eventType}: {eventMetadata}", eventType, eventMetadata);
        }
        catch (Exception e)
        {
            _apmService.RecordCustomEvent("EventProducedError", new Dictionary<string, object>(attributes)
            {
                { "Error", e.Message },
                { "Stacktrace", e.StackTrace }
            });
        }
    }

