using Quartz;
using System.Reflection;

public static class JobMapExtensions
{
    public static T ToObject<T>(this JobDataMap map)
        where T : class, new()
    {
        var someObject = new T();
        var someObjectType = someObject.GetType();

        foreach (var item in map.Where(x => string.IsNullOrEmpty(x.Value?.ToString()) == false))
        {
            object value;

            var property = someObjectType.GetProperty(item.Key);
            if (property is null)
            {
                continue;
            }

            var propertyType = property.PropertyType;
            
            if (propertyType.IsInterface)
            {
                continue;
            }
            else if (propertyType.IsEnum)
            {
                value = Enum.Parse(propertyType, item.Value.ToString());
            }
            else if (propertyType == typeof(TimeSpan))
            {
                value = TimeSpan.Parse(item.Value.ToString());
            }
            else if (propertyType == typeof(DateTime?) || propertyType == typeof(DateTime))
            {
                value = DateTime.Parse(item.Value.ToString());
            }
            else
            {
                value = Convert.ChangeType(item.Value, property.PropertyType);
            }

            property.SetValue(someObject, value, null);
        }

        return someObject;
    }

    public static IDictionary<string, object> AsDictionary(this object source, BindingFlags bindingAttr = BindingFlags.DeclaredOnly | BindingFlags.Public | BindingFlags.Instance)
    {
        return source.GetType().GetProperties(bindingAttr).ToDictionary
        (
            propInfo => propInfo.Name,
            propInfo => propInfo.GetValue(source, null)
        );

    }
}

