using Quartz;
using Quartz.Impl.Matchers;

public class JobCleaner : IJobCleaner
{
    private readonly ISchedulerFactory _schedulerFactory;

    public JobCleaner(ISchedulerFactory schedulerFactory)
    {
        _schedulerFactory = schedulerFactory;
    }

    public async Task<List<string>> DeleteIdleJobs(int fromDaysStoped)
    {
        var jobKeys = new List<string>();

        var scheduler = await _schedulerFactory.GetScheduler();

        var jobsKeys = await scheduler.GetJobKeys(GroupMatcher<JobKey>.AnyGroup());
        foreach (var jobKey in jobsKeys)
        {
            var jobDetail = await scheduler.GetJobDetail(jobKey);
            var jobMap = jobDetail.JobDataMap;

            var triggers = await scheduler.GetTriggersOfJob(jobKey);

            var isAtLeastOneRunning = false;

            foreach (var trigger in triggers)
            {
                var state = await scheduler.GetTriggerState(trigger.Key);
                if (state == TriggerState.Normal)
                {
                    isAtLeastOneRunning = true;
                    break;
                }
            }

            if (!isAtLeastOneRunning)
            {
                var date = DateTime.UtcNow;
                if (jobMap.Contains("Day") && !string.IsNullOrEmpty(jobMap.GetString("Day")))
                {
                    date = DateTime.ParseExact(jobMap.GetString("Day"), "dd/MM/yyyy HH:mm:ss", null);
                }

                if (jobMap.Contains("StartDate") && !string.IsNullOrEmpty(jobMap.GetString("StartDate")))
                {
                    date = DateTime.ParseExact(jobMap.GetString("StartDate"), "dd/MM/yyyy HH:mm:ss", null);
                }

                if ((DateTime.UtcNow - date).Days >= fromDaysStoped)
                {
                    await scheduler.DeleteJob(jobKey);
                    jobKeys.Add(jobKey.Name);
                }
            }
        }

        return jobKeys;
    }
}

