// Namespace: Providers.Jobs.Services
// Class: TaskSchedulerService
using Providers.Application.Models;
using Providers.Application.Services;
using Providers.Application.Services.Parameters;
using Providers.Domain.Models.Enums;
using Providers.Jobs.Exceptions;
using Providers.Jobs.Extensions;
using Providers.Jobs.Factories;
using Providers.Shared.Requests.Subscriptions.Responses;
using Quartz;

public async Task<ScheduledTaskResult> Schedule(TaskScheduleParameter parameter)
    {
        var producer = _eventProducerFactory.Create(parameter.Provider, parameter.Type);
        if (producer == null)
        {
            return new ScheduledTaskResult
            {
                Error = $"Nenhum EventProducer para {parameter.Provider} e {parameter.Type}"
            };
        }

        var jobData = new Dictionary<string, string>();
        foreach (var prop in parameter.GetType().GetProperties())
        {
            jobData.Add(prop.Name, prop.GetValue(parameter)?.ToString());
        }

        foreach (var prop in parameter.Data.GetType().GetProperties())
        {
            jobData.Add(prop.Name, prop.GetValue(parameter.Data)?.ToString());
        }

        var jobIdentifier = $"{parameter.Provider}:{parameter.Type}";
        switch (parameter.Type)
        {
            case ScheduleTaskType.PartidasDia:
                var partidaDiaData = parameter.Data as PartidasDiaTaskData;

                jobIdentifier += $":{partidaDiaData.Day:yyyy-MM-dd}";

                break;
            case ScheduleTaskType.Partida:
                jobIdentifier += $":{jobData[nameof(PartidaCoverageTaskData.Identifier)]}";

                break;
            case ScheduleTaskType.ParticipanteTemporada:
                var participanteTemporada = parameter.Data as ParticipanteTemporadaTaskData;

                jobIdentifier += $":{participanteTemporada.Season}:{participanteTemporada.LigaId}:{participanteTemporada.TimeNome}";

                break;

            case ScheduleTaskType.TopScorersLiga:
                var topScorerData = parameter.Data as LigaTemporadaTaskData;

                jobIdentifier += $":{topScorerData.Season}:{topScorerData.LigaId}";
                break;

        }

        var scheduler = await _schedulerFactory.GetScheduler();

        var job = JobBuilder.Create<EventProducerJob>()
            .StoreDurably()
            .WithIdentity(jobIdentifier)
            .SetJobData(new JobDataMap(jobData))
            .Build();

        if (await scheduler.CheckExists(job.Key))
        {
            throw new DuplicatedJobException($"Job with identifier {jobIdentifier} already exists.");
        }

        await scheduler.AddJob(job, true);

        var triggerIdentifier = $"{jobIdentifier}:{parameter.Interval.Seconds}";

        var triggerBuilder = TriggerBuilder.Create()
                            .WithIdentity(triggerIdentifier)
                            .WithSimpleSchedule(x => x
                                .WithInterval(parameter.Interval)
                                .RepeatForever()
                                .WithMisfireHandlingInstructionFireNow()
                            )
                            .ForJob(job);

        if (parameter.StartDate.HasValue)
        {
            triggerBuilder.StartAt(parameter.StartDate.Value);
        }
        else
        {
            triggerBuilder.StartNow();
        }

        if (parameter.EndDate.HasValue)
        {
            triggerBuilder.EndAt(parameter.EndDate.Value);
        }

        var trigger = triggerBuilder.Build();

        var scheduledAt = await scheduler.ScheduleJob(trigger);

        var result = new ScheduledTaskResult
        {
            Identity = jobIdentifier,
            ScheduledAt = scheduledAt,
        };

        return result;
    }

