// File: Providers/Providers.Application/Messaging/ResourceRequestConsumer.cs
// Namespace: Providers.Application.Messaging
// Class: ResourceRequestConsumer
using MassTransit;
using Microsoft.Extensions.DependencyInjection;
using Providers.Application.Messaging.Interfaces;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Resources;
using Providers.Shared.Requests.Messaging;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System.Diagnostics;
using System.Reflection;

public async Task Consume(ConsumeContext<IRequestResourceMessage> context)
    {
        var message = context.Message;
        var providerName = message.Provider;
        var provider = Enum.Parse<DataProvider>(providerName);

        var messageAttributes = new Dictionary<string, object>
        {
            { "Provider", providerName },
            { "MappingId", message.MappingId },
            { "ResourceId", message.ResourceId },
            { "ResourceType", message.ResourceType.ToString() },
        };

        _clientsAssembly = GetProviderAssembly(providerName);

        var resourceType = _domainAssembly.GetType($"Providers.Domain.Models.Resources.{message.ResourceType}Resource");

        _apmService.RecordCustomEvent("ResourceRequestReceived", new Dictionary<string, object>(messageAttributes)
        {
            { "ProviderResourceType", resourceType.Name },
        });

        using var scope = _scopeFactory.CreateScope();

        var handlerType = typeof(IResourceRequestHandler<>).MakeGenericType(resourceType);
        var appliesToProvider = handlerType.GetProperty(nameof(IResourceRequestHandler<Resource>.Provider));

        var providerHandler = scope.ServiceProvider.GetServices(handlerType)?.FirstOrDefault(x => (DataProvider)appliesToProvider.GetValue(x, null) == provider);
        if (providerHandler == null ||
            providerHandler.GetType().GetMethods().Any(method => method.ReturnType.FullName.Contains($"{message.ResourceType}Resource")) is false)
        {
            _apmService.RecordCustomEvent("ResourceRequestHandlerNotImplemented", new Dictionary<string, object>(messageAttributes)
            {
                { "ProviderResourceType", resourceType.Name }
            });

            return;
        }

        var resourceHandleMethod = handlerType.GetMethod(nameof(IResourceRequestHandler<Resource>.Handle));

        var requestType = typeof(ResourceRequest<>).MakeGenericType(resourceType);
        var request = Activator.CreateInstance(requestType);

        requestType.GetProperty(nameof(ResourceRequest<Resource>.ResourceId)).SetValue(request, message.ResourceId);
        requestType.GetProperty(nameof(ResourceRequest<Resource>.MappingId)).SetValue(request, message.MappingId);

        var sw = Stopwatch.StartNew();

        var task = (Task)resourceHandleMethod.Invoke(providerHandler, new object[] { request });

        await task.ConfigureAwait(false);

        sw.Stop();

        var resultProperty = task.GetType().GetProperty("Result");
        var resource = resultProperty.GetValue(task) as Resource;
        if (resource == null)
        {
            _apmService.RecordCustomEvent("ResourceRequestNoReply", new Dictionary<string, object>(messageAttributes)
            {
                { "ProviderResourceType", resourceType.Name }
            });

            return;
        }

        var reply = new ResourceReply(message, resource) as IResourceReplied;

        await context.Publish<IResourceReplied>(reply);

        _apmService.RecordCustomEvent("ResourceRequestReplied", new Dictionary<string, object>(messageAttributes)
        {
            { "ProviderResourceType", resourceType.Name },
            { "ReplyType", reply.GetType().Name }
        });
    }

