using Microsoft.AspNetCore.Mvc;
using Newtonsoft.Json.Linq;
using Providers.Application.Services;
using Providers.Application.Services.Parameters;
using Providers.Domain.Models.Enums;
using Providers.Shared.Requests.Subscriptions;

[HttpPost]
    public async Task<IActionResult> CreateSubscription([FromBody] TaskSubscriptionRequest request)
    {
        var parameter = new TaskScheduleParameter
        {
            Provider = request.Provider,
            Type = request.Type,
            StartDate = request.StartDate,
            EndDate = request.EndDate,
            Interval = TimeSpan.FromSeconds(request.IntervalSeconds)
        };

        var data = request.Data as JObject;

        switch (request.Type)
        {
            case ScheduleTaskType.PartidasDia:
                parameter.Data = data.ToObject<PartidasDiaTaskData>();

                break;
            case ScheduleTaskType.Partida:
                parameter.Data = data.ToObject<PartidaCoverageTaskData>();

                break;

            case ScheduleTaskType.ParticipanteTemporada:
                parameter.Data = data.ToObject<ParticipanteTemporadaTaskData>();
                break;

            case ScheduleTaskType.TopScorersLiga:
                parameter.Data = data.ToObject<LigaTemporadaTaskData>();

                break;
            default:
                break;
        }

        var result = await _taskSchedulerService.Schedule(parameter);
        if (string.IsNullOrEmpty(result.Error))
        {
            return Ok(result);
        }

        return BadRequest(result);
    }

