using Providers.Application.Common.Abstractions;
using Providers.Application.Models;
using Providers.Application.Services.Parameters;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Events;
using Providers.Domain.Models.Resources;
using Providers.Shared.Events.JogosVirtuais;

public async Task<IProviderEvent> ProduceEventAsync(ITaskData data)
    {
        var status = await _client.GetStatus();
        if (status.MercadoAberto)
        {
            return null;
        }

        var pontuacao = await _client.GetPontuacaoAtual();

        var campeonato = new CampeonatoResource("Brasileirão", "1", ResourceLanguage.PT);

        var @event = new TimeFantasiaPontuacaoCollectionUpdated(campeonato)
        {
            Rodada = status.RodadaAtual
        };

        foreach (var clube in pontuacao.Clubes)
        {
            var clubeAtletas = pontuacao.Atletas.Where(x => x.Value.ClubeId == clube.Value.Id);

            var pts = clubeAtletas.Sum(x => x.Value.Pontuacao);
            var timePts = new TimeFantasiaPontuacao
            {
                AtletasPontuando = clubeAtletas.Count(),
                Pontuacao = pts,
                Time = new TimeResource
                {
                    ResourceId = clube.Key,
                    Escudo = clube.Value.Escudos.The60X60,
                    ResourceLanguage = ResourceLanguage.PT,
                    Nome = clube.Value.Nome,
                },
                Atletas = clubeAtletas.Select(atleta => new AtletaFantasiaPontuacao
                {
                    Nome = atleta.Value.Apelido,
                    Foto = atleta.Value.Foto.Replace("FORMATO", "140x140"),
                    Pontuacao = atleta.Value.Pontuacao,
                    Posicao = pontuacao.Posicoes[atleta.Value.PosicaoId.ToString()].Abreviacao.ToUpper()
                })
            };

            @event.Times.Add(timePts);
        }

        return @event;
    }

