public class YoutubeVideoCollectionProducer : BaseProvider, IEventProducerTask
{
    private readonly IConfigRepository<YoutubeConfig> _configRepository;
    private readonly IYoutubeClient _client;
    private YoutubeConfig _config;

    public string[] Cron => new string[] {
        "0 0/40 1,11,13,15,17,19,21,23 * * ?", // A cada hora ímpar, minutos 00 e 40. Ex: 1h00, 01h40, 11h00, 11h40...
        "0 20 0,2,10,12,14,16,18,20,22 * * ?"  // A cada hora par, minuto 20. Ex: 0h20, 2h20, 10h20, 12h20...
    };

    public YoutubeVideoCollectionProducer(
        IConfigRepository<YoutubeConfig> configRepository,
        IYoutubeClient client)
    {
        _configRepository = configRepository;
        _client = client;
    }

    public async Task<IProviderEvent> ProduceEventAsync(ITaskData data)
    {
        _config = await _configRepository.GetConfig();

        var publishedAfter = DateTime.UtcNow.AddHours(-3).AddHours(-2);

        var getSearchTasks = _config.ChannelsId?.Select(channelId => _client.GetYoutubeSearchByChannelId(channelId, publishedAfter))
            ?? new List<Task<YoutubeSearchResponse>>();
        getSearchTasks.Append(_client.GetYoutubeSearchByQuery("melhores momentos", publishedAfter));

        var tasksResponse = await Task.WhenAll(getSearchTasks);

        var videos = tasksResponse.SelectMany(x => x.Items);

        var videosEvent = new List<Video>();

        foreach (var video in videos)
        {
            var info = video.Snippet;
            var videoUrl = $"https://www.youtube.com/watch?v={video.Id.VideoId}";

            videosEvent.Add(new Video(
                info.Title,
                video.Id.VideoId,
                info.Thumbnails.High.Url,
                info.Description,
                info.ChannelId,
                info.ChannelTitle,
                videoUrl,
                info.PublishedAt.AddHours(-3)));
        }

        return new VideoCollectionProduced(videosEvent);
    }

    public bool AppliesTo(DataProvider provider, ScheduleTaskType type)
        => provider == DataProvider.Youtube && type == ScheduleTaskType.Videos;
}

