using AutoMapper;
using Providers.ApiFootball.DTOs.Players;
using Providers.Application.Common.Abstractions;
using Providers.Application.Services.Parameters;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Events;
using Providers.Domain.Models.Resources;
using Providers.Domain.Models.ValueObjects;
using Providers.Shared.Events.Temporadas;

public async Task<IProviderEvent> ProduceEventAsync(ITaskData data)
    {
        var participanteTemporadaData = data as ParticipanteTemporadaTaskData;

        var leagueId = long.Parse(participanteTemporadaData.LigaId);
        var teamid = long.Parse(participanteTemporadaData.TimeId);
        var season = participanteTemporadaData.Season;

        var playersSquad = await _client.GetTeamSquad(teamid);

        if (playersSquad?.Players?.Any() is false)
        {
            return null;
        }

        var team = playersSquad.Team;
        var league = default(League);

        var jogadoresResource = new List<JogadorResource>();
        foreach (var playerSquad in playersSquad.Players)
        {
            var player = await _client.GetPlayer(playerSquad.Id, season);

            var jogadorResource = _mapper.Map<JogadorResource>(player.Player);
            jogadorResource.Posicao = playerSquad.GetPosicao();

            var clube = player.Statistics.Where(x => x.League.Country != "World").Select(x => x.Team).FirstOrDefault();

            if (clube != null)
            {
                jogadorResource.Clube = _mapper.Map<TimeResource>(clube);
            }

            league ??= player.Statistics.Where(x => x.League.Id == leagueId).Select(x => x.League).FirstOrDefault();

            jogadoresResource.Add(jogadorResource);
        }

        var timeResource = new TimeResource(team.Id.ToString(), ResourceLanguage.EN, team.Name, team.Logo);

        var campeonatoResource = new CampeonatoResource(league.Name, league.Id.ToString(), ResourceLanguage.EN);

        var temporada = new Temporada { Ano = league.Season.ToString() };

        return new ParticipanteLigaUpdated
        {
            Campeonato = campeonatoResource,
            Temporada = temporada,
            Jogadores = jogadoresResource,
            Time = timeResource
        };
    }

