using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Events;
using Providers.Domain.Models.Partidas;
using Providers.Shared.Events.Partidas;

public async Task<IProviderEvent> ProduceEventAsync(ITaskData data)
    {
        var coverageData = data as PartidaCoverageTaskData;

        var fixtureId = long.Parse(coverageData.PartidaId);

        var fixture = await _client.GetFixturesById(fixtureId);

        var (lineupMandante, lineupVisitante) = (fixture.Lineups.FirstOrDefault(), fixture.Lineups.LastOrDefault());

        var events = fixture.Events;

        lineupMandante ??= new() { Team = fixture.Teams.Home };
        lineupVisitante ??= new() { Team = fixture.Teams.Away };

        var coverage = new PartidaCoverageUpdated
        {
            Id = fixtureId.ToString(),
            Lances = GetLances(lineupMandante, lineupVisitante, events),
            Mandante = GetEscalacao(lineupMandante, events),
            Visitante = GetEscalacao(lineupVisitante, events)
        };

        return coverage;
    }

