using Providers.ApiFootball.DTOs.Fixtures;
using Providers.Application.Common.Abstractions;
using Providers.Application.Services.Parameters;
using Providers.Domain.Extensions;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Events;
using Providers.Domain.Models.Partidas;
using Providers.Shared.Events.Partidas;

private List<Lance> GetLances(FootballApiLineupFixtureDto home, FootballApiLineupFixtureDto away, List<FootbalApiEventFixtureDto> eventFixtures)
    {
        var lances = new List<Lance>();

        var homeId = home.Team.Id;
        var awayId = away.Team.Id;

        foreach (var dto in eventFixtures)
        {
            var jogador1 = default(JogadorLanceDto);
            var jogador2 = default(JogadorLanceDto);
            var indicador = default(LanceIndicador?);
            var side = default(LanceSide?);

            var timeIdProvider = dto.Team.Id.ToString();
            var timeNome = dto.Team.Name;
            var minuto = dto.Time.Elapsed.ToString();
            var extra = dto.Time.Extra?.ToString();
            var momento = new Momento(minuto, TipoMomento.UmTempoDe90Min)
            {
                Extra = extra
            };

            var player = dto.Player;
            var playerAssist = dto.Assist;

            jogador1 = player.GetJogador();

            if (playerAssist != null)
            {
                jogador2 = playerAssist.GetJogador();
            }

            if (homeId == dto.Team?.Id)
            {
                side = LanceSide.Mandante;
            }

            if (awayId == dto.Team?.Id)
            {
                side = LanceSide.Visitante;
            }

            switch (dto.Type.ToLower())
            {
                case "goal":
                    indicador = LanceIndicador.Gol;

                    if (dto.Detail == "Own Goal")
                    {
                        indicador = LanceIndicador.GolContra;
                    }

                    if (dto.Detail == "Missed Penalty")
                    {
                        indicador = LanceIndicador.PenaltiPerdido;

                        if (dto.Comments == "Penalty Shootout")
                        {
                            indicador = LanceIndicador.ErrouDisputaPenalti;
                        }
                    }
                    else
                    {
                        if (dto.Comments == "Penalty Shootout")
                        {
                            indicador = LanceIndicador.ConverteuDisputaPenalti;
                        }
                    }
                    break;
                case "card":
                    if (dto.Detail.Contains("Yellow"))
                        indicador = LanceIndicador.CartaoAmarelo;
                    else if (dto.Detail.Contains("Red"))
                        indicador = LanceIndicador.CartaoVermelho;
                    else
                        throw new ArgumentException($"Tipo de Cartão '{dto.Detail}' não identificado.");

                    break;
                case "subst":
                    indicador = LanceIndicador.Substituicao;

                    if (side == LanceSide.Mandante)
                    {
                        (jogador1, jogador2) = GetJogadorSubs(player, playerAssist, home);
                    }
                    else
                    {
                        (jogador1, jogador2) = GetJogadorSubs(player, playerAssist, away);
                    }

                    break;
                case "var":
                    if (dto.Detail == "Goal cancelled" ||
                        dto.Detail.Contains("Goal Disallowed"))
                    {
                        indicador = LanceIndicador.VarGolAnulado;
                    }
                    else if (dto.Detail == "Penalty confirmed")
                    {
                        indicador = LanceIndicador.VarPenaltiMarcado;
                    }
                    else
                    {
                        continue;
                    }

                    break;
                default:
                    break;
            }

            var lanceDto = new Lance(momento, indicador.Value, timeIdProvider)
            {
                Jogador1 = jogador1,
                Jogador2 = jogador2,
                Side = side
            };

            if (dto.Comments == "Penalty Shootout")
            {
                lanceDto.Periodo = "Cobrança de Pênaltis";
            }

            lances.Add(lanceDto);
        }

        return lances;
    }

