private Escalacao GetEscalacao(FootballApiLineupFixtureDto lineup, List<FootbalApiEventFixtureDto> eventsDto)
    {
        var jogadores = new List<JogadorEscalacao>();
        var reservas = new List<JogadorEscalacao>();

        if (lineup.StartXi != null)
        {
            foreach (var player in lineup.StartXi.Select(x => x.Player))
            {
                var jogadorEscalacao = new JogadorEscalacao
                {
                    Id = player.Id.ToString(),
                    Nome = player.Name,
                    Numero = player.Number.ToString(),
                    Posicao = player.GetPosicao(),
                    Scouts = GetPlayerScouts(player, eventsDto),
                    Foto = $"https://media.api-sports.io/football/players/{player.Id}.png"
                };

                jogadores.Add(jogadorEscalacao);

                var substEvent = eventsDto
                    .FirstOrDefault(x =>
                        (
                            // RapidApi inverte a ordem dependendo dos jogos.
                            // Fixture 721066 'assist' indica quem sai
                            // fixture 838701 'assist' indica quem entra
                            (x.Assist.Id == player.Id || x.Assist.Name.RemoveAccents() == player.Name.RemoveAccents()) ||
                            (x.Player.Id == player.Id || x.Player.Name.RemoveAccents() == player.Name.RemoveAccents())
                        ) &&
                        x.Type == "subst");
                if (substEvent != null)
                {
                    var playerIn = lineup
                        .Substitutes
                        .FirstOrDefault(x =>
                            // RapidApi inverte a ordem dependendo dos jogos.
                            // Fixture 721066 'assist' indica quem sai
                            // fixture 838701 'assist' indica quem entra
                            (x.Player.Id == substEvent.Player.Id || x.Player.Name.RemoveAccents() == substEvent.Player.Name.RemoveAccents()) ||
                            (x.Player.Id == substEvent.Assist.Id || x.Player.Name.RemoveAccents() == substEvent.Assist.Name.RemoveAccents())
                        )?.Player;
                    if (playerIn != null)
                    {
                        jogadorEscalacao.SubstituicaoTipo = SubstituicaoTipo.Sai;
                        lineup.Substitutes.RemoveAll(x => x.Player.Id == substEvent.Assist.Id);

                        var jogadorSubstEntra = new JogadorEscalacao
                        {
                            Id = playerIn.Id?.ToString(),
                            Nome = playerIn.Name,
                            Posicao = player.GetPosicao(),
                            Numero = playerIn.Number.ToString(),
                            SubstituicaoTipo = SubstituicaoTipo.Entra,
                            Scouts = GetPlayerScouts(playerIn, eventsDto),
                            Foto = $"https://media.api-sports.io/football/players/{player.Id}.png"
                        };

                        jogadores.Add(jogadorSubstEntra);
                    }
                }
            }

            reservas = lineup.Substitutes.Select(s => new JogadorEscalacao
            {
                Id = s.Player.Id?.ToString(),
                Nome = s.Player.Name,
                Numero = s.Player.Number.ToString(),
                Posicao = s.Player.GetPosicao(),
                Scouts = new EscalacaoScouts(),
                Foto = s.Player.Id.HasValue ? $"https://media.api-sports.io/football/players/{s.Player.Id}.png" : null
            }).ToList();
        }

        var escalacao = new Escalacao
        {
            Esquema = lineup.Formation,
            Tecnico = new Tecnico
            {
                Id = lineup.Coach?.Id.ToString(),
                Nome = lineup.Coach?.Name,
                Foto = lineup.Coach?.Photo,
            },
            Jogadores = jogadores,
            Reservas = reservas
        };

        return escalacao;
    }

