using AutoMapper;
using Providers.Application.Common.Abstractions;
using Providers.Application.Services.Parameters;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Events;
using Providers.Domain.Models.Resources;
using Providers.Domain.Models.ValueObjects;
using Providers.Shared.Events.Temporadas;

public class ApiFootballTopScorersLigaEventProducer : IEventProducerTask
{
    private readonly IMapper _mapper;
    private readonly IFootballApiClient _client;

    public ApiFootballTopScorersLigaEventProducer(
        IMapper mapper,
        IFootballApiClient client)
    {
        _mapper = mapper;
        _client = client;
    }

    public async Task<IProviderEvent> ProduceEventAsync(ITaskData data)
    {
        var parameters = data as LigaTemporadaTaskData;

        var topScorersResponse = await _client.GetTopScorersFromLeague(long.Parse(parameters.LigaId), parameters.Season);

        var topScorers = new List<TopScorer>();

        var league = topScorersResponse.First().Statistics.First().League;
        var campeonato = new CampeonatoResource(league.Name, league.Id.ToString(), ResourceLanguage.EN);
        var temporada = new Temporada { Ano = league.Season.ToString() };

        foreach (var dto in topScorersResponse)
        {
            var stats = dto.Statistics.First();

            var jogador = _mapper.Map<JogadorResource>(dto.Player);
            var scouts = _mapper.Map<Scout>(stats);
            jogador.Posicao = stats.Games.GetPosicao();

            topScorers.Add(new()
            {
                Jogador = jogador,
                Scouts = scouts
            });
        }

        return new TopScorersLigaUpdated
        {
            Campeonato = campeonato,
            Temporada = temporada,
            TopScorers = topScorers,
        };
    }

    public bool AppliesTo(DataProvider provider, ScheduleTaskType type)
        => provider == DataProvider.ApiFootball && type == ScheduleTaskType.TopScorersLiga;
}

