using AutoMapper;
using Providers.ApiFootball.DTOs.Players;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Resources;

public class PlayerProfile : Profile
{
    public PlayerProfile()
    {
        CreateMap<FootballApiPlayerDto, JogadorResource>()
            .ForMember(x => x.ResourceId, x => x.MapFrom(y => y.Id.ToString()))
            .ForMember(x => x.ResourceLanguage, x => x.MapFrom(y => ResourceLanguage.EN))
            .ForMember(x => x.NomeCompleto, x => x.MapFrom(y => (y.Firstname + " " + y.Lastname).Trim()))
            .ForMember(x => x.Apelido, x => x.MapFrom(y => y.Name))
            .ForMember(x => x.FotoUri, x => x.MapFrom(y => y.Photo.ToString()))
            .ForMember(x => x.DataNascimento, x => x.MapFrom(y => y.Birth != null ? y.Birth.Date : default(DateTime?)))
            .ForMember(x => x.Nacionalidade, x => x.MapFrom(y => y.Nationality))
            .ForMember(x => x.LocalNascimento, x => x.MapFrom(y => $"{y.Birth.Place}, {y.Birth.Country}"))
            .ForMember(x => x.AlturaCm, x => x.MapFrom(y => GetAltura(y.Height)))
            .ForMember(x => x.PesoKg, x => x.MapFrom(y => GetPeso(y.Weight)));
    }

    private static int? GetAltura(string height)
    {
        if (int.TryParse(height?.Replace(" cm", string.Empty), out var altura))
        {
            return altura;
        }

        return null;
    }

    private static int? GetPeso(string weight)
    {
        if (int.TryParse(weight?.Replace(" kg", string.Empty), out var peso))
        {
            return peso;
        }

        return null;
    }
}

