using Providers.ApiFootball.Factories.Rodadas;
using Providers.ApiFootball.Repositories;
using Providers.ApiFootball.Services;
using Providers.Application.Messaging;
using Providers.Application.Messaging.Interfaces;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Resources;

public async Task<CampeonatoResource> Handle(ResourceRequest<CampeonatoResource> request)
    {
        var leagueId = long.Parse(request.ResourceId);

        var league = await _client.GetLeague(leagueId);

        var campeonato = new CampeonatoResource(league.League.Name, league.League.Id.ToString(), ResourceLanguage.EN);

        foreach (var season in league.Seasons.Where(x => x.Year >= 2022))
        {
            var temporada = new TemporadaResource(season.Year.ToString(), $"{leagueId}_{season.Year}", ResourceLanguage.EN);

            campeonato.Temporadas.Add(temporada);

            var rounds = await _client.GetLeagueRounds(leagueId, season.Year);

            temporada.Rodadas = await _rodadaResourceFactory.CreateRodadaResourceCollection(league.League, season.Year, rounds);
        }

        await _partidasRepository.RegistryCampeonato(leagueId);

        return campeonato;
    }

