public async Task<List<Partida>> GetPartidasDia(DateTime date, int season)
    {
        var fixtures = await _client.GetFixturesByDate(date, season);

        var partidas = new List<Partida>();

        foreach (var fixture in fixtures)
        {
            var league = fixture.League;
            // ToDo: Configurar ligas
            if (league.Id != 1 && league.Id != 71)
            {
                continue;
            }

            var campeonato = new CampeonatoResource(league.Name, league.Id.ToString(), ResourceLanguage.EN);

            var home = fixture.Teams.Home;
            var away = fixture.Teams.Away;

            var mandante = GetTimeResource(home);
            var visitante = GetTimeResource(away);

            var temporada = new Temporada { Ano = season.ToString() };

            var rodada = await _rodadasFactory.CreateRodada(league.Id, season, league.Round);

            var status = fixture.Fixture.Status.Short switch
            {
                "TBD" => PartidaStatus.DataNaoDefinida,
                "NS" => PartidaStatus.NaoIniciada,
                "1H" => PartidaStatus.PrimeiroTempo,
                "BT" or // Break Time (in Extra Time)
                "HT" => PartidaStatus.Intervalo,
                "2H" => PartidaStatus.SegundoTempo,
                "ET" => PartidaStatus.Prorrogacao,
                "P" => PartidaStatus.DisputaPenaltis,
                "FT" => PartidaStatus.Encerrada,
                "SUSP" or
                "INT" or
                "PST" or
                "CANC" or
                "ABD" => PartidaStatus.SuspensaOuCancelada,
                _ => PartidaStatus.Encerrada
            };

            if (fixture.Fixture.Status.Long == "Match Finished")
                status = PartidaStatus.Encerrada;

            var goals = fixture.Goals;
            var penalty = fixture.Score.Penalty;

            Placar placar = null;
            if (goals.Away.HasValue && goals.Home.HasValue)
            {
                placar = new(goals.Home.Value, goals.Away.Value);
            }

            DisputaPenalti disputaPenalti = null;
            if (penalty.Away.HasValue && penalty.Home.HasValue)
            {
                disputaPenalti = new() { PenaltisConvertidosMandante = penalty.Home.Value, PenaltisConvertidosVisitante = penalty.Away.Value };
            }

            EstadioResource estadio = null;

            var venue = fixture.Fixture.Venue;
            if (venue != null)
            {
                estadio = new()
                {
                    ResourceId = venue.Id?.ToString(),
                    Nome = venue.Name,
                    Cidade = venue.City
                };

                if (venue.Id.HasValue)
                {
                    estadio.Imagem = $"https://media.api-sports.io/football/venues/{venue.Id}.png";
                }
            }

            var partida = new Partida
            {
                Id = fixture.Fixture.Id.ToString(),
                Campeonato = campeonato,
                Temporada = temporada,
                Mandante = mandante,
                Visitante = visitante,
                Rodada = rodada,
                Data = fixture.Fixture.Date.DateTime,
                Status = status,
                Placar = placar,
                DisputaPenaltis = disputaPenalti,
                Estadio = estadio
            };

            partidas.Add(partida);
        }

        return partidas;
    }

