using Providers.Domain.Models.Resources;
using Providers.Domain.Models.ValueObjects;

public class RodadasFactory : IRodadasFactory
{
    private readonly IEnumerable<IRodadasLeagueFactory> _rodadasLeagueFactories;
    private readonly IConfigRepository<FootballApiConfig> _configRepository;

    public RodadasFactory(
        IEnumerable<IRodadasLeagueFactory> rodadasLeagueFactories,
        IConfigRepository<FootballApiConfig> configRepository)
    {
        _rodadasLeagueFactories = rodadasLeagueFactories;
        _configRepository = configRepository;
    }

    public async Task<List<RodadaResource>> CreateRodadaResourceCollection(League league, int season, List<string> rounds)
    {
        var config = await _configRepository.GetConfig();

        foreach (var factory in _rodadasLeagueFactories)
        {
            factory.Config = config;
        }

        var leagueRodadasFactory = _rodadasLeagueFactories.FirstOrDefault(x => x.AppliesTo(league.Id, season));
        if (leagueRodadasFactory is null)
        {
            // ToDo: log with Apm
            throw new NotImplementedException();
        }

        return leagueRodadasFactory.CreateResourceCollection(league, season, rounds);
    }

    public async Task<Rodada> CreateRodada(long leagueId, int season, string round)
    {
        var config = await _configRepository.GetConfig();

        foreach (var factory in _rodadasLeagueFactories)
        {
            factory.Config = config;
        }

        var leagueRodadasFactory = _rodadasLeagueFactories.FirstOrDefault(x => x.AppliesTo(leagueId, season));
        if (leagueRodadasFactory is null)
        {
            // ToDo: log with Apm
            throw new NotImplementedException();
        }

        return leagueRodadasFactory.Create(leagueId, season, round);
    }
}

