public class PontosCorridosRodadaResourceFactory : IRodadasLeagueFactory
{
    public FootballApiConfig Config { get; set; }

    public bool AppliesTo(long leagueId, int season)
        => Config.PontosCorridosLeaguesId.Contains(leagueId) && season >= 2022;

    public Rodada Create(long leagueId, int season, string round)
    {
        var rodadaName = round.Replace("Regular Season -", "Rodada");

        var rodada = new Rodada
        {
            Language = ResourceLanguage.PT,
            Nome = rodadaName,
            ResourceId = round,
            Tipo = RodadaTipo.Numerada
        };

        return rodada;
    }

    public List<RodadaResource> CreateResourceCollection(League league, int season, List<string> rounds)
    {
        var rodadas = new List<RodadaResource>();

        foreach (var round in rounds)
        {
            var numero = int.Parse(round.Replace("Regular Season -", string.Empty));

            rodadas.Add(new RodadaResource(RodadaTipo.Numerada, "Rodada", $"Rodada {numero}", round, ResourceLanguage.PT)
            {
                NumeroRodada = numero,
            });
        }

        return rodadas;
    }
}

