using Providers.ApiFootball.DTOs;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Resources;
using Providers.Domain.Models.ValueObjects;

public List<RodadaResource> CreateResourceCollection(League league, int season, List<string> rounds)
    {
        var rodadas = new List<RodadaResource>();

        foreach (var grupo in _grupos)
        {
            var resourceId = $"{league.Id}:{season}:{grupo}";
            var nomeRodada = $"Group Stage {grupo}";
            var rodada = new RodadaResource(RodadaTipo.Grupo, grupo, nomeRodada, resourceId, ResourceLanguage.EN);

            rodadas.Add(rodada);
        }

        foreach (var round in rounds.Where(x => !x.Contains("Group")))
        {
            var roundRodada = Create(league.Id, season, round);
            var rodadaResource = new RodadaResource(roundRodada.Tipo, roundRodada.MataMataChave.ToString(), roundRodada.Nome, roundRodada.ResourceId, ResourceLanguage.EN);

            rodadas.Add(rodadaResource);
        }

        return rodadas;
    }

// File: Providers/Clients/Providers.ApiFootball/Factories/Rodadas/Leagues/WorldCupRodadaResourceFactory.cs
// Namespace: Providers.ApiFootball.Factories.Rodadas.Leagues
// Class: WorldCupRodadaResourceFactory
using Providers.ApiFootball.DTOs;
using Providers.Domain.Models.Enums;
using Providers.Domain.Models.Resources;
using Providers.Domain.Models.ValueObjects;

public Rodada Create(long leagueId, int season, string round)
    {
        RodadaTipo tipo;
        MataMataChave? mataMataChave = null;
        string nome;

        if (round.Contains("group", StringComparison.OrdinalIgnoreCase))
        {
            tipo = RodadaTipo.Grupo;
            round = nome = "?";
        }
        else
        {
            switch (round)
            {
                case "Round of 16":
                    tipo = RodadaTipo.Fase;
                    mataMataChave = MataMataChave.OitavasDeFinal;
                    nome = "Oitavas de Final";
                    break;
                case "Quarter-finals":
                    tipo = RodadaTipo.Fase;
                    mataMataChave = MataMataChave.QuartasDeFinal;
                    nome = "Quartas de Final";
                    break;
                case "Semi-finals":
                    tipo = RodadaTipo.Fase;
                    mataMataChave = MataMataChave.Semifinal;
                    nome = "Semifinal";
                    break;
                case "Final":
                    tipo = RodadaTipo.Fase;
                    mataMataChave = MataMataChave.Final;
                    nome = "Final";
                    break;
                case "3rd Place Final":
                    tipo = RodadaTipo.Fase;
                    mataMataChave = MataMataChave.Disputa3Lugar;
                    nome = "Disputa 3o Lugar";
                    break;
                default:
                    throw new NotImplementedException(round + " not implemented.");
            }
        }

        return new Rodada
        {
            ResourceId = $"{leagueId}:{season}:{round}",
            Language = ResourceLanguage.EN,
            Nome = nome,
            Tipo = tipo,
            MataMataChave = mataMataChave
        };
    }

