using Amazon.Lambda.APIGatewayEvents;
using CSharpFunctionalExtensions;
using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;
using System.Collections.Generic;

public class APIGatewayResponseBuilder
    {
        private static JsonSerializerSettings _serializerSettings = new JsonSerializerSettings
        {
            ContractResolver = new CamelCasePropertyNamesContractResolver()
        };

        private static Dictionary<string, string> _headers = new Dictionary<string, string>
        {
            { "content-type", "application/json; charset=utf-8" }
        };

        public static APIGatewayProxyResponse Failure(string error)
        {
            var json = JsonConvert.SerializeObject(new { error }, _serializerSettings);

            return new APIGatewayProxyResponse
            {
                Body = json,
                Headers = _headers,
                StatusCode = 400
            };
        }

        public static APIGatewayProxyResponse Generic(string json, int statusCode)
        {
            return new APIGatewayProxyResponse
            {
                Body = json,
                Headers = _headers,
                StatusCode = statusCode
            };
        }
    }

