using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using RealtimeMatches.Application;
using RealtimeMatches.Infrastructure;
using RealtimeMatches.Infrastructure.Logs;
using System.IO;

public static class DependencyInjection
{
    public static IServiceScopeFactory GetScopeFactory(string functionName = null)
    {
        var configuration = new ConfigurationBuilder()
            .SetBasePath(Directory.GetCurrentDirectory())
            .AddJsonFile("appsettings.json", true, true)
            .AddEnvironmentVariables()
            .Build();

        var services = new ServiceCollection();

        services.AddSingleton<IConfiguration>(configuration);

        if (string.IsNullOrEmpty(functionName))
        {
            services.AddLogging(configuration);
        }
        else
        {
#if DEBUG
            services.AddFunctionLogging(configuration, functionName + "-DEBUG");
#else
            services.AddFunctionLogging(configuration, functionName);
#endif
        }

        services.AddInfrastructure(configuration);
        services.AddApplication();

        var scopeFactory = services.BuildServiceProvider().GetService<IServiceScopeFactory>();

        return scopeFactory;
    }
}

