// Namespace: RealtimeMatches.Functions.Common
using Amazon.Lambda.APIGatewayEvents;
using CSharpFunctionalExtensions;
using MediatR;
using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;
using System.Collections.Generic;
using System.Threading.Tasks;

public static class Extensions
    {
        private static JsonSerializerSettings _serializerSettings = new JsonSerializerSettings
        {
            ContractResolver = new CamelCasePropertyNamesContractResolver()
        };

        public static async Task<APIGatewayProxyResponse> HandleAndReturn<TResponse>(this IMediator mediator, IRequest<Result<TResponse>> contract)
        {
            var result = await mediator.Send(contract);

            return ResultToResponse(result);
        }

        public static APIGatewayProxyResponse ResultToResponse<TResponse>(Result<TResponse> result)
        {
            var response = new APIGatewayProxyResponse
            {
                Headers = new Dictionary<string, string>
                {
                    { "content-type", "application/json; charset=utf-8" }
                }
            };

            if (result.IsFailure)
            {
                var errorJson = JsonConvert.SerializeObject(new { error = result.Error }, _serializerSettings);

                response.StatusCode = 400;
                response.Body = errorJson;
            }
            else
            {
                var valueJson = JsonConvert.SerializeObject(result.Value, _serializerSettings);

                response.StatusCode = 200;
                response.Body = valueJson;
            }

            return response;
        }
    }

