public async Task<APIGatewayProxyResponse> FunctionHandler(APIGatewayProxyRequest input, ILambdaContext context)
        {
            var response = new APIGatewayProxyResponse();

            try
            {
                using var scope = _scopeFactory.CreateScope();

                var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

                var dia = "hoje";
                var campeonatoId = default(Guid?);

                if (input.PathParameters != null && input.PathParameters.ContainsKey("dia"))
                {
                    dia = input.PathParameters["dia"];
                    if (input.PathParameters.ContainsKey("campeonatoId"))
                    {
                        if (Guid.TryParse(input.PathParameters["campeonatoId"], out var campGuid))
                            campeonatoId = campGuid;
                    }
                }

                response = await mediator.HandleAndReturn(new BuscarPartidasPorDia.Contract { Dia = dia, CampeonatoId = campeonatoId, CacheOnly = true });
                if (response.StatusCode == 400)
                {
                    var configuration = scope.ServiceProvider.GetRequiredService<IConfiguration>();
                    var apiUrl = configuration.GetValue("ApiUrl", "http://ip-172-31-7-242.ec2.internal/api");

                    try
                    {
                        var http = new HttpClient();
                        var httpResponse = await http.GetAsync($"{apiUrl}/jogos/{dia}");

                        var json = await httpResponse.Content.ReadAsStringAsync();

                        if (httpResponse.IsSuccessStatusCode)
                            return APIGatewayResponseBuilder.Generic(json, 200);

                        return APIGatewayResponseBuilder.Generic(json, 400);
                    }
                    catch (Exception e)
                    {
                        return APIGatewayResponseBuilder.Failure("error " + e.Message);
                    }
                }

                return response;
            }
            catch (Exception e)
            {
                context.Logger.Log(e.Message + e.StackTrace);

                response.Body = e.StackTrace;
                response.StatusCode = 500;

                return response;
            }
        }

