            var response = await mediator.HandleAndReturn(new GetPartidaByIdAndDate.Contract
            {
                PartidaId = partidaId,
                PartidaData = partidaData,
                FichaCompleta = true,
                CacheOnly = true
            });

            if (response.StatusCode == 400)
            {
                var configuration = scope.ServiceProvider.GetRequiredService<IConfiguration>();
                var apiUrl = configuration.GetValue("ApiUrl", "http://ip-172-31-7-242.ec2.internal/api");

