        public CampeonatoCategoria Categoria { get; set; }
        public bool SempreMostrarTabela { get; set; }
        public int OrderingKey { get; set; }
        public List<PartidaAgregada> Partidas { get; set; }
        public List<Video> Videos { get; set; }

        public ClassificacaoCampeonato Classificacao { get; set; }
        public Guid? ClassificacaoId { get; set; }

        public PartidasProvider Provider { get; set; }
        public Guid ProviderId { get; set; }

        /// <summary>
        /// Canais que vão transmitir todos os jogos do campeonato
        /// </summary>
        public List<CampeonatoCanal> Canais { get; set; }

        public Campeonato(string nome, Guid providerId, bool ativo = false)
        {
            Id = nome.ToGuid();

            Nome = nome;
            Ativo = ativo;
            Categoria = CampeonatoCategoria.Principal;

            ProviderId = providerId;

            var isSub = nome.ToLower().Contains("sub-");
            if (isSub)
                Categoria = CampeonatoCategoria.SubCategoria;

            var isFem = nome.ToLower().Contains("feminino");
            if (isFem)
                Categoria = CampeonatoCategoria.Feminino;

            if (isFem && isSub)
                Categoria = CampeonatoCategoria.SubFeminino;
        }

        [JsonConstructor]
        private Campeonato()
        {

        }
    }

