public int GetMinutoCorrido()
        {
            var start = 0;

            if (Periodo == "Intervalo" ||
                Periodo == "2º tempo")
                start = 45;

            if (Periodo.Equals("1º tempo da prorrogação", StringComparison.OrdinalIgnoreCase) ||
                Periodo.Equals("aguardando prorrogação", StringComparison.OrdinalIgnoreCase) ||
                Periodo.Equals("intervalo da prorrogação", StringComparison.OrdinalIgnoreCase))
                start = 90;
            
            if (Periodo.Equals("2º tempo da prorrogação", StringComparison.OrdinalIgnoreCase))
                start = 105;

            _ = int.TryParse(Minuto.Replace("'", ""), out var min);

            return start + min;
        }

