public PartidaAgregada AtualizarPlacar(int? mandante, int? visitante, int? penaltiMandante, int? penaltiVisitante, string destaqueMandante = null, string destaqueVisitante = null)
    {
        if (Status != PartidaStatus.NaoComecou)
        {
            if (mandante > PlacarMandante)
            {
                Events.Add(new PartidaEvent(this, PartidaEventType.Placar, $"GOOL do {Mandante.Nome}!!!")
                {
                    Descricao = $"{Mandante.Nome} [{mandante}] x {visitante} {Visitante.Nome}"
                });
            }

            if (visitante > PlacarVisitante)
            {
                Events.Add(new PartidaEvent(this, PartidaEventType.Placar, $"GOOL do {Visitante.Nome}!!!")
                {
                    Descricao = $"{Mandante.Nome} {mandante} x [{visitante}] {Visitante.Nome}"
                });
            }
        }

        if (mandante.HasValue)
            PlacarMandante = mandante;

        if (visitante.HasValue)
            PlacarVisitante = visitante;

        DestaqueMandante = destaqueMandante;
        DestaqueVisitante = destaqueVisitante;

        PenaltiMandante = penaltiMandante;
        PenaltiVisitante = penaltiVisitante;

        return this;
    }

// File: Domain/RealtimeMatches.Domain/Entities/PartidaAgregada.cs
// Namespace: RealtimeMatches.Domain.Entities
// Class: PartidaAgregada
using RealtimeMatches.Domain.Entities.Fantasia;
using RealtimeMatches.Domain.Events;
using System;
using System.Collections.Generic;

public PartidaAgregada AtualizarStatus(PartidaStatus status, string momento = null)
    {
        Momento ??= momento;

        var horarioBr = DateTime.UtcNow.AddHours(-3);

        if (status == PartidaStatus.AoVivo && horarioBr < Data)
            Status = PartidaStatus.NaoComecou;
        else
        {
            if (status == PartidaStatus.AoVivo && Status == PartidaStatus.NaoComecou)
            {
                Events.Add(new PartidaEvent(this, PartidaEventType.Status, "Início de Jogo!")
                {
                    Descricao = $"{Mandante.Nome} x {Visitante.Nome} - {Rodada} - {Campeonato.Nome}"
                });
            }

            if (status == PartidaStatus.Encerrada && Status == PartidaStatus.AoVivo)
            {
                Events.Add(new PartidaEvent(this, PartidaEventType.Status, "Partida Encerrada!")
                {
                    Descricao = $"{Mandante.Nome} {PlacarMandante} x {PlacarVisitante} {Visitante.Nome} - {Rodada} - {Campeonato.Nome}"
                });
            }

            Status = status;
        }

        return this;
    }

