            MataMataChave.Semifinal => FaseTipo.Semifinal,
            MataMataChave.QuartasDeFinal => FaseTipo.Quartas,
            MataMataChave.OitavasDeFinal => FaseTipo.Oitavas,
            _ => throw new ArgumentOutOfRangeException()
        };

