public record Momento
{
    public TipoMomento Tipo { get; set; }
    public int Tempo { get; set; }
    public int? Extra { get; set; }

    public int GetTempoTotal()
    {
        if (Tempo <= 45)
        {
            return Tempo;
        }
        else
        {
            return Tempo + Extra.GetValueOrDefault();
        }
    }

    public static Momento Inicial() => new() { Tempo = 0, Tipo = TipoMomento.PreJogo };
    public static Momento Final() => new() { Tempo = 90, Tipo = TipoMomento.PosJogo };
}

