// Namespace: RealtimeMatches.Domain.Profiles.Partidas
using AutoMapper;
using RealtimeMatches.Domain.Entities.Aggregates.Partidas;
using RealtimeMatches.Domain.Projections.Partidas;
using RealtimeMatches.Domain.Projections.Partidas.Escalacoes;
using RealtimeMatches.Domain.Projections.Partidas.Lances;
using RealtimeMatches.Domain.ValueObjects.Partidas;

public class PartidasProfile : Profile
{
    public PartidasProfile()
    {
        CreateMap<Partida, PartidaProjection>();

        CreateMap<Equipe, EquipeProjection>();

        CreateMap<Partida, PartidaLancesProjection>();
        CreateMap<Lance, LanceProjection>();
        CreateMap<JogadorLance, JogadorLanceProjection>();

        CreateMap<Partida, PartidaEscalacoesProjection>();

        CreateMap<Equipe, EscalacaoProjection>()
            .ForMember(x => x.Treinador, x => x.MapFrom(y => y.Comandante.Pessoa.Nome))
            .ForMember(x => x.TreinadorFoto, x => x.MapFrom(y => y.Comandante.Pessoa.Foto));

        CreateMap<Titular, JogadorRelacionadoProjection>()
            .ForMember(x => x.Nome, x => x.MapFrom(y => y.Pessoa.Nome))
            .ForMember(x => x.Foto, x => x.MapFrom(y => y.Pessoa.Foto));

        CreateMap<Reserva, JogadorRelacionadoProjection>()
            .ForMember(x => x.Nome, x => x.MapFrom(y => y.Pessoa.Nome))
            .ForMember(x => x.Foto, x => x.MapFrom(y => y.Pessoa.Foto));
    }
}

