using AutoMapper;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.MataMataFases;
using RealtimeMatches.Domain.Projections.Tabelas;
using System.Linq;

public class TabelaProfile : Profile
{
    public TabelaProfile()
    {
        CreateMap<TabelaFases, TabelaProjection>()
            .ForMember(x => x.Fases, x => x.MapFrom(y => y.Fases.OrderBy(x => x.Ordem).Select(x => x.Id.ToString())));

        CreateMap<FaseGrupos, FaseProjection>()
            .ForMember(x => x.RegulamentoFaseMataMata, x => x.Ignore())
            .ForMember(x => x.RegulamentoFaseGrupos, x => x.MapFrom(y => y.Regulamento));

        CreateMap<FaseMataMata, FaseProjection>()
            .ForMember(x => x.RegulamentoFaseGrupos, x => x.Ignore())
            .ForMember(x => x.RegulamentoFaseMataMata, x => x.MapFrom(y => y.Regulamento));

        CreateMap<Grupo, GrupoProjection>();

        CreateMap<GrupoTimeClassificacao, GrupoTimeClassificacaoProjection>();
    }
}

