// Namespace: RealtimeMatches.Domain.Profiles.Temporadas
using AutoMapper;
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;
using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.Enums.Temporadas;
using RealtimeMatches.Domain.Projections.Temporadas;

public class TemporadaProfile : Profile
{
    public TemporadaProfile()
    {
        CreateMap<Temporada, TemporadaProjection>();

        CreateMap<Rodada, RodadaProjection>()
            .ForMember(x => x.Nome, x => x.MapFrom(y => GetRodadaNome(y)));

        CreateMap<PalcoTemporada, PalcoTemporadaProjection>();
    }

    private string GetRodadaNome(Rodada rodada)
        => rodada.Tipo switch
        {
            RodadaTipo.Amistoso => "Amistoso",
            RodadaTipo.Grupo => "Grupo " + rodada.Grupo,
            RodadaTipo.PontosCorridos => "Rodada " + rodada.Numero,
            RodadaTipo.MataMata => rodada.MataMata switch
            {
                MataMataChave.OitavasDeFinal => "Oitavas de Final",
                MataMataChave.QuartasDeFinal => "Quartas de Final",
                MataMataChave.Disputa3Lugar => "Disputa 3o Lugar",
                _ => rodada.MataMata.ToString()
            },
            _ => string.Empty
        };
}

