using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.Events.Campeonatos;
using System;
using System.Collections.Generic;
using System.Linq;

public class Campeonato : AggregateRoot
{
    public string Nome { get; private set; }
    public string Logo { get; private set; }
    public string Slug { get; private set; }
    public CampeonatoOrganizacao Organizacao { get; private set; }
    public List<Participacao> Participacoes { get; set; }

    public Campeonato(string nome, string slug, CampeonatoOrganizacao organizacao, string logo = null)
    {
        Nome = nome;
        Slug = slug;
        Organizacao = organizacao;
        Logo = logo;

        Participacoes = new List<Participacao>();

        AddDomainEvent(new CampeonatoCriado(this));
    }

    private Campeonato()
    {

    }

    public void AdicionarParticipacao(Guid timeId, params string[] titulos)
    {
        if (Participacoes.Any(x => x.TimeId == timeId))
        {
            Participacoes.RemoveAll(x => x.TimeId == timeId);
        }

        var participacao = new Participacao(Id, timeId, titulos);
        Participacoes.Add(participacao);

        AddDomainEvent(new ParticipacaoAdicionada(participacao));
    }
}

