public void AtualizarInformacoes(
        string nome,
        string nomeCompleto,
        string descricao,
        string informacao,
        string historia,
        string curiosidade)
    {
        if ((nome ?? nomeCompleto ?? descricao ?? informacao ?? historia ?? curiosidade) == null)
        {
            return;
        }

        Nome = nome ?? Nome;
        NomeCompleto = nomeCompleto ?? NomeCompleto;
        Descricao = descricao ?? Descricao;
        Informacao = informacao ?? Informacao;
        Historia = historia ?? Historia;
        Curiosidade = curiosidade ?? Curiosidade;

        AddDomainEvent(new EstadioAtualizado(this));
    }

