using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.Events.Estadios;
using RealtimeMatches.Domain.ValueObjects;
using System.Collections.Generic;
using System.Linq;

public void AtualizarNomesAlternativos(string[] nomes)
    {
        NomesAlternativos ??= new();

        NomesAlternativos?.Clear();

        foreach (var nome in nomes)
        {
            if (NomesAlternativos.Any(x => x.Nome.Equals(nome, System.StringComparison.OrdinalIgnoreCase)))
            {
                continue;
            }

            NomesAlternativos.Add(new EstadioNomeAlternativo(Id, nome));
        }
    }

