using System;
using System.Collections.Generic;

public class Equipe : Entity
{
    public Partida Partida => MandantePartida ?? VisitantePartida;
    public Guid PartidaId => (MandantePartidaId ?? VisitantePartidaId).Value;

    protected Partida MandantePartida { get; set; }
    protected Guid? MandantePartidaId { get; private set; }

    protected Partida VisitantePartida { get; set; }
    protected Guid? VisitantePartidaId { get; private set; }

    public Guid? TimeId { get; set; }

    public string Nome { get; set; }
    public string Escudo { get; set; }
    public string Esquema { get; set; }

    public List<Titular> Titulares { get; set; }
    public List<Reserva> Reservas { get; set; }
    public Comandante Comandante { get; set; }

    private Equipe(Guid timeId)
    {
        TimeId = timeId;

        Titulares = new List<Titular>();
        Reservas = new List<Reserva>();
    }

    protected Equipe()
    {

    }

    public void AtualizarEscalacao(List<Titular> titulares, List<Reserva> reservas, Comandante comandante, string esquema)
    {
        Titulares = titulares;
        Reservas = reservas;
        Comandante = comandante;
        Esquema = esquema;
    }

    public bool EquipeDefinida => TimeId.HasValue;
    public bool IsMandante => MandantePartidaId.HasValue;
    public bool IsVisitante => VisitantePartidaId.HasValue;

    public static Equipe Mandante(Guid partidaId, Guid timeId)
        => new(timeId) { MandantePartidaId = partidaId };

    public static Equipe Visitante(Guid partidaId, Guid timeId)
        => new(timeId) { VisitantePartidaId = partidaId };

    public static Equipe MandanteNaoDefinida() => new();
    public static Equipe VisitanteNaoDefinida() => new();
}

