public Partida(Guid rodadaId, DateTime? data = null)
    {
        RodadaId = rodadaId;
        Mandante = Equipe.MandanteNaoDefinida();
        Visitante = Equipe.VisitanteNaoDefinida();
        Data = data;

        Lances = new();

        if (data.HasValue)
        {
            Situacao = new Situacao(SituacaoStatus.AguardandoInicio);
        }
        else
        {
            Situacao = new Situacao(SituacaoStatus.DataNaoDefinida);
        }

        AddDomainEvent(new PartidaCriada(this));
    }

