public void DefinirMandante(Guid timeId, string nome, string escudo)
    {
        if (Mandante != null && Mandante.EquipeDefinida && Mandante.TimeId.Value != timeId)
        {
            throw new PartidaAtualizacaoValidationException("Mandante ja definido.");
        }

        Mandante = Equipe.Mandante(Id, timeId);
        Mandante.Nome = nome;
        Mandante.Escudo = escudo;

        AddDomainEvent(new PartidaEquipeDefinida(this, Mandante));
    }

