using System.Linq;

public void AtualizarEscalacao(Guid timeId, List<Titular> titulares, List<Reserva> reservas, Comandante treinador, string esquema = null)
    {
        Equipe equipe = GetEquipe(timeId);

        if (equipe.Titulares == null || equipe.Reservas == null ||
            (esquema != null && equipe.Esquema != esquema) ||
            (equipe.Comandante == null && treinador != null) ||
            equipe.Comandante?.TreinadorId != treinador.TreinadorId ||
            titulares.All(x => equipe.Titulares.Exists(y => y.JogadorId == x.JogadorId)) is false ||
            reservas.All(x => equipe.Reservas.Exists(y => y.JogadorId == x.JogadorId)) is false)
        {
            AddDomainEvent(new EscalacaoAtualizada(Id, equipe.Id));
        }

        equipe.AtualizarEscalacao(titulares, reservas, treinador, esquema);
    }

