    public void AtualizarDadosPessoais(string nomeCompleto, string foto, string apelido)
    {
        Pessoa.Nome = nomeCompleto ?? Nome;
        Pessoa.Foto = foto ?? Foto;

        Apelido = apelido ?? Apelido;

        if ((nomeCompleto ?? foto ?? apelido) != null)
        {
            AddDomainEvent(new JogadorDadosPessoaisAtualizados(this));
        }
    }

    public void AtualizarInformacoes(PosicaoAtuante? posicao, MedidasCorpo medidas, Nascimento nascimento)
    {
        Posicao = posicao ?? Posicao;
        Medidas = medidas ?? Medidas;
        Nascimento = nascimento ?? Nascimento;

        if (posicao != null || medidas != null || nascimento != null)
        {
            AddDomainEvent(new JogadorInformacoesAtualizadas(this));
        }
    }
}

