using System;

public class TabelaTimeClassificacao
{
    public TabelaPontosCorridos Tabela { get; set; }
    public Guid TabelaId { get; set; }

    public Guid TimeId { get; set; }

    public int Posicao { get; set; }

    public int Pontos => 3 * Vitorias + Empates;
    public int Jogos { get; set; }
    public int Vitorias { get; set; }
    public int Derrotas { get; set; }
    public int Empates { get; set; }
    public int GolsPro { get; set; }
    public int GolsContra { get; set; }
    public int SaldoGols => GolsPro - GolsContra;
    public double Aproveitamento
    {
        get
        {
            if (Jogos == 0)
            {
                return .0;
            }

            var aproveitamento = Math.Round(Pontos / (Jogos * 3.0) * 100, 1);
            return aproveitamento;
        }
    }
}

