using System;
using System.Collections.Generic;
using System.Linq;

/// <summary>
/// Time participante de uma temporada de um campeonato.
/// </summary>
public class Participante
{
    public Guid TemporadaId { get; set; }
    public Guid TimeId { get; set; }
    public List<JogadorParticipante> Jogadores { get; set; }

    public Participante(Guid temporadaId, Guid timeId)
    {
        TemporadaId = temporadaId;
        TimeId = timeId;
    }

    private Participante() { }

    public bool AdicionarJogador(JogadorParticipante jogador)
    {
        var jogadorParticipante = Jogadores
            .FirstOrDefault(x =>
                x.TemporadaId == jogador.TemporadaId &&
                x.TimeId == jogador.TimeId &&
                x.JogadorId == jogador.JogadorId
            );

        if (jogadorParticipante != null)
        {
            if (jogadorParticipante.TimeSecundario == null && jogador.TimeSecundario != null)
            {
                jogadorParticipante.AdicionarTimeSecundario(jogador.TimeSecundario);
            }

            return false;
        }

        Jogadores.Add(jogador);

        return true;
    }

    public bool ContainsJogador(Guid jogadorId)
        => Jogadores.Any(x => x.JogadorId == jogadorId);
}

