public class GrupoTimeClassificacao
{
    // ToDo: Verificar se relação (ef core) do grupo funciona como private 
    public Grupo Grupo { get; set; }

    public Guid FaseGruposId { get; set; }
    public GrupoNome GrupoNome { get; set; }
    public Guid TimeId { get; set; }

    public bool PartidaEmAndamento { get; set; }

    public int Posicao { get; set; }

    public int Pontos => 3 * Vitorias + Empates;
    public int Jogos { get; set; }
    public int Vitorias { get; set; }
    public int Derrotas { get; set; }
    public int Empates { get; set; }
    public int GolsPro { get; set; }
    public int GolsContra { get; set; }
