                var provider = _providersFactory.GetFakeProvider(providerId);

                var channelRequest = request.ChannelRequest;

                var events = provider.GetProviderEvents(channelRequest);

                await _mediator.Send(new UpdateChannelRequestCommand.Contract(channelRequest)
                {
                    Status = ChannelRequestStatus.Success,
                    Response = string.Empty
                });

                await _providerEventService.SendCommandEvents(events, cancellationToken);

                return Result.Success();
            }
        }
    }

