using System.Threading;

public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IMediator _mediator;
            private readonly ProvidersFactory _providersFactory;
            private readonly ProviderEventsHandler _providerEventService;
            private readonly ILogger<RestApiChannelResponseHandler> _logger;

            public Handler(
                IMediator mediator,
                ProvidersFactory providersFactory,
                ProviderEventsHandler providerEventService,
                ILogger<RestApiChannelResponseHandler> logger)
            {
                _mediator = mediator;
                _providersFactory = providersFactory;
                _providerEventService = providerEventService;
                _logger = logger;
            }

            public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var providerId = request.ChannelMessage.Request.ProviderId;

                var restApiProvider = _providersFactory.GetRestApiProvider(providerId);

                var channelRequest = request.ChannelMessage.Request;

                _logger.LogInformation("Handling {url} {statusCode}", request.ChannelMessage.Request.Data.Url, request.StatusCode);

                var eventsResult = restApiProvider.HandleResponseAndGetEvents(request.Body, request.Headers, request.StatusCode, request.ChannelMessage);
                if (eventsResult.IsFailure)
                {
                    _logger.LogError(eventsResult.Error);

                    await _mediator.Send(new UpdateChannelRequestCommand.Contract(channelRequest)
                    {
                        Status = ChannelRequestStatus.Failed,
                        Error = eventsResult.Error,
                        Response = request.Body
                    });

                    return Result.Failure(eventsResult.Error);
                }

                await _mediator.Send(new UpdateChannelRequestCommand.Contract(channelRequest)
                {
                    Status = ChannelRequestStatus.Success,
                    Response = null
                });

                await _providerEventService.SendCommandEvents(eventsResult.Value, cancellationToken);

                return Result.Success();
            }
        }

