public class CampeonatoCanalProvider : TransmissaoProvider, IFakeProvider
    {
        public static new Guid Id => typeof(ManualProvider).Name.ToGuid();

        public override List<CanalOperadora> GetCanaisPartida(PartidaAgregada partida, List<CanalProgramas> canais)
        {
            return new List<CanalOperadora>();
        }

        public override List<ChannelRequest> GetChannelRequests(DateTime referenceDate)
        {
            var requests = new List<ChannelRequest>();

            for (int i = 0; i < 5; i++)
            {
                var date = referenceDate.AddDays(i);
                var stopDate = date.AddHours(24);

                var model = GetModelForDate(date);

                var req = new ChannelRequest(
                    this,
                    model,
                    ProviderMessageType.Transmissao,
                    ChannelData.Empty(),
                    stopDate,
                    TimeSpan.FromHours(6));

                requests.Add(req);
            }

            return requests;
        }

        public List<ProviderEvent> GetProviderEvents(ChannelRequest request)
        {
            var date = GetDateForModel(request.Model);
            var @event = new ProgramacaoOperadoraObtidaEvent(Id, date.Value, OperadoraEnum.Fake)
            {
                Programacao = new List<CanalProgramas>()
            };

            return new List<ProviderEvent> { @event };
        }
    }

