// Class: ProvidersFactory
using MediatR;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Channels;
using RealtimeMatches.Application.Providers.Globoesporte;
using RealtimeMatches.Application.Providers.Sources.RapidApiFootball;
using RealtimeMatches.Application.Requests.Queries;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Entities.Providers;

public async Task<List<ChannelRequest>> RunProvidersRequests(CancellationToken stoppingToken)
        {
            using var scope = _scopeFactory.CreateScope();
            var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

            var referenceDate = DateTime.UtcNow.AddHours(-3);

            var recurringRequests = await mediator.Send(new GetRecurringRequests.Contract { ReferenceDate = referenceDate }, stoppingToken);
            var providerRequests = Providers.SelectMany(x => x.Value.GetChannelRequests(referenceDate));

            foreach (var request in providerRequests)
            {
                if (!recurringRequests.Any(x => x.ProviderId == request.ProviderId && x.Model == request.Model))
                    recurringRequests.Add(request);
            }

            foreach (var request in recurringRequests)
            {
                try
                {
                    var providerRequest = providerRequests.FirstOrDefault(x => x.ProviderId == request.ProviderId && x.Model == request.Model);
                    if (providerRequest != null)
                    {
                        var updatedRequestResult = await mediator.Send(new AddOrGetUpdatedRequest.Contract(request));
                        if (updatedRequestResult.IsFailure)
                        {
                            _logger.LogError($"Erro ao buscar request atualizado. Provider {request.ProviderId}. Model: {request.Model}");
                            continue;
                        }

                        providerRequest = updatedRequestResult.Value;
                        if (providerRequest.CanRun())
                        {
                            var publishResult = await _channelPublish.Publish(request);
                            if (publishResult.IsFailure)
                            {
                                _logger.LogError($"Erro ao executar request pro channel. Provider {request.ProviderId}");
                            }
                        }
                    }
                    else
                    {
                        if (request.CanRun())
                        {
                            var publishResult = await _channelPublish.Publish(request);
                            if (publishResult.IsFailure)
                            {
                                _logger.LogError($"Erro ao executar request pro channel. Provider {request.ProviderId}");
                            }
                        }
                    }
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Erro ao processar request providerId: {providerId}, model: {model}", request.ProviderId, request.Model);
                    continue;
                }
            }

            return recurringRequests;
        }

