using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using System;
using System.Threading;
using System.Threading.Tasks;

public class ExibirVideoCommand
{
    public class Contract : IRequest<Result>
    {
        public Guid VideoId { get; set; }
    }

    public class Handler : IRequestHandler<Contract, Result>
    {
        private readonly IApplicationContext _applicationContext;
        private readonly VideoCacheService _videoCacheService;

        public Handler(
            IApplicationContext applicationContext,
            VideoCacheService videoCacheService)
        {
            _applicationContext = applicationContext;
            _videoCacheService = videoCacheService;
        }

        public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
        {
            var video = await _applicationContext.Videos.FirstOrDefaultAsync(v => v.Id == request.VideoId);
            if (video == null)
                return Result.Failure("Video nao encontrado.");

            video.DeletedAt = null;
            video.Exibir = true;

            await _applicationContext.SaveChangesAsync();

            var videoCache = new VideoCache(
                video.Id,
                video.Titulo,
                video.VideoId,
                video.Thumbnail,
                video.Descricao,
                video.CanalId,
                video.CanalNome,
                video.Url,
                video.PublishedAt);

            await _videoCacheService.SaveVideo(videoCache);

            return Result.Success();
        }
    }
}

