using CSharpFunctionalExtensions;
using MediatR;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class GetCachedVideos
    {
        public class Contract : IRequest<Result<List<VideoCache>>>
        {
            public DateTime InitialDate { get; set; }
            public DateTime? UntilDate { get; set; }
        }

        public class Handler : IRequestHandler<Contract, Result<List<VideoCache>>>
        {
            private readonly VideoCacheService _videoCacheService;

            public Handler(
                VideoCacheService videoCacheService)
            {
                _videoCacheService = videoCacheService;
            }

            public async Task<Result<List<VideoCache>>> Handle(Contract request, CancellationToken cancellationToken)
            {
                if (request.InitialDate == DateTime.MinValue)
                    return Result.Failure<List<VideoCache>>("Data obrigatoria.");

                var videos = new List<VideoCache>();

                for (DateTime i = DateTime.UtcNow; videos.Count < 40; i = i.AddDays(-1))
                {
                    var cache = await _videoCacheService.GetVideos(i);
                    if (cache != null)
                        videos.AddRange(cache);
                }

                videos = videos.OrderByDescending(v => v.PublishedAt).Take(40).ToList();

                return Result.Success(videos);
            }
        }
    }

