using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Enums;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class Handler : IRequestHandler<Contract, Time>
        {
            private readonly IApplicationContext _context;
            private readonly ICacheService _cacheService;

            public Handler(
                IApplicationContext context,
                ICacheService cacheService)
            {
                _context = context;
                _cacheService = cacheService;
            }

            public async Task<Time> Handle(Contract request, CancellationToken cancellationToken)
            {
                var timeId = request.Nome.ToGuid();
                var time = await _context
                    .Times
                    .FirstOrDefaultAsync(t => t.Id == timeId);

                if (time == null)
                {
                    var times = await _cacheService.GetObjectAsync<List<TimeQueryCache>>("TimeQueryCache");
                    if (times == null)
                    {
                        times = await _context
                            .Times
                            .Where(t => t.NomesPossiveis != null)
                            .Select(t => new TimeQueryCache(

                                t.Id,
                                t.NomesPossiveis,
                                t.Nome,
                                t.Importancia
                            ))
                            .ToListAsync(cancellationToken);

                        await _cacheService.SetObjectAsync("TimeQueryCache", times, TimeSpan.FromMinutes(5));
                    }

                    var timeQuery = times.FirstOrDefault(x => x.NomesPossiveis.Any(n => n.Contains(request.Nome, StringComparison.OrdinalIgnoreCase)));
                    if (timeQuery == null)
                        return null;

                    timeId = timeQuery.Id;

                    time = await _context
                        .Times
                        .FirstOrDefaultAsync(t => t.Id == timeId);
                }

                return time;
            }
        }

