using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Events.Temporadas;
using RealtimeMatches.Domain.Projections.Profissionais;
using RealtimeMatches.Domain.Projections.Temporadas;
using System.Collections.Generic;
using System.Linq;
using System.Threading;

public async Task Handle(JogadoresParticipanteAdicionado notification, CancellationToken cancellationToken)
    {
        var locker = await _readModel.AcquireLockAsync();

        var temporada = await _temporadaRepository.GetTemporadaById(notification.TemporadaId);
        var time = await _timeRepository.GetAsync(notification.TimeId);

        var projection = _mapper.Map<ParticipanteProjection>(time);
        projection.TemporadaId = notification.TemporadaId;

        projection.SetParentChildKeys(notification.TemporadaId.ToString(), time.Id.ToString());

        projection.Jogadores = new List<JogadorParticipanteProjection>();

        var participante = temporada.GetParticipante(notification.TimeId);

        var jogadores = await _profissionalRepository.GetJogadoresAsync(participante.Jogadores.Select(x => x.JogadorId));

        foreach (var jogador in jogadores)
        {
            var jogadorProjection = _mapper.Map<JogadorParticipanteProjection>(jogador);
            jogadorProjection.TimeSecundario = participante.Jogadores.First(x => x.JogadorId == jogador.Id)?.TimeSecundario;

            projection.Jogadores.Add(jogadorProjection);
        }

        await _readModel.SaveAsync(locker, projection);

        await _readModel.ReleaseLockAsync(locker);
    }

