public class TemporadaEventHandler :
    INotificationHandler<TemporadaCriada>,
    INotificationHandler<RodadaAdicionada>,
    INotificationHandler<PalcoTemporadaAdicionado>
{
    private readonly ICampeonatoRepository _campeonatoRepository;
    private readonly ITemporadaRepository _temporadaRepository;
    private readonly IReadModelRepository<TemporadaProjection> _readModelRepository;
    private readonly IMapper _mapper;

    public TemporadaEventHandler(
        ICampeonatoRepository campeonatoRepository,
        ITemporadaRepository temporadaRepository,
        IReadModelRepository<TemporadaProjection> readModelRepository,
        IMapper mapper)
    {
        _campeonatoRepository = campeonatoRepository;
        _temporadaRepository = temporadaRepository;
        _readModelRepository = readModelRepository;
        _mapper = mapper;
    }

    public Task Handle(TemporadaCriada notification, CancellationToken cancellationToken)
        => UpdateProjection(notification.TemporadaId);

    public Task Handle(RodadaAdicionada notification, CancellationToken cancellationToken)
        => UpdateProjection(notification.TemporadaId);

    public Task Handle(PalcoTemporadaAdicionado notification, CancellationToken cancellationToken)
        => UpdateProjection(notification.TemporadaId);

    private async Task UpdateProjection(Guid temporadaId)
    {
        var locker = await _readModelRepository.AcquireLockAsync();

        var temporada = await GetTemporadaAsync(temporadaId);

        var campeonatoSlug = await _campeonatoRepository.GetCampeonatoSlugAsync(temporada.CampeonatoId);

        var projection = _mapper.Map<TemporadaProjection>(temporada);
        projection.CampeonatoSlug = campeonatoSlug;

        await _readModelRepository.SaveAsync(locker, projection);

        await _readModelRepository.ReleaseLockAsync(locker);
    }

    private async Task<Temporada> GetTemporadaAsync(Guid id)
        => await _temporadaRepository.Temporadas.AsNoTracking().Include(x => x.Rodadas).FirstOrDefaultAsync(x => x.Id == id);
}

