            var visitanteTimeId = partida.Visitante.TimeId.Value;

            if (temporada.ExistsParticipante(visitanteTimeId) is false)
            {
                var adicionarParticipanteVisitante = new AdicionarParticipante(temporada.Id, visitanteTimeId);

                await _commandBus.Send(adicionarParticipanteVisitante);
            }
        }
    }

