        var temporadas = await _temporadaRepository
            .Temporadas
            .Include(x => x.Participantes)
            .Where(x => x.Participantes != null && x.Participantes.Any(x => x.TimeId == notification.TimeId))
            .ToListAsync(cancellationToken);

        foreach (var temporada in temporadas)
        {
            var participante = temporada.Participantes.First(x => x.TimeId == notification.TimeId);

            await _eventBus.Publish(new ParticipanteEscudoAtualizado(temporada.Id, participante.TimeId)
