public async Task Handle(RegulamentoFaseGrupoAlterado notification, CancellationToken cancellationToken)
    {
        if (notification.ProximaFase == FaseTipo.Grupos)
        {
            return;
        }

        var tabela = await _tabelaRepository.GetTabelaById(notification.TabelaId);
        var temporada = await _temporadaRepository.GetTemporadaById(tabela.TemporadaId);

        var fase = notification.ProximaFase;

        var matamataChave = fase switch
        {
            FaseTipo.Oitavas => MataMataChave.OitavasDeFinal,
            FaseTipo.Quartas => MataMataChave.QuartasDeFinal,
            FaseTipo.Semifinal => MataMataChave.Semifinal,
            FaseTipo.Final => MataMataChave.Final,
            _ => throw new ArgumentException()
        };

        await _commandBus.Send(new CreateRodadasFaseAteFinal(temporada.Id, matamataChave) { Disputa3Lugar = true });
    }

