public async Task<Unit> Handle(CreateRodadasFaseAteFinal request, CancellationToken cancellationToken)
    {
        var temporada = await _repository.GetTemporadaById(request.AggregateId.Value);

        for (int i = (int)request.FaseInicial; i >= 0; i--)
        {
            var mataMata = (MataMataChave)i;

            if (mataMata == MataMataChave.Disputa3Lugar && request.Disputa3Lugar == false)
            {
                continue;
            }

            if (!temporada.Rodadas.Any(x => x.MataMata == mataMata))
            {
                temporada.AdicionarRodada(Rodada.CreateFase(temporada.Id, mataMata));
            }
        }

        await _repository.SaveChangesAsync();

        return Unit.Value;
    }

