// Namespace: RealtimeMatches.Application.Campeonatos.Commands.CreateTemporada
using FluentValidation;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Repositories;

public class CreateTemporadaValidator : AbstractValidator<CreateTemporada>
{
    public CreateTemporadaValidator(
        ICampeonatoRepository campeonatoRepository,
        ITemporadaRepository temporadaRepository)
    {
        RuleFor(x => x.Ano).NotEmpty().MinimumLength(4);
        RuleFor(x => x.Ano).Must(x => !x.Contains('\\') && !x.Contains('/'));

        RuleFor(x => x.CampeonatoId)
            .MustAsync(async (campeonatoId, cancellation) =>
            {
                var exists = await campeonatoRepository.Campeonatos.AnyAsync(x => x.Id == campeonatoId);
                return exists is true;
            });

        RuleFor(x => x)
            .MustAsync(async (command, cancellation) =>
                !await temporadaRepository.Temporadas.AnyAsync(x => x.Nome == command.Ano && x.CampeonatoId == command.CampeonatoId));
    }
}

