// Namespace: RealtimeMatches.Application.Tabelas.EventHandlers
// Class: TabelaEventsHandler
using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using RealtimeMatches.Domain.Events.Tabelas;
using RealtimeMatches.Domain.Projections.Tabelas;
using System;
using System.Linq;

private async Task UpdateProjection(Guid tabelaId)
    {
        var locker = await _readModel.AcquireLockAsync();

        var tabela = await _repository.GetTabelaById(tabelaId);

        var tabelaProjection = _mapper.Map<TabelaProjection>(tabela);

        await _readModel.SaveAsync(locker, tabelaProjection);

        await _readModel.ReleaseLockAsync(locker);

        var tabelaFases = tabela as TabelaFases;

        foreach (var fase in tabelaFases.Fases.OrderBy(x => x.Ordem))
        {
            locker = await _faseRepository.AcquireLockAsync();

            var faseProjection = _mapper.Map<FaseProjection>(fase);

            if (fase is FaseGrupos)
            {
                foreach (var grupo in faseProjection.Grupos)
                {
                    grupo.Classificacao = grupo
                        .Classificacao
                        .OrderByDescending(x => x.Pontos)
                            .ThenByDescending(x => x.SaldoGols)
                                .ThenByDescending(x => x.GolsPro)
                        .ToList();

                    for (int i = 1; i <= grupo.Classificacao.Count; i++)
                    {
                        grupo.Classificacao[i - 1].Posicao = i;
                    }
                }
            }

            await _faseRepository.SaveAsync(locker, faseProjection);

            await _faseRepository.ReleaseLockAsync(locker);
        }
    }

