using RealtimeMatches.Domain.Events.Tabelas;
using RealtimeMatches.Domain.Projections.Tabelas;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class TabelaTopScorersEventHandler : INotificationHandler<TopScorersAtualizado>
{
	private readonly IMapper _mapper;
	private readonly ITabelaRepository _tabelaRepository;
	private readonly ITimeRepository _timeRepository;
	private readonly IReadModelRepository<TabelaTopScorersProjection> _readModel;

	public TabelaTopScorersEventHandler(
		IMapper mapper,
		ITabelaRepository tabelaRepository,
		ITimeRepository timeRepository,
		IReadModelRepository<TabelaTopScorersProjection> readModel)
	{
		_mapper = mapper;
		_tabelaRepository = tabelaRepository;
		_timeRepository = timeRepository;
		_readModel = readModel;
	}

	public async Task Handle(TopScorersAtualizado notification, CancellationToken cancellationToken)
	{
		var locker = await _readModel.AcquireLockAsync();

		var tabela = await _tabelaRepository.GetTabelaTopScorersById(notification.TabelaId);

		var projection = _mapper.Map<TabelaTopScorersProjection>(tabela);

        var times = await _timeRepository.GetTimesAsync(tabela.TopScorers.Select(x => x.TimeId).Distinct());

		foreach (var jogador in projection.TopScorers)
		{
			var time = times.First(x => x.Id == jogador.TimeId);

			jogador.TimeNome = time.Nome;
			jogador.TimeEscudo = time.Escudo;
		}

		await _readModel.SaveAsync(locker, projection);

		await _readModel.ReleaseLockAsync(locker);
	}
}

