// Namespace: RealtimeMatches.Application.Tabelas.Factories
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.MataMataFases;
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;
using RealtimeMatches.Domain.Enums.Tabelas;
using RealtimeMatches.Domain.Extensions;
using System;
using System.Linq;

public class TabelaFaseFactory : ITabelaFaseFactory
{
    public Fase CreateFase(TabelaFases tabela, Temporada temporada, FaseTipo tipo)
    {
        return tipo switch
        {
            FaseTipo.Grupos => CreateFaseGrupos(tabela.Id, temporada),
            _ => CreateFaseMataMata(tabela, tipo),
        };
    }

    private FaseMataMata CreateFaseMataMata(TabelaFases tabela, FaseTipo fase)
    {
        var faseMataMata = new FaseMataMata(tabela.Id, fase.ToMataMataChave());

        return faseMataMata;
    }

    private FaseGrupos CreateFaseGrupos(Guid tabelaId, Temporada temporada)
    {
        var rodadaGrupos = temporada
            .Rodadas
            .Where(x => x.IsGrupo)
            .GroupBy(x => x.Grupo);

        var faseGrupos = new FaseGrupos(tabelaId);

        foreach (var rodadaGrupo in rodadaGrupos)
        {
            var grupoNome = Enum.Parse<GrupoNome>(rodadaGrupo.Key);

            foreach (var rodada in rodadaGrupo)
            {
                var times = rodada.Times.Select(x => x.TimeId);
                faseGrupos.AdicionarGrupo(grupoNome, times);
            }
        }

        return faseGrupos;
    }
}

