using MediatR;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Partidas.Commands.AgendarPartida;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.MataMataFases;
using RealtimeMatches.Domain.Enums;
