public async Task Handle(RegulamentoFaseMataMataAlterado notification, CancellationToken cancellationToken)
    {
        var tabela = await _repository.GetTabelaById(notification.TabelaId);
        if (tabela is not TabelaFases)
        {
            return;
        }

        var tabelaFases = tabela as TabelaFases;

        var faseMataMata = tabelaFases.GetFaseMataMata(notification.Regulamento.FaseMataMataId);

        var qtdJogos = faseMataMata.Chave switch
        {
            MataMataChave.OitavasDeFinal => 8,
            MataMataChave.QuartasDeFinal => 4,
            MataMataChave.Semifinal => 2,
            MataMataChave.Disputa3Lugar => 1,
            MataMataChave.Final => 1,
            _ => throw new ArgumentOutOfRangeException()
        };

        if (faseMataMata.Partidas.Count == qtdJogos)
        {
            return;
        }

        var rodada = await _temporadaRepository.FindRodada(tabela.TemporadaId, null, null, faseMataMata.Chave, false);
        var chave = faseMataMata.Chave;

        var partidas = new List<PartidaFaseMataMata>();
        for (int i = 0; i < qtdJogos; i++)
        {
            var chaveId = i + 1;

            if (faseMataMata.Regulamento.JogoUnico == false)
            {
                throw new NotImplementedException("Criacao de duas partidas nao implementada.");
            }

            var partidaAgendada = await _bus.Send(new AgendarPartida(rodada.Id));

            var chaveNome = chave.FriendlyName();
            if (faseMataMata.Chave != MataMataChave.Final && faseMataMata.Chave != MataMataChave.Disputa3Lugar)
            {
                chaveNome = $"{chave.FriendlyName()} {chaveId}";
            }

            partidas.Add(new(faseMataMata.Id, partidaAgendada, TipoPartidaMataMata.Unico, chaveId, chaveNome));
        }

        tabelaFases.AgendarPartidasMataMata(partidas);

        await _repository.SaveChangesAsync(cancellationToken);
    }

