public class TabelaFaseGrupoSagaHandler :
    INotificationHandler<PlacarAtualizado>,
    INotificationHandler<PartidaEncerrada>,
    INotificationHandler<PartidaIniciada>
{
    private readonly ITemporadaRepository _temporadaRepository;
    private readonly IPartidaRepository _partidaRepository;
    private readonly ITabelaRepository _tabelaRepository;
    private readonly ITabelaGrupoGenerator _tabelaGrupoGenerator;
    private readonly ICommandBus _bus;

    public TabelaFaseGrupoSagaHandler(
        ITemporadaRepository temporadaRepository,
        IPartidaRepository partidaRepository,
        ITabelaRepository tabelaRepository,
        ITabelaGrupoGenerator tabelaGrupoGenerator,
        ICommandBus bus)
    {
        _temporadaRepository = temporadaRepository;
        _partidaRepository = partidaRepository;
        _tabelaRepository = tabelaRepository;
        _tabelaGrupoGenerator = tabelaGrupoGenerator;
        _bus = bus;
    }

    public Task Handle(PlacarAtualizado notification, CancellationToken cancellationToken)
        => AtualizarTabelaGrupoPartida(notification.PartidaId);

    public Task Handle(PartidaEncerrada notification, CancellationToken cancellationToken)
        => AtualizarTabelaGrupoPartida(notification.PartidaId);

    public Task Handle(PartidaIniciada notification, CancellationToken cancellationToken)
        => AtualizarTabelaGrupoPartida(notification.PartidaId);

    private async Task AtualizarTabelaGrupoPartida(Guid partidaId)
    {
        var rodadaId = await _partidaRepository.GetRodadaPartida(partidaId);
        var rodada = await _temporadaRepository.GetRodadaById(rodadaId);
        if (!rodada.IsGrupo)
        {
            return;
        }

        var tabelaId = await _tabelaRepository.GetTabelaIdByTemporadaId(rodada.TemporadaId);

        var partidasRodada = await _partidaRepository.GetPartidasRodada(rodadaId);

        var classificacaoGenerated = _tabelaGrupoGenerator.GenerateGrupoClassificacao(rodada.GrupoNome.Value, partidasRodada);

        var atualizarTabelaGrupo = new AtualizarTabelaGrupo(tabelaId)
        {
            Classificacao = classificacaoGenerated,
        };

        await _bus.Send(atualizarTabelaGrupo);
    }
}

