using RealtimeMatches.Domain.Events.Partidas;
using System;
using System.Linq;

public class TabelaTimesClassificadosSagaHandler : INotificationHandler<PartidaEncerrada>
{
    private readonly IPartidaRepository _partidaRepository;
    private readonly ITemporadaRepository _temporadaRepository;
    private readonly ITabelaRepository _tabelaRepository;
    private readonly ITabelaMataMataManager _tabelaMataMataManager;
    private readonly ICommandBus _bus;

    public TabelaTimesClassificadosSagaHandler(
        IPartidaRepository partidaRepository,
        ITemporadaRepository temporadaRepository,
        ITabelaRepository tabelaRepository,
        ITabelaMataMataManager tabelaMataMataManager,
        ICommandBus bus)
    {
        _partidaRepository = partidaRepository;
        _temporadaRepository = temporadaRepository;
        _tabelaRepository = tabelaRepository;
        _tabelaMataMataManager = tabelaMataMataManager;
        _bus = bus;
    }

    public async Task Handle(PartidaEncerrada notification, CancellationToken cancellationToken)
    {
        var rodadaId = await _partidaRepository.GetRodadaPartida(notification.PartidaId);
        var rodada = await _temporadaRepository.GetRodadaById(rodadaId);

        if (rodada.Tipo != RodadaTipo.MataMata)
        {
            return;
        }

        var tabelaFases = await _tabelaRepository.GetTabelaByTemporadaId(rodada.TemporadaId) as TabelaFases;
        var fase = tabelaFases.GetFasesMataMata().FirstOrDefault(x => x.Chave == rodada.MataMata);

        var classificados = await _tabelaMataMataManager.ComputarClassificadosProximaFase(fase);

        foreach (var classificadosChave in classificados.GroupBy(x => x.Chave))
        {
            var proximaFase = tabelaFases.GetFasesMataMata().FirstOrDefault(x => x.Chave == classificadosChave.Key);
            var partidasProximaFase = proximaFase.Partidas;

            foreach (var classificado in classificadosChave)
            {
                if (!classificado.Mandante.HasValue && !classificado.Visitante.HasValue)
                {
                    continue;
                }

                var partidaProximaFase = proximaFase.Partidas.First(x => x.ChaveId == classificado.ChaveId);

                await _bus.Send(new DefinirEquipes(partidaProximaFase.PartidaId)
                {
                    MandanteTimeId = classificado.Mandante,
                    VisitanteTimeId = classificado.Visitante,
                });
            }
        }
    }
}

