using RealtimeMatches.Application.Tabelas.Dtos;
using RealtimeMatches.Domain.Entities.Aggregates.Partidas;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using RealtimeMatches.Domain.Enums.Partidas;
using System;
using System.Collections.Generic;
using System.Linq;

public List<GrupoTimeClassificacaoDto> GenerateGrupoClassificacao(GrupoNome grupo, List<Partida> partidas)
    {
        var partidasIniciadasOuEncerradas = partidas
            .Where(x => x.Situacao.Status == SituacaoStatus.AoVivo || x.Situacao.Status == SituacaoStatus.Encerrada)
            .ToList();

        var classificacao = new Dictionary<Guid, GrupoTimeClassificacaoDto>();

        foreach (var partida in partidasIniciadasOuEncerradas)
        {
            var mandante = partida.Mandante.TimeId.Value;
            var visitante = partida.Visitante.TimeId.Value;

            if (!classificacao.ContainsKey(mandante))
            {
                classificacao[mandante] = new GrupoTimeClassificacaoDto(grupo, mandante);
            }

            if (!classificacao.ContainsKey(visitante))
            {
                classificacao[visitante] = new GrupoTimeClassificacaoDto(grupo, visitante);
            }

            classificacao[mandante].Jogos++;
            classificacao[visitante].Jogos++;

            if (partida.Situacao.Status == SituacaoStatus.AoVivo)
            {
                classificacao[mandante].PartidaEmAndamento = true;
                classificacao[visitante].PartidaEmAndamento = true;
            }

            if (partida.Placar == null)
            {
                classificacao[mandante].Empates++;
                classificacao[visitante].Empates++;
            }
            else
            {
                switch (partida.Placar.Vencedor)
                {
                    case Vencedor.Empate:
                        classificacao[mandante].Empates++;
                        classificacao[visitante].Empates++;
                        break;
                    case Vencedor.Mandante:
                        classificacao[mandante].Vitorias++;
                        classificacao[visitante].Derrotas++;
                        break;
                    case Vencedor.Visitante:
                        classificacao[mandante].Derrotas++;
                        classificacao[visitante].Vitorias++;
                        break;
                    default:
                        break;
                }

                classificacao[mandante].GolsPro += partida.Placar.Mandante;
                classificacao[mandante].GolsContra += partida.Placar.Visitante;

                classificacao[visitante].GolsPro += partida.Placar.Visitante;
                classificacao[visitante].GolsContra += partida.Placar.Mandante;
            }
        }

        return classificacao.Select(x => x.Value).ToList();
    }

