using System.Linq;
using System.Threading.Tasks;

public async Task<List<ClassificadoChaveDto>> ComputarClassificadosProximaFase(FaseMataMata faseMataMata)
    {
        if (faseMataMata.Regulamento == null)
        {
            throw new InvalidOperationException("Cannot compute if hasn't a regulamento.");
        }

        if (faseMataMata.Regulamento.JogoUnico == false)
        {
            throw new NotImplementedException("Compute of JogoIdaVolta not implemented.");
        }

        faseMataMata.Partidas = faseMataMata.Partidas.OrderBy(x => x.ChaveId).ToList();

        var resultados = await _partidaRepository.GetPartidaResultados(faseMataMata.Partidas.Select(x => x.PartidaId));

        var classificados = new List<ClassificadoChaveDto>();

        for (int i = 0; i < faseMataMata.Partidas.Count; i += 2)
        {
            var partida1 = faseMataMata.Partidas[i];
            var partida2 = faseMataMata.Partidas[i + 1];

            var partida1Resultado = resultados.First(x => x.Id == partida1.PartidaId);
            var partida2Resultado = resultados.First(x => x.Id == partida2.PartidaId);

            var vencedor1 = partida1Resultado.Encerrada ? partida1Resultado.VencedorId : null;
            var vencedor2 = partida2Resultado.Encerrada ? partida2Resultado.VencedorId : null;

            if (faseMataMata.Chave == Domain.Enums.MataMataChave.Semifinal)
            {
                classificados.Add(new ClassificadoChaveDto
                {
                    Chave = Domain.Enums.MataMataChave.Final,
                    ChaveId = 1,
                    Partida1Id = partida1.PartidaId,
                    Partida2Id = partida2.PartidaId,
                    Mandante = vencedor1,
                    Visitante = vencedor2,
                    PartidasEncerradas = partida1Resultado.Encerrada && partida2Resultado.Encerrada
                });

                if (faseMataMata.Regulamento.TemDisputa3Lugar)
                {
                    classificados.Add(new ClassificadoChaveDto
                    {
                        Chave = Domain.Enums.MataMataChave.Disputa3Lugar,
                        ChaveId = 1,
                        Partida1Id = partida1.PartidaId,
                        Partida2Id = partida2.PartidaId,
                        Mandante = partida1Resultado.PerdedorId,
                        Visitante = partida2Resultado.PerdedorId,
                        PartidasEncerradas = partida1Resultado.Encerrada && partida2Resultado.Encerrada
                    });
                }
            }
            else
            {
                classificados.Add(new ClassificadoChaveDto
                {
                    Chave = faseMataMata.ProximaChave,
                    ChaveId = classificados.Count + 1,
                    Partida1Id = partida1.PartidaId,
                    Partida2Id = partida2.PartidaId,
                    Mandante = vencedor1,
                    Visitante = vencedor2,
                    PartidasEncerradas = partida1Resultado.Encerrada && partida2Resultado.Encerrada
                });
            }
        }

        return classificados;
    }

