// Namespace: RealtimeMatches.Application.Tabelas.Services
using RealtimeMatches.Application.Tabelas.Dtos;
using RealtimeMatches.Domain.Enums.Partidas;
using RealtimeMatches.Domain.ValueObjects.Partidas;
using System.Collections.Generic;
using System.Linq;

public class TabelaTopScorersGenerator : ITabelaTopScorersGenerator
{
    public List<TopScorerDto> Generate(List<Lance> lances)
    {
        var topScorers = new List<TopScorerDto>();

        var lancesFiltered = lances.Where(x => x.JogadorPrincipal != null && x.JogadorPrincipal.JogadorId.HasValue);

        foreach (var jogadorLances in lancesFiltered.GroupBy(x => x.JogadorPrincipal.JogadorId))
        {
            var jogador = jogadorLances.Last().JogadorPrincipal;

            var gols = jogadorLances.Where(x => x.Tipo == TipoLance.Gol).Count();
            var amarelos = jogadorLances.Where(x => x.Tipo == TipoLance.CartaoAmarelo).Count();
            var vermelhos = jogadorLances.Where(x => x.Tipo == TipoLance.CartaoVermelho).Count();

            var assistencias = lancesFiltered.Where(x => x.Tipo == TipoLance.Gol && x.JogadorSecundario != null && x.JogadorSecundario.JogadorId == jogador.JogadorId).Count();

            if (gols + assistencias == 0)
            {
                continue;
            }

            var topScorer = new TopScorerDto
            {
                JogadorId = jogadorLances.Key.Value,
                Scout = new Scout
                {
                    Gols = gols,
                    Assistencias = assistencias,
                    CartoesAmarelo = amarelos,
                    CartoesVermelho = vermelhos
                }
            };

            topScorers.Add(topScorer);
        }

        var topScorersOrdered = topScorers
            .OrderByDescending(x => x.Scout.Gols)
                .ThenByDescending(x => x.Scout.Assistencias)
                    .ThenBy(x => x.Scout.CartoesVermelho)
                        .ThenBy(x => x.Scout.CartoesAmarelo);

        return topScorersOrdered.ToList();
    }
}

