using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using System.Threading;
using System.Threading.Tasks;

public class AtualizarRegulamentoFaseGruposHandler : IRequestHandler<AtualizarRegulamentoFaseGruposIntercalado>
{
    private readonly ITabelaRepository _repository;

    public AtualizarRegulamentoFaseGruposHandler(
        ITabelaRepository repository)
    {
        _repository = repository;
    }

    public async Task<Unit> Handle(AtualizarRegulamentoFaseGruposIntercalado request, CancellationToken cancellationToken)
    {
        var tabela = await _repository.GetTabelaById(request.TabelaId) as TabelaFases;

        var faseGrupo = tabela.GetFaseGrupos(request.FaseGrupoId);

        var regulamento = new RegulamentoFaseGrupos(faseGrupo.Id, request.ProximaFase);

        var chaves = (int)request.ProximaFase;

        var grupo1Id = 0;
        var grupo2Id = 1;

        // ToDo: Mover pra uma factory
        for (int i = 0; i < chaves; i++)
        {
            RegulamentoGrupoTimeClassificado chave1;
            RegulamentoGrupoTimeClassificado chave2;

            if (i == chaves / 2)
            {
                grupo1Id = 1;
                grupo2Id = 0;
            }

            var grupo1 = (GrupoNome)grupo1Id;
            var grupo2 = (GrupoNome)grupo2Id;

            chave1 = new RegulamentoGrupoTimeClassificado { Grupo = grupo1, Posicao = 1 };
            chave2 = new RegulamentoGrupoTimeClassificado { Grupo = grupo2, Posicao = 2 };

            grupo1Id += 2;
            grupo2Id += 2;

            regulamento.AdicionarRegulamentoClassificados(chave1, chave2);
        }

        tabela.AlterarRegulamento(regulamento);

        await _repository.SaveChangesAsync(cancellationToken);

        return Unit.Value;
    }
}

