using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class AtualizarTopScorersHandler : IRequestHandler<AtualizarTopScorers>
{
    private readonly ITabelaRepository _repository;
    private readonly IProfissionalRepository _profissionalRepository;
    private readonly ITemporadaRepository _temporadaRepository;

    public AtualizarTopScorersHandler(
        ITabelaRepository repository,
        IProfissionalRepository profissionalRepository,
        ITemporadaRepository temporadaRepository)
    {
        _repository = repository;
        _profissionalRepository = profissionalRepository;
        _temporadaRepository = temporadaRepository;
    }

    public async Task<Unit> Handle(AtualizarTopScorers request, CancellationToken cancellationToken)
    {
        var tabela = await _repository.GetTabelaTopScorersById(request.TemporadaId);
        if (tabela == null)
        {
            tabela = new TabelaTopScorers(request.TemporadaId);
            _repository.TabelaTopScorers.Add(tabela);
        }

        var temporada = await _temporadaRepository.GetTemporadaById(request.TemporadaId);

        var jogadores = await _profissionalRepository.GetJogadoresAsync(request.TopScorers.Select(x => x.JogadorId));

        var topScores = new List<TopScorer>();

        foreach (var jogador in jogadores)
        {
            var dto = request.TopScorers.First(x => x.JogadorId == jogador.Id);

            var participante = temporada.Participantes.First(x => x.ContainsJogador(jogador.Id));

            topScores.Add(new TopScorer
            {
                JogadorId = jogador.Id,
                Pessoa = new Domain.ValueObjects.Pessoa { Nome = jogador.Apelido, Foto = jogador.Foto },
                Scout = dto.Scout,
                TemporadaId = tabela.TemporadaId,
                TimeId = participante.TimeId,
                Posicao = jogador.Posicao
            });
        }

        tabela.AtualizarTopScorers(topScores);

        await _repository.SaveChangesAsync();

        return Unit.Value;
    }
}

