using RealtimeMatches.Application.Tabelas.Factories;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using System;
using System.Threading;
using System.Threading.Tasks;

public class CriarTabelasHandler : IRequestHandler<CriarTabelaFases, Guid>
{
    private readonly ITabelaRepository _repository;
    private readonly ITemporadaRepository _temporadaRepository;
    private readonly ITabelaFaseFactory _tabelaFaseFactory;

    public CriarTabelasHandler(
        ITabelaRepository repository,
        ITemporadaRepository temporadaRepository,
        ITabelaFaseFactory tabelaFaseFactory)
    {
        _repository = repository;
        _temporadaRepository = temporadaRepository;
        _tabelaFaseFactory = tabelaFaseFactory;
    }

    public async Task<Guid> Handle(CriarTabelaFases request, CancellationToken cancellationToken)
    {
        var temporada = await _temporadaRepository.GetTemporadaById(request.TemporadaId);

        var tabelaFases = new TabelaFases(temporada.Id);

        foreach (var tipo in request.Fases)
        {
            var fase = _tabelaFaseFactory.CreateFase(tabelaFases, temporada, tipo);
            if (fase == null)
            {
                continue;
            }

            tabelaFases.AdicionarFase(fase);
        }

        _repository.Tabelas.Add(tabelaFases);
        await _repository.SaveChangesAsync(cancellationToken);

        return tabelaFases.Id;
    }
}

