using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Domain.Entities;
using System;
using System.Threading;
using System.Threading.Tasks;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var channelRequest = await _applicationContext
                    .ChannelRequests
                    .FirstOrDefaultAsync(x => x.ProviderId == request.ProviderId && x.Model == request.Model);

                try
                {
                    if (channelRequest == null)
                    {
                        channelRequest = request.ChannelRequest;
                        _applicationContext.ChannelRequests.Add(channelRequest);
                    }

                    channelRequest.Status = request.Status;

                    if (channelRequest.Status == ChannelRequestStatus.Running)
                        channelRequest.BeginRun = DateTime.UtcNow.AddHours(-3);

                    if (channelRequest.Status == ChannelRequestStatus.Success)
                    {
                        channelRequest.LastSuccessRun = DateTime.UtcNow.AddHours(-3);
                        channelRequest.Response = request.Response;
                        channelRequest.Error = null;
                    }

                    if (channelRequest.Status == ChannelRequestStatus.Failed)
                    {
                        channelRequest.Error = request.Error;
                        channelRequest.Response = request.Response;
                    }

                    if (channelRequest.Status == ChannelRequestStatus.Finished)
                    {
                        channelRequest.RequestUntilDate = DateTime.UtcNow.AddHours(-3);
                    }

                    await _applicationContext.SaveChangesAsync(cancellationToken);

                    return Result.Success();
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Erro ao atualizar ChannelRequest {model} {providerId}. Cobertura {coberturaId}", channelRequest.Model, channelRequest.ProviderId, channelRequest.CoberturaId);

                    return Result.Failure("Erro inesperado ao atualizar ChannelRequest. " + e.Message);
                }
