using RealtimeMatches.Domain.Application.Providers;
using System;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class RecreateRequestCommand
    {
        public class Contract : IRequest<Result>
        {
            public Guid ProviderId { get; set; }
            public DateTime Date { get; set; }

            public Contract(Guid providerId, DateTime date)
            {
                ProviderId = providerId;
                Date = date;
            }
        }

        public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IMediator _mediator;
            private readonly IApplicationContext _applicationContext;
            private readonly ProvidersFactory _providersFactory;

            public Handler(
                IMediator mediator,
                IApplicationContext applicationContext,
                ProvidersFactory providersFactory)
            {
                _mediator = mediator;
                _applicationContext = applicationContext;
                _providersFactory = providersFactory;
            }

            public async Task<Result> Handle(Contract contract, CancellationToken cancellationToken)
            {
                if (contract.Date == DateTime.MinValue)
                    return Result.Failure($"Data invalida");

                var provider = _providersFactory.Resolve(contract.ProviderId);

                var request = provider.GetChannelRequest(contract.Date);

                //provider = await _applicationContext.Providers.FirstOrDefaultAsync(x => x.Id == provider.Id);

                //request.SetProvider(provider);
                var requestDb = await _applicationContext.ChannelRequests.FirstOrDefaultAsync(x => x.ProviderId == provider.Id && x.Model == request.Model);
                if (requestDb == null)
                {
                    _applicationContext.ChannelRequests.Add(request);
                    await _applicationContext.SaveChangesAsync();
                }
                else
                {
                    var result = await _mediator.Send(new ReprocessarRequest.Contract(provider.Id, request.Model));
                }

                return Result.Success();
            }
        }
    }

