public Result<List<ProviderEvent>> HandleResponseAndGetEvents(string body, Dictionary<string, string> headers, int statusCode, ChannelMessage channelMessage)
        {
            if (channelMessage.Request.MessageType != ProviderMessageType.Transmissao)
                throw new NotImplementedException();

            if (statusCode != 200 && statusCode != 304)
                return Result.Failure<List<ProviderEvent>>("status code nao é 200: " + body);

            var request = channelMessage.Request;
            var response = JsonConvert.DeserializeObject<GloboplayResponse>(body);
            var dataProgramacao = GetDateForModel(request.Model);

            if (!dataProgramacao.HasValue)
                return Result.Failure<List<ProviderEvent>>("Invalid date for model.");

            var events = new List<ProviderEvent>();
            var canais = new List<CanalProgramas>();

            var programacao = response.Data.Broadcasts;
            foreach (var globoCanal in programacao)
            {
                var canal = new CanalProgramas(globoCanal.Channel.Slug, globoCanal.Channel.Logo, globoCanal.Channel.Id);

                foreach (var programa in globoCanal.EpgByDate.Entries)
                {
                    if (!programa.LiveBroadcast || string.IsNullOrEmpty(programa.Metadata))
                        continue;

                    var canalPrograma = new CanalPrograma(programa.Metadata, DateTime.MinValue, DateTime.MinValue);
                    canal.Programas.Add(canalPrograma);
                }

                if (canal.Programas.Count > 0)
                    canais.Add(canal);
            }

            if (canais.Count > 0)
            {
                var partidaEvent = new ProgramacaoOperadoraObtidaEvent(Id, dataProgramacao.Value, OperadoraEnum.Globoplay)
                {
                    Programacao = canais
                };

                events.Add(partidaEvent);
            }

            return events;
        }

