using RealtimeMatches.Application.Providers.Sources.RapidApiFootball.DTOs;
using RealtimeMatches.Domain.Entities;
using System.Collections.Generic;
using System.Linq;

private static Scouts GetPlayerScouts(Player player, List<EventFixtureDto> events)
        {
            var scout = new Scouts();

            var playerEvents = events.Where(x => x.Player.Id == player.Id || x.Player.Name.RemoveAccents() == player.Name.RemoveAccents());
            foreach (var playerEvent in playerEvents)
            {
                if (playerEvent.Type == "Goal") { 
                    
                    if (playerEvent.Detail == "Normal Goal" || playerEvent.Detail == "Penalty")
                        scout.Gol++;

                    if (playerEvent.Detail == "Own Goal")
                        scout.GolContra++;
                }

                if (playerEvent.Type == "Card")
                {
                    if (playerEvent.Detail == "Yellow Card")
                        scout.CartaoAmarelo++;

                    if (playerEvent.Detail == "Red Card")
                        scout.CartaoVermelho++;
                }
            }

            return scout;
        }

