using CSharpFunctionalExtensions;
using Newtonsoft.Json;
using RealtimeMatches.Application.Providers.Sources.Sky;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Entities.Providers;
using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.Events;
using System;
using System.Collections.Generic;

public Result<List<ProviderEvent>> HandleResponseAndGetEvents(string body, Dictionary<string, string> headers, int statusCode, ChannelMessage channelMessage)
        {
            var events = new List<ProviderEvent>();
            if (channelMessage.Request.MessageType == ProviderMessageType.Transmissao)
            {
                if (statusCode != 200 && statusCode != 304)
                {
                    return Result.Failure<List<ProviderEvent>>("StatusCode nao eh 200");
                }

                var agendaData = channelMessage.Request.Model.Split('_')[1];
                var dataProgramacao = DateTime.ParseExact(agendaData, "dd-MM-yyyy", null);

                var guide = JsonConvert.DeserializeObject<SkyGuide>(body);

                var canais = new List<CanalProgramas>();
                foreach (var skyCanal in guide.Content)
                {
                    var canal = new CanalProgramas(skyCanal.CallLetter, skyCanal.ImageUrl, skyCanal.ChannelNumber.ToString());
                    var schedules = skyCanal.Schedules.Where(x => x.Title.Contains(" x ") && !x.Title.EndsWith(" VT")).ToList();

                    foreach (var schedule in schedules)
                    {
                        var programa = new CanalPrograma(schedule.Title, schedule.StartDate.DateTime, schedule.EndDate.DateTime);
                        canal.Programas.Add(programa);
                    }

                    if (canal.Programas.Count > 0)
                        canais.Add(canal);
                }

                if (canais.Count > 0)
                {
                    var partidaEvent = new ProgramacaoOperadoraObtidaEvent(Id, dataProgramacao, OperadoraEnum.Sky)
                    {
                        Programacao = canais
                    };

                    events.Add(partidaEvent);
                }
            }

            return Result.Success(events);
        }

