public static (Escalacao, Escalacao, string) FichaFromHtml(string html)
        {
            var htmlDoc = new HtmlDocument();
            htmlDoc.LoadHtml(html);

            var escalacaoMandante = new Escalacao();
            var escalacaoVisitante = new Escalacao();

            var escalacoes = htmlDoc.DocumentNode.SelectNodes("//div[@class='ficha-jogo__flex-filho ficha-jogo__time']");
            if (escalacoes != null)
            {

                var mandanteJogadores = GetJogadoresTime(escalacoes[0]);
                var visitanteJogadores = GetJogadoresTime(escalacoes[1]);

                var mandanteReservas = GetJogadoresTime(escalacoes[2]);
                var visitanteReservas = GetJogadoresTime(escalacoes[3]);

                escalacaoMandante = new Escalacao
                {
                    Jogadores = mandanteJogadores,
                    Reservas = mandanteReservas
                };

                escalacaoVisitante = new Escalacao
                {
                    Jogadores = visitanteJogadores,
                    Reservas = visitanteReservas
                };

                var fichasNodes = htmlDoc.DocumentNode.SelectNodes("//div[@class='ficha-jogo__flex-filho ficha-jogo__comissao-tecnica']");

                (var tecMandante, var esqMandante) = GetFicha(fichasNodes[0]);
                (var tecVisitante, var esqVisitante) = GetFicha(fichasNodes[1]);

                escalacaoMandante.Tecnico = tecMandante;
                escalacaoMandante.Esquema = esqMandante;

                escalacaoVisitante.Tecnico = tecVisitante;
                escalacaoVisitante.Esquema = esqVisitante;
            }

            var estadio = htmlDoc.DocumentNode.SelectSingleNode("//div[@class='ficha-jogo__estadio-nome']")?.InnerText;

            return (escalacaoMandante, escalacaoVisitante, estadio);
        }

