using HtmlAgilityPack;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;

private static Scouts GetScouts(HtmlNode jogadorNode)
        {
            var scout = new Scouts();

            var cartoesNode = jogadorNode.SelectSingleNode(".//div[@class='ficha-jogo__time__jogadores__lista__jogador__scouts-cartoes']");
            if (cartoesNode.HasChildNodes)
            {
                var corCartao = cartoesNode.SelectSingleNode("svg/rect")?.Attributes["fill"]?.Value;
                if (corCartao == "#FA060E")
                    scout.CartaoVermelho++;

                if (corCartao == "#F3C500")
                    scout.CartaoAmarelo++;
            }

            var golsNode = jogadorNode.SelectSingleNode(".//div[@class='ficha-jogo__time__jogadores__lista__jogador__scouts__gols']");
            if (golsNode.HasChildNodes)
            {
                var golQtdNode = golsNode.SelectSingleNode("span");
                if (golQtdNode != null)
                {
                    var golsQtd = golQtdNode.InnerText.Replace("(", "").Replace(")", "");
                    scout.Gol = int.Parse(golsQtd);
                }
                else if (golsNode.SelectSingleNode("svg") != null)
                {
                    scout.Gol = 1;
                }
            }

            return scout;
        }

