public class LancePlacarGeHtmlBuilder
    {
        public static Result<LancePlacarDto> PlacarFromHtml(string html)
        {
            try
            {
                var htmlDoc = new HtmlDocument();
                htmlDoc.LoadHtml(html);

                var node = htmlDoc.DocumentNode;

                var mandantePlacar = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/article/article[1]/div[1]/strong")?.InnerText;
                var mandantePenalti = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/article/article[1]/div[2]/span")?.InnerText;
                var mandanteDestaques = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/article/article[1]/header/div/span")?.InnerText;

                var visitantePlacar = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/article/article[2]/div[1]/strong")?.InnerText;
                var visitantePenalti = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/article/article[2]/div[2]/span")?.InnerText;
                var visitanteDestaque = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/article/article[2]/header/div/span")?.InnerText;

                var momento = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/div/div/time/text()[1]")?.InnerText;
                var tempo = node.SelectSingleNode("//*[@id=\"transmissao\"]/div/div/section[1]/div/div/abbr")?.InnerText;

                if (!string.IsNullOrEmpty(momento) && momento.Contains(":"))
                {
                    momento = momento.Split(':')[0];
                }

                var placar = new LancePlacarDto
                {
                    DestaqueMandante = mandanteDestaques,
                    DestaqueVisitante = visitanteDestaque,
                    Momento = momento,
                    Tempo = tempo
                };

                placar.SetPlacar(mandantePlacar, visitantePlacar, mandantePenalti, visitantePenalti);;

                return Result.Success(placar);
            }
            catch (System.Exception e)
            {
                return Result.Failure<LancePlacarDto>($"Erro ao atualizar placar: " + e.Message);
            }
        }
    }

