using HtmlAgilityPack;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;
using System.Globalization;

public static List<PartidaGeDto> PartidasFromHtml(string html, DateTime dataJogo)
        {
            var htmlDoc = new HtmlDocument();
            htmlDoc.LoadHtml(html);

            var campeonatosNode = htmlDoc
                .DocumentNode
                .SelectNodes("//div[contains(@class, 'GroupByChampionshipsstyle__GroupBychampionshipsWrapper')]");

            if (campeonatosNode == null)
                return null;

            var partidasCampeonato = new List<PartidaGeDto>();

            foreach (var campNode in campeonatosNode)
            {
                var campeonatoNome = campNode.SelectSingleNode(".//div")
                    ?.InnerText;

                var jogosNode = campNode.SelectNodes("div/a");
                foreach (var jogoNode in jogosNode)
                {
                    var horario = jogoNode.SelectSingleNode(".//div/div")?.InnerText;
                    var status = string.Empty;
                    if (!DateTime.TryParseExact($"{dataJogo:yyyy-MM-dd} {horario}", "yyyy-MM-dd HH:mm", null, DateTimeStyles.None, out var partidaData))
                        status = horario;

                    var temhorario = true;
                    if (partidaData == DateTime.MinValue)
                    {
                        partidaData = dataJogo;
                        temhorario = false;
                    }

                    var link = jogoNode.SelectSingleNode(".//div/div/a")?.Attributes["href"]?.Value;
                    if (link == null)
                        link = jogoNode.Attributes["href"]?.Value;

                    if (!string.IsNullOrEmpty(link))
                        link = $"{link}?beta-test-v2-refused=true";

                    var mandanteNode = jogoNode.SelectSingleNode(".//div[2]/div[1]");
                    var visitanteNode = jogoNode.SelectSingleNode(".//div[2]/div[2]");

                    if (mandanteNode == null || visitanteNode == null)
                        continue;

                    var mandante = GetTime(mandanteNode);
                    var visitante = GetTime(visitanteNode);

                    var rodada = jogoNode.SelectSingleNode(".//div[3]")?.InnerText;

                    var partida = new PartidaGeDto
                    {
                        Data = partidaData,
                        TimeMandante = mandante.Time,
                        TimeMandantePlacar = string.IsNullOrEmpty(mandante.Placar) ? null : int.Parse(mandante.Placar),
                        TimeMandantePenalti = string.IsNullOrEmpty(mandante.PlacarPenalti) ? null : int.Parse(mandante.PlacarPenalti),
                        TimeVisitante = visitante.Time,
                        TimeVisitantePlacar = string.IsNullOrEmpty(visitante.Placar) ? null : int.Parse(visitante.Placar),
                        TimeVisitantePenalti = string.IsNullOrEmpty(visitante.PlacarPenalti) ? null : int.Parse(visitante.PlacarPenalti),
                        UrlTransmissao = link,
                        Rodada = rodada,
                        Campeonato = campeonatoNome,
                        Status = status switch
                        {
                            "Veja como foi" => PartidaStatus.Encerrada,
                            "Saiba como foi" => PartidaStatus.Encerrada,
                            "Encerrado" => PartidaStatus.Encerrada,
                            "TEMPO REAL" => PartidaStatus.AoVivo,
                            "AO VIVO" => PartidaStatus.AoVivo,
                            "Sem cobertura" => PartidaStatus.AoVivo,
                            _ => PartidaStatus.NaoComecou
                        },
                        TemHorario = temhorario
                    };

                    partidasCampeonato.Add(partida);
                }
            }

            return partidasCampeonato;
        }

