            var fase = default(IFase);

            var nav = htmlDoc.DocumentNode.SelectSingleNode("/html/body/div[2]/main/div[2]/div/section[1]/nav");
            var temNavigation = nav != null;

            if (temNavigation)
            {
                var faseNome = htmlDoc.DocumentNode.SelectSingleNode("/html/body/div[2]/main/div[2]/div/section[1]/nav/span[2]")?.InnerText;

                var section = htmlDoc.DocumentNode.SelectSingleNode("/html/body/div[2]/main/div[2]/div/section/article/section");
                var sectionClass = section.Attributes["class"]?.Value;

                var isMataMata = sectionClass == "tabela tabela__mata-mata";
                if (isMataMata)
                {
                    var faseMataMata = new FaseMataMata(faseNome);
                    fase = faseMataMata;

                    var chavesNodes = 
                        section.SelectNodes(".//div[@class='mata-mata__chave chave__jogos--2']") ??
                        section.SelectNodes(".//div[@class='mata-mata__chave chave__jogos--1']");
                    foreach (var chaveNode in chavesNodes)
                    {
                        var chave = BuildChaveMataMata(chaveNode);
                        if (chave == null)
                            break;

                        faseMataMata.AddChave(chave);
                    }
                }
                else
                {
                    if (sectionClass == "tabela tabela__pontos-corridos")
                    {
                        var tabelaNode = section;
                        var tableRows = tabelaNode.SelectNodes("//tr[@class='classificacao__tabela--linha']");

                        var faseClassificatoria = new FaseClassificatoria(faseNome);
                        faseClassificatoria.Classificacao = BuildClassificacao(tableRows);

                        fase = faseClassificatoria;
                    }
                    else if (sectionClass == "tabela tabela__pontos-corridos-grupado")
                    {
                        var gruposNome = new List<string>();

                        var headersNodes = htmlDoc
                            .DocumentNode
                            .SelectNodes("/html/body/div[2]/main/div[2]/div/section[1]/article/header");

                        foreach (var headerNode in headersNodes)
                        {
                            gruposNome.Add(headerNode.InnerText);
                        }

                        var gruposNodes = section.SelectNodes("//section[@class='tabela tabela__pontos-corridos-grupado']");

                        var faseGrupos = new FaseGrupos(faseNome);
                        fase = faseGrupos;

                        for (int i = 0; i < gruposNodes.Count; i++)
                        {
                            var grupoNode = gruposNodes[i];
                            var grupoNome = gruposNome[i];

                            var tableRows = grupoNode.SelectNodes(".//tr[@class='classificacao__tabela--linha']");

                            var grupoClassificacao = BuildClassificacao(tableRows);

                            var grupo = new FaseGrupos.FaseGrupo(grupoNome);
                            grupo.Classificacao = grupoClassificacao;

                            faseGrupos.AddGrupo(grupo);
                        }
                    }
                    else
                    {
                        throw new NotImplementedException($"Section Class {sectionClass} nao implementado.");
                    }
                }
            }
            else
            {
                // classificao - fase unica
            }

            return fase;
        }

