private static List<ClassificacaoTimeDTO> BuildClassificacao(HtmlNodeCollection tableRows)
        {
            var linhas = tableRows.Count / 2;

            var classificacao = new List<ClassificacaoTimeDTO>();

            for (int i = 0; i < linhas; i++)
            {
                var timeNode = tableRows[i];
                var statsNode = tableRows[i + linhas];

                var timePos = timeNode.SelectSingleNode(".//td[1]")?.InnerText;
                var time = timeNode.SelectSingleNode(".//td[2]/strong")?.InnerText;
                var timeVar = timeNode.SelectSingleNode(".//td[3]/span")?.InnerText;

                var pontos = statsNode.SelectSingleNode(".//td[1]")?.InnerText;
                var jogos = statsNode.SelectSingleNode(".//td[2]")?.InnerText;
                var vitorias = statsNode.SelectSingleNode(".//td[3]")?.InnerText;
                var empates = statsNode.SelectSingleNode(".//td[4]")?.InnerText;
                var derrotas = statsNode.SelectSingleNode(".//td[5]")?.InnerText;
                var golsPro = statsNode.SelectSingleNode(".//td[6]")?.InnerText;
                var golsContra = statsNode.SelectSingleNode(".//td[7]")?.InnerText;

                var classificacaoTime = new ClassificacaoTimeDTO
                {
                    Time = new TimeProviderRaw(time, time),
                    Posicao = int.Parse(timePos),
                    Variacao = int.Parse(timeVar),
                    Pontos = int.Parse(pontos),
                    Vitorias = int.Parse(vitorias),
                    Derrotas = int.Parse(derrotas),
                    Empates = int.Parse(empates),
                    GolsContra = int.Parse(golsContra),
                    GolsPro = int.Parse(golsPro),
                    Jogos = int.Parse(jogos)
                };

                classificacao.Add(classificacaoTime);
            }

            return classificacao;
        }

