public static List<ClassificacaoTimeDTO> GetClassificacaoDtos(string html, string model)
        {
            var classificacao = new List<ClassificacaoTimeDTO>();

            var htmlDoc = new HtmlDocument();
            htmlDoc.LoadHtml(html);

            var tableRows = htmlDoc.DocumentNode.SelectNodes("//table/tbody/tr");

            for (int i = 0; i < tableRows.Count / 2; i++)
            {
                var nodeRow = tableRows[i];
                var pos = nodeRow.SelectSingleNode(".//td/div/span[1]")?.InnerText;
                var time = nodeRow.SelectSingleNode(".//td/div/span[4]")?.InnerText;
                var link = nodeRow.SelectSingleNode(".//td/div/span[4]/a")?.Attributes["href"]?.Value;
                var escudo = nodeRow.SelectSingleNode(".//td/div/span[2]/a/img")?.Attributes["src"]?.Value;
                escudo = null;
                var id = string.Empty;

                if (!string.IsNullOrEmpty(link))
                {
                    foreach (var slice in link.Split('/'))
                    {
                        if (int.TryParse(slice, out var timeId))
                            id = timeId.ToString();
                    }
                }

                var c = new ClassificacaoTimeDTO
                {
                    Time = new TimeProviderRaw(id, time, escudo, link),
                    TimeLink = link,
                    TimeId = id,
                    Posicao = int.Parse(pos)
                };

                classificacao.Add(c);
            }

            int index = 0;
            for (int i = tableRows.Count / 2; i < tableRows.Count; i++, index++)
            {
                var c = classificacao[index];

                var nodeRow = tableRows[i];

                var jogos = nodeRow.SelectSingleNode(".//td[1]/span[1]")?.InnerText;
                var vit = nodeRow.SelectSingleNode(".//td[2]/span[1]")?.InnerText;
                var emp = nodeRow.SelectSingleNode(".//td[3]/span[1]")?.InnerText;
                var derr = nodeRow.SelectSingleNode(".//td[4]/span[1]")?.InnerText;
                var golsPro = nodeRow.SelectSingleNode(".//td[5]/span[1]")?.InnerText;
                var golsContra = nodeRow.SelectSingleNode(".//td[6]/span[1]")?.InnerText;

                var pontos = nodeRow.SelectSingleNode(".//td[8]/span[1]")?.InnerText;

                c.Jogos = int.Parse(jogos);
                c.Vitorias = int.Parse(vit);
                c.Empates = int.Parse(emp);
                c.Derrotas = int.Parse(derr);
                c.GolsPro = int.Parse(golsPro);
                c.GolsContra = int.Parse(golsContra);
                c.Pontos = int.Parse(pontos);
            }

            return classificacao;
        }

