using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Events.Profissionais;
using RealtimeMatches.Domain.Projections.Profissionais;
using System.Threading;
using System.Threading.Tasks;

public class ProfissionaisEventHandler : INotificationHandler<JogadorCriado>
{
    private readonly IProfissionalRepository _repository;
    private readonly IReadModelRepository<JogadorProjection> _jogadorReadModel;
    private readonly IMapper _mapper;

    public ProfissionaisEventHandler(
        IProfissionalRepository repository,
        IReadModelRepository<JogadorProjection> jogadorReadModel,
        IMapper mapper)
    {
        _repository = repository;
        _jogadorReadModel = jogadorReadModel;
        _mapper = mapper;
    }

    public async Task Handle(JogadorCriado notification, CancellationToken cancellationToken)
    {
        var jogador = await _repository.GetJogadorAsync(notification.JogadorId);

        var projection = _mapper.Map<JogadorProjection>(jogador);

        var locker = await _jogadorReadModel.AcquireLockAsync();

        await _jogadorReadModel.SaveAsync(locker, projection);

        await _jogadorReadModel.ReleaseLockAsync(locker);
    }
}

