    public CriarJogadorHandler(IProfissionalRepository repository)
    {
        _repository = repository;
    }

    public async Task<Guid> Handle(CriarJogador request, CancellationToken cancellationToken)
    {
        var pessoa = new Pessoa(request.Nome, request.Foto);

        var jogador = new Jogador(pessoa, request.Apelido)
        {
