// Namespace: RealtimeMatches.Application.Partidas.Commands
// Class: CreateOrUpdatePartidaCommand.Handler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Agendas.Commands;
using RealtimeMatches.Application.Coberturas.Commands;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services.Abstractions;
using RealtimeMatches.Application.Models.Caching;

public async Task<Result<PartidaAgregada>> Handle(Contract request, CancellationToken cancellationToken)
        {
            _logger.LogInformation($"Updating PartidaDto {request.Mandante.Nome} {request.PlacarMandante} x {request.PlacarVisitante} {request.Visitante.Nome}.");

            var partida = default(PartidaAgregada);

            if (request.PartidaId.HasValue)
            {
                partida = await _applicationContext.Partidas
                    .IgnoreQueryFilters()
                    .Include(p => p.Campeonato)
                    .Include(p => p.Mandante)
                    .Include(p => p.Visitante)
                    .Include(p => p.Atualizacoes)
                    .Include(p => p.Lances)
                    .FirstOrDefaultAsync(p => p.Id == request.PartidaId.Value, cancellationToken: cancellationToken);
            }
            else
            {
                var partidaRequest = new PartidaAgregada(
                    request.ProviderId,
                    request.DataHorario,
                    request.Campeonato,
                    request.Mandante,
                    request.Visitante,
                    request.Rodada,
                    request.Status,
                    request.PlacarMandante,
                    request.PlacarVisitante);

                partida = await _applicationContext.Partidas
                        .IgnoreQueryFilters()
                        .Include(p => p.Campeonato)
                        .Include(p => p.Mandante)
                        .Include(p => p.Visitante)
                        .Include(p => p.Atualizacoes)
                        .Include(p => p.Lances)
                        .FirstOrDefaultAsync(p => p.Id == partidaRequest.Id, cancellationToken: cancellationToken);

                if (partida == null)
                {
                    partida = partidaRequest;
                    _applicationContext.Partidas.Add(partida);
                }
            }

            partida.SetUniqueKey(partida.Campeonato, partida.Mandante, partida.Visitante);

            // ToDo: Criar evento e handler
            var estadio = await _integrationService.GetEstadio(partida.ProviderId, request.Estadio);

            partida
                .AtualizarStatus(request.Status, request.Momento)
                .AtualizarEstadio(estadio)
                .AtualizarPlacar(
                    request.PlacarMandante,
                    request.PlacarVisitante,
                    request.PenaltiMandante,
                    request.PenaltiVisitante,
                    request.DestaqueMandante,
                    request.DestaqueVisitante);

            if (partida.Status == PartidaStatus.NaoComecou &&
                request.TemHorario &&
                request.DataHorario != partida.Data)
            {
                partida.Data = request.DataHorario;
                partida.DataFimEstimada = partida.Data.AddHours(3);
            }

            if (partida.Data.Hour == 0 && partida.Data.Minute == 0)
            {
                _logger.LogWarning($"Possível partida sem horário definido. {partida}. ");

                partida.DataFimEstimada = DateTime.UtcNow.AddHours(-3).Date.AddHours(26);
            }

            if (DateTime.UtcNow.AddHours(-3) > partida.Data &&
                partida.Status == PartidaStatus.NaoComecou)
            {
                partida.Status = PartidaStatus.AoVivo;
            }

            if (DateTime.UtcNow.AddHours(-3) > partida.Data.AddMinutes(180) &&
                partida.Status == PartidaStatus.AoVivo)
            {
                partida.Status = PartidaStatus.Encerrada;
            }

            var partidaCache = new BasePartidaCache(partida);
            await _partidaCache.SetPartidaBase(partidaCache);

            partida.UpdatedAt = DateTime.UtcNow.AddHours(-3);

            var rowsAffected = await _applicationContext.SaveChangesAsync(cancellationToken);

            _logger.LogInformation($"Updating PartidaCache {partidaCache.Mandante.Nome} {partidaCache.Mandante.Placar} x {partidaCache.Visitante.Placar} {partidaCache.Visitante.Nome}.");

            _logger.LogInformation($"Updating Partida {partida.Id} {partida.Mandante.Nome} {partida.PlacarMandante} x {partida.PlacarVisitante} {partida.Visitante.Nome}. Status: {partida.Status}");

            if (partida.Events.Count > 0)
            {
                await _partidaEventService.Publish(partida.Events);
            }

            var coberturaResult = await _mediator.Send(new CreateCobertura.Contract(partida.ProviderId, partida.Id, request.UrlTransmissao));
            if (coberturaResult.IsFailure)
                _logger.LogInformation(coberturaResult.Error);

            var agendaResult = await _mediator.Send(new Agendas.Commands.AgendarPartida.Contract(partida.Id, partida.UniqueKey), cancellationToken);
            if (agendaResult.IsFailure)
            {
                _logger.LogError($"Erro ao agendar partida {partida}: {agendaResult.Error}");
                return Result.Failure<PartidaAgregada>("Erro ao agendar Partida");
            }
            else
            {
                if (agendaResult.Value.Agendada)
                {
                    await _mediator.Send(new AplicarCoberturaRequestParaPartidaAgendada.Contract(partida.UniqueKey));
                }
            }

            return Result.Success(partida);
        }

