using AutoMapper;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Events.Partidas;
using RealtimeMatches.Domain.Projections.Partidas.Escalacoes;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class PartidasEscalacoesEventHandler : INotificationHandler<EscalacaoAtualizada>
{
    private readonly IMapper _mapper;
    private readonly IPartidaRepository _repository;
    private readonly IReadModelRepository<PartidaEscalacoesProjection> _readModel;

    public PartidasEscalacoesEventHandler(
        IMapper mapper,
        IPartidaRepository repository,
        IReadModelRepository<PartidaEscalacoesProjection> readModel)
    {
        _mapper = mapper;
        _repository = repository;
        _readModel = readModel;
    }

    public async Task Handle(EscalacaoAtualizada notification, CancellationToken cancellationToken)
    {
        var locker = await _readModel.AcquireLockAsync();

        var partida = await _repository
            .Partidas
            .AsNoTracking()
            .Include(x => x.Lances)
            .Include(x => x.Mandante)
            .Include(x => x.Visitante)
            .FirstOrDefaultAsync(x => x.Id == notification.PartidaId);

        var projection = _mapper.Map<PartidaEscalacoesProjection>(partida);

        projection.Mandante.Reservas = projection.Mandante.Reservas.OrderBy(x => (int)x.Posicao).ToList();
        projection.Mandante.Titulares = projection.Mandante.Titulares.OrderBy(x => (int)x.Posicao).ToList();

        projection.Visitante.Reservas = projection.Visitante.Reservas.OrderBy(x => (int)x.Posicao).ToList();
        projection.Visitante.Titulares = projection.Visitante.Titulares.OrderBy(x => (int)x.Posicao).ToList();

        await _readModel.SaveAsync(locker, projection);

        await _readModel.ReleaseLockAsync(locker);
    }
}

