using AutoMapper;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas;
using RealtimeMatches.Domain.Events.Partidas;
using RealtimeMatches.Domain.Events.Tabelas;
using RealtimeMatches.Domain.Extensions;
using RealtimeMatches.Domain.Projections.Partidas;

public async Task Handle(PartidasMataMataAgendadas notification, CancellationToken cancellationToken)
    {
        var tabela = await _tabelaRepository.GetTabelaById(notification.TabelaId) as TabelaFases;
        var faseMataMata = tabela.GetFaseMataMata(notification.Partidas[0].FaseMataMataId);

        var regulamento = tabela.GetRegulamentoFaseGrupos();

        foreach (var partidaMataMata in notification.Partidas)
        {
            var locker = await _readModelRepository.AcquireLockAsync();

            var partida = await _repository
                .Partidas
                .AsNoTracking()
                .Include(x => x.Mandante)
                .Include(x => x.Visitante)
                .FirstOrDefaultAsync(x => x.Id == partidaMataMata.PartidaId);

            var partidaProjection = _mapper.Map<PartidaProjection>(partida);

            if (regulamento.ProximaFase == faseMataMata.Chave.ToFaseTipo())
            {
                var classificado = regulamento.Classificados.First(x => x.ClassificadosId == partidaMataMata.ChaveId);

                if (!partida.Mandante.EquipeDefinida)
                {
                    partidaProjection.Mandante = new EquipeProjection
                    {
                        Nome = $"{classificado.GrupoTime1Classificado.Posicao}º Grupo {classificado.GrupoTime1Classificado.Grupo}"
                    };
                }

                if (!partida.Visitante.EquipeDefinida)
                {
                    partidaProjection.Visitante = new EquipeProjection
                    {
                        Nome = $"{classificado.GrupoTime2Classificado.Posicao}º Grupo {classificado.GrupoTime2Classificado.Grupo}"
                    };
                }
            }

            await _readModelRepository.SaveAsync(locker, partidaProjection);

            await _readModelRepository.ReleaseLockAsync(locker);
        }
    }

