using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Enums.Partidas;
using RealtimeMatches.Domain.Events.Partidas;
using RealtimeMatches.Domain.Projections.Partidas.Lances;
using System.Collections.Generic;
using System.Linq;
using System.Threading;

public class PartidasLancesEventHandler : INotificationHandler<LanceRegistrado>
{
    private readonly IMapper _mapper;
    private readonly IPartidaRepository _repository;
    private readonly IReadModelRepository<PartidaLancesProjection> _readModel;

    public PartidasLancesEventHandler(
        IMapper mapper,
        IPartidaRepository repository,
        IReadModelRepository<PartidaLancesProjection> readModel)
    {
        _mapper = mapper;
        _repository = repository;
        _readModel = readModel;
    }

    public async Task Handle(LanceRegistrado notification, CancellationToken cancellationToken)
    {
        var locker = await _readModel.AcquireLockAsync();

        var partida = await _repository.GetPartidaWithLancesById(notification.PartidaId);

        var projection = _mapper.Map<PartidaLancesProjection>(partida);

        var lanceInicial = projection.Lances.FirstOrDefault(x => x.Tipo == TipoLance.InicioDeJogo);
        var lanceFinal = projection.Lances.FirstOrDefault(x => x.Tipo == TipoLance.FimDeJogo);

        var lancesOrdered = new List<LanceProjection>(
                projection.Lances
                .Where(x => x.Tipo != TipoLance.InicioDeJogo && x.Tipo != TipoLance.FimDeJogo)
                .OrderByDescending(x => x.Momento.GetTempoTotal()));

        projection.Lances.Clear();

        if (lanceFinal != null)
        {
            projection.Lances.Add(lanceFinal);
        }

        projection.Lances.AddRange(lancesOrdered);

        if (lanceInicial != null)
        {
            projection.Lances.Add(lanceInicial);
        }

        await _readModel.SaveAsync(locker, projection);

        await _readModel.ReleaseLockAsync(locker);
    }
}

