using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Partidas.Commands.Lances.Contracts;
using RealtimeMatches.Domain.ValueObjects.Partidas;
using System;
using System.Threading.Tasks;

public async Task<Lance> Create(LanceCommand command)
    {
        Lance lance;
        switch (command)
        {
            case RegistrarCartao registrarCartao:
                lance = new Lance(command.PartidaId, command.Momento, registrarCartao.TimeId);

                lance.Cartao(registrarCartao.Cartao, await UpdateJogadorLanceWithJogadorIfHasId(registrarCartao.Jogador));

                break;

            case RegistrarInicioDeJogo:
                lance = new Lance(command.PartidaId, command.Momento);

                lance.InicioDeJogo();

                break;
            case RegistrarFimDeJogo:
                lance = new Lance(command.PartidaId, command.Momento);

                lance.FimDeJogo();

                break;

            case RegistrarGol registrarGol:
                lance = new Lance(registrarGol.PartidaId, registrarGol.Momento, registrarGol.TimeId);

                var autorGol = await UpdateJogadorLanceWithJogadorIfHasId(registrarGol.Autor);

                if (registrarGol.Contra)
                {
                    lance.GolContra(autorGol);
                }
                else
                {
                    var jogadorAssistencia = registrarGol.Assistencia != null ? await UpdateJogadorLanceWithJogadorIfHasId(registrarGol.Assistencia) : null;
                    lance.Gol(autorGol, jogadorAssistencia);
                }

                break;

            case RegistrarVarGolAnulado registrarVarGolAnulado:
                lance = new Lance(command.PartidaId, command.Momento, registrarVarGolAnulado.TimeId);

                lance.GolAnulado(true, await UpdateJogadorLanceWithJogadorIfHasId(registrarVarGolAnulado.Jogador));

                break;

            case RegistrarPenaltiPerdido registrarPenaltiPerdido:
                lance = new Lance(command.PartidaId, command.Momento, registrarPenaltiPerdido.TimeId);

                lance.PenaltiPerdido(await UpdateJogadorLanceWithJogadorIfHasId(registrarPenaltiPerdido.Jogador));

                break;

            case RegistrarSubstituicao registrarSubstituicao:
                lance = new Lance(command.PartidaId, command.Momento, registrarSubstituicao.TimeId);

                var jogadorEntra = await UpdateJogadorLanceWithJogadorIfHasId(registrarSubstituicao.Entra);
                var jogadorSai = await UpdateJogadorLanceWithJogadorIfHasId(registrarSubstituicao.Sai);

                lance.Substituicao(jogadorEntra, jogadorSai);

                break;

            case RegistrarDisputaPenalti registrarDisputaPenalti:
                lance = new Lance(registrarDisputaPenalti.PartidaId, registrarDisputaPenalti.Momento, registrarDisputaPenalti.TimeId);

                var autorPenalti = await UpdateJogadorLanceWithJogadorIfHasId(registrarDisputaPenalti.Autor);

                lance.DisputaPenalti(autorPenalti, registrarDisputaPenalti.Converteu);

                break;
            default:
                throw new NotImplementedException($"{command.GetType().Name} not implemented to create Lance");
        }

        return lance;
    }

