using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Models.Caching;
using RealtimeMatches.Domain.Enums;
using System;
using System.Collections.Generic;
using System.Linq;

public async Task<Result<IEnumerable<PartidaCache>>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var dia = request.Dia?.ToLower();

                var date = DateTime.UtcNow.AddHours(-3);

                if (!request.Date.HasValue)
                {
                    if (string.IsNullOrEmpty(dia))
                        _ = date;
                    else if (dia == "ontem")
                        date = date.AddDays(-1);
                    else if (dia == "amanha" || dia == "amanhã")
                        date = date.AddDays(1);
                    else if (dia == "hoje")
                        _ = date;
                    else if (!DateTime.TryParse(dia, out date))
                        return Result.Failure<IEnumerable<PartidaCache>>("Data não estava num formato válido.");
                }
                else
                {
                    date = request.Date.Value;
                }

                var partidasIdResult = await _partidaCacheService.ListPartidasDate(date);
                if (partidasIdResult.IsFailure)
                {
                    _logger.LogError($"Erro ao buscar partidas do dia {date}");
                    return Result.Failure<IEnumerable<PartidaCache>>($"Erro ao buscar partidas do dia {date}");
                }

                var contracts = partidasIdResult.Value
                    .Select(id => Task.Run(() => 
                    {
                        var scope = _scopeFactory.CreateScope();
                        var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

                        return mediator.Send(new GetPartidaByIdAndDate.Contract { PartidaData = date, PartidaId = id, FichaCompleta = false, CacheOnly = request.CacheOnly });
                    }));

                var partidasResult = await Task.WhenAll(contracts);

                var partidas = partidasResult.Where(x => x.IsSuccess).Select(x => x.Value);

                if (request.CampeonatoId != null)
                {
                    partidas = partidas
                        .Where(j => j.Campeonato.Id == request.CampeonatoId)
                        .OrderBy(p => p.OrderKey)
                        .ToList();
                }
                else
                {
                    partidas = partidas.Where(x =>
                    {
                        if (x.Rodada.Contains("final", StringComparison.OrdinalIgnoreCase))
                            return true;

                        if (x.Campeonato.Importancia == ImportanciaEnum.Grande ||
                            x.Mandante.Importancia == ImportanciaEnum.Grande ||
                            x.Visitante.Importancia == ImportanciaEnum.Grande)
                            return true;
                        else if ((x.Campeonato.Importancia == ImportanciaEnum.Media && x.Mandante.Importancia == ImportanciaEnum.Media) ||
                                 (x.Campeonato.Importancia == ImportanciaEnum.Media && x.Visitante.Importancia == ImportanciaEnum.Media) ||
                                 (x.Mandante.Importancia == ImportanciaEnum.Media && x.Visitante.Importancia == ImportanciaEnum.Media))
                            return true;
                        else
                            return false;
                    })
                    .OrderBy(p => p.OrderKey)
                    .ToList();
                }

                return Result.Success(partidas);
            }

