using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Models.Caching;
using System;
using System.Collections.Generic;

public async Task<Result<PartidaCache>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partidaDataResult = await _partidaCacheService.GetPartidaDate(request.PartidaId);
                if (partidaDataResult.IsFailure)
                {
                    _logger.LogError(partidaDataResult.Error);

                    if (request.CacheOnly)
                        return Result.Failure<PartidaCache>(partidaDataResult.Error);

                    partidaDataResult = await _mediator.Send(new GetDataPartida.Contract(request.PartidaId));
                    if (partidaDataResult.IsFailure)
                    {
                        _logger.LogError($"Data da partida {request.PartidaId} nao encontrada");

                        if (request.PartidaData.HasValue)
                            await _partidaCacheService.DelPartidaFromDate(request.PartidaId, request.PartidaData.Value);

                        return Result.Failure<PartidaCache>(partidaDataResult.Error);
                    }
                }

                var partidaData = partidaDataResult.Value;
                var partidaCache = default(PartidaCache);

                var partidaBaseResult = await _partidaCacheService.GetPartidaBase(request.PartidaId, partidaData);
                if (partidaBaseResult.IsFailure)
                {
                    if (request.CacheOnly)
                        return Result.Failure<PartidaCache>("Partida not found in cache.");

                    using var scope = _serviceScopeFactory.CreateScope();
                    var context = scope.ServiceProvider.GetRequiredService<IApplicationContext>();

                    var partidaDb = await context
                        .Partidas
                        .Include(x=>x.Campeonato)
                        .Include(x => x.Mandante)
                        .Include(x => x.Visitante)
                        .Include(x => x.Transmissoes)
                            .ThenInclude(x => x.Canal)
                        .AsNoTracking()
                        .Where(x => x.Id == request.PartidaId)
                        .FirstOrDefaultAsync(cancellationToken);

                    if (partidaDb == null)
                        return Result.Failure<PartidaCache>("Partida not found in cache.");

                    partidaCache = new PartidaCache(partidaDb);
                }
                else
                {
                    partidaCache = new PartidaCache(partidaBaseResult.Value);
                }

                if (request.FichaCompleta)
                {
                    var lances = await _partidaCacheService.GetLancesPartida(request.PartidaId, partidaData);
                    if (lances != null)
                    {
                        partidaCache.Lances = lances ?? new List<LanceCache>();
                    }

                    var escalacao = await _partidaCacheService.GetEscalacaoPartida(request.PartidaId, partidaData);
                    if (escalacao != null)
                    {
                        var escMandante = escalacao.FirstOrDefault();
                        var escVisitante = escalacao.LastOrDefault();

                        partidaCache.Mandante.Escalacao = escMandante;
                        partidaCache.Visitante.Escalacao = escVisitante;
                    }

                    var cobrancaPenalti = await _partidaCacheService.GetCobrancaPenalti(request.PartidaId, partidaData);
                    if (cobrancaPenalti != null)
                    {
                        partidaCache.CobrancaPenaltis = cobrancaPenalti;
                    }

                    var pontuacao = await _partidaCacheService.GetPontuacaoFantasia(request.PartidaId, partidaData);
                    if (pontuacao != null)
                    {
                        partidaCache.PontuacaoFantasia = pontuacao;
                    }
                }

                var transmissoesResult = await _partidaCacheService.GetTransmicoesPartida(request.PartidaId, partidaData);

                var transmissoes = transmissoesResult.Value;
                partidaCache.Transmissoes = transmissoes ?? new List<TransmissaoCache>();

                return Result.Success(partidaCache);
            }

