using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Bus;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Partidas.Commands.Atualizacoes;
using RealtimeMatches.Domain.Entities.Aggregates.Partidas;
using RealtimeMatches.Domain.Events.Times;
using System;
using System.Linq;
using System.Threading;

public class PartidaEquipeSagaHandlers : INotificationHandler<TimeEscudoAtualizado>
{
    private readonly IPartidaRepository _repository;
    private readonly ICommandBus _bus;

    public PartidaEquipeSagaHandlers(
        IPartidaRepository repository,
        ICommandBus bus)
    {
        _repository = repository;
        _bus = bus;
    }

    public async Task Handle(TimeEscudoAtualizado notification, CancellationToken cancellationToken)
    {
        var partidas = await _repository
            .Partidas.AsNoTracking()
            .Where(x => x.Mandante.TimeId == notification.TimeId || x.Visitante.TimeId == notification.TimeId)
            .Where(x => x.Data.HasValue && x.Data.Value >= DateTime.UtcNow)
            .Select(x => new
            {
                x.Id,
                Equipes = new Equipe[] { x.Mandante, x.Visitante },
            })
            .ToListAsync(cancellationToken);

        foreach (var partida in partidas)
        {
            var equipe = partida.Equipes.First(x => x.TimeId == notification.TimeId);

            var command = new AtualizarDadosEquipe(notification.TimeId, partida.Id)
            {
                Nome = equipe.Nome,
                Escudo = notification.Escudo,
            };

            await _bus.Send(command);
        }
    }
}

