using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Domain.Entities.Aggregates.Partidas;
using System;
using System.Threading;
using System.Threading.Tasks;

public class CreatePartidaHandler : IRequestHandler<CreatePartida, Guid>
{
    private readonly IPartidaRepository _repository;
    private readonly ITimeRepository _timeRepository;

    public CreatePartidaHandler(
        IPartidaRepository repository,
        ITimeRepository timeRepository)
    {
        _repository = repository;
        _timeRepository = timeRepository;
    }

    public async Task<Guid> Handle(CreatePartida request, CancellationToken cancellationToken)
    {
        var mandante = await _timeRepository.GetAsync(request.MandanteId);
        var visitante = await _timeRepository.GetAsync(request.VisitanteId);

        var partida = new Partida(request.RodadaId, request.MandanteId, request.VisitanteId, request.Data);

        partida.Mandante.Nome = mandante.Nome;
        partida.Mandante.Escudo = mandante.Escudo;
        partida.Visitante.Nome = visitante.Nome;
        partida.Visitante.Escudo = visitante.Escudo;

        _repository.Partidas.Add(partida);
        await _repository.SaveChangesAsync(cancellationToken);

        return partida.Id;
    }
}

