// Namespace: RealtimeMatches.Application.Partidas.Commands.CreatePartida
using FluentValidation;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Common.Repositories;

public class CreatePartidaValidator : CommandValidator<CreatePartida>
{
    public CreatePartidaValidator(
        ITemporadaRepository temporadaRepository,
        ITimeRepository timeRepository)
    {
        RuleFor(x => x.RodadaId).NotEmpty();
        RuleFor(x => x.VisitanteId).NotEmpty();
        RuleFor(x => x.MandanteId).NotEmpty();

        RuleFor(x => x.RodadaId).MustAsync(async (rodadaId, cancellation) =>
        {
            var exists = await temporadaRepository.Rodadas.AnyAsync(x => x.Id == rodadaId, cancellation);
            return exists;
        });

        RuleFor(x => x.VisitanteId).MustAsync(async (timeId, cancellation) =>
        {
            var exists = await timeRepository.Times.AnyAsync(x => x.Id == timeId, cancellation);
            return exists;
        });

        RuleFor(x => x.MandanteId).MustAsync(async (timeId, cancellation) =>
        {
            var exists = await timeRepository.Times.AnyAsync(x => x.Id == timeId, cancellation);
            return exists;
        });
    }
}

