    {
        var partida = await _repository.GetPartidaWithLancesById(request.AggregateId.Value);

        // ToDo: Tava causando lances repetidos.
        partida.Lances.Clear();

        if (partida.Situacao.Status == SituacaoStatus.Encerrada)
        {
            var lance = new Lance(partida.Id, Momento.Final());
            lance.FimDeJogo();

            partida.AdicionarLance(lance);
        }

        var lances = new List<Lance>();
        foreach (var command in request.Lances)
        {
            var lance = await _lanceFactory.Create(command);

            partida.AdicionarLance(lance);

        }

        if (partida.Lances.Count > 0 && partida.Lances.Any(x => x.Tipo == TipoLance.InicioDeJogo) is false)
        {
            var lance = new Lance(partida.Id, Momento.Inicial());
            lance.InicioDeJogo();

            partida.AdicionarLance(lance);
        }

        await _repository.SaveChangesAsync();

        return Unit.Value;
    }

