using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Models.Caching;
using System;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class LoadAndCacheLances
    {
        public class Contract : IRequest<Result>
        {
            public Guid PartidaId { get; set; }

            public Contract(Guid partidaId)
            {
                PartidaId = partidaId;
            }
        }

        public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IPartidaCacheService _partidaCacheService;
            private readonly IApplicationContext _applicationContext;

            public Handler(
                IPartidaCacheService partidaCacheService,
                IApplicationContext applicationContext)
            {
                _partidaCacheService = partidaCacheService;
                _applicationContext = applicationContext;
            }

            public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partida = await _applicationContext
                    .Partidas
                    .IgnoreQueryFilters()
                    .Include(p => p.Lances)
                    .FirstOrDefaultAsync(p => p.Id == request.PartidaId, cancellationToken: cancellationToken);

                if (partida == null)
                    return Result.Failure("Partida nao encontrada.");

                var orderedLances = partida
                    .Lances
                    .OrderByDescending(l => l)
                    .ToList();

                var lancesCache = orderedLances
                    .Select(l => new LanceCache(l)).ToList();
                await _partidaCacheService.SetLancesPartida(partida.Id, partida.Data, lancesCache);

                return Result.Success();
            }
        }
    }

