using AutoMapper;
using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Domain.Events.Estadios;
using RealtimeMatches.Domain.Projections.Estadios;
using System.Threading;
using System.Threading.Tasks;

public class EstadioEventsHandler :
    INotificationHandler<EstadioCriado>,
    INotificationHandler<EstadioAtualizado>
{
    private readonly IReadModelRepository<EstadioProjection> _readModel;
    private readonly IMapper _mapper;
    private readonly IEstadioRepository _repository;

    public EstadioEventsHandler(
        IMapper mapper,
        IEstadioRepository repository,
        IReadModelRepository<EstadioProjection> readModel)
    {
        _mapper = mapper;
        _repository = repository;
        _readModel = readModel;
    }

    public async Task Handle(EstadioCriado notification, CancellationToken cancellationToken)
    {
        var locker = await _readModel.AcquireLockAsync();

        var estadio = await _repository.GetEstadioById(notification.EstadioId);

        var projection = _mapper.Map<EstadioProjection>(estadio);

        await _readModel.SaveAsync(locker, projection);

        await _readModel.ReleaseLockAsync(locker);
    }

    public async Task Handle(EstadioAtualizado notification, CancellationToken cancellationToken)
    {
        var locker = await _readModel.AcquireLockAsync();

        var estadio = await _repository.GetEstadioById(notification.EstadioId);

        var projection = _mapper.Map<EstadioProjection>(estadio);

        await _readModel.SaveAsync(locker, projection);

        await _readModel.ReleaseLockAsync(locker);
    }
}

