using MediatR;
using RealtimeMatches.Application.Common.Repositories;
using System.Threading;
using System.Threading.Tasks;

public class AtualizarEstadioHandler : IRequestHandler<AtualizarEstadio>
{
    private readonly IEstadioRepository _repository;

    public AtualizarEstadioHandler(IEstadioRepository repository)
    {
        _repository = repository;
    }

    public async Task<Unit> Handle(AtualizarEstadio request, CancellationToken cancellationToken)
    {
        var estadio = await _repository.GetEstadioById(request.AggregateId.Value);

        if (request.Imagens != null)
        {
            estadio.AtualizarImagens(request.Imagens);
        }

        if (request.NomesAlternativos != null)
        {
            estadio.AtualizarNomesAlternativos(request.NomesAlternativos);
        }

        estadio.AtualizarInformacoes(request.Campo, request.Capacidade);

        estadio.AtualizarInformacoes(
            request.Nome,
            request.NomeCompleto,
            request.Descricao,
            request.Informacao,
            request.Historia,
            request.Curiosidade);

        estadio.AtualizarInformacoes(request.AnoInauguracao, request.Localizacao);

        await _repository.SaveChangesAsync(cancellationToken);

        return Unit.Value;
    }
}

