using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Events;
using System;
using System.Threading;
using System.Threading.Tasks;

public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IPartidaCacheService _partidaCacheService;
            private readonly IApplicationContext _applicationContext;

            public Handler(
                IPartidaCacheService partidaCacheService,
                IApplicationContext applicationContext)
            {
                _partidaCacheService = partidaCacheService;
                _applicationContext = applicationContext;
            }

            public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partida = await _applicationContext
                    .Partidas
                    .AsNoTracking()
                    .Include(p => p.Mandante)
                    .Include(p => p.Visitante)
                    .FirstOrDefaultAsync(p => p.Id == request.PartidaId, cancellationToken);

                if (partida == null)
                    return Result.Failure("Partida nao encontrada.");

                var partidaData = partida.Data;

                if (request.EscalacaoVisitante == null ||
                    request.EscalacaoMandante == null)
                {
                    return Result.Failure("Escalacao nao pode ser null.");
                }

                if (!request.EscalacaoVisitante.IsValid() ||
                    !request.EscalacaoMandante.IsValid())
                {
                    return Result.Failure("Escalacao inválida.");
                }

                var escalacaoOld = await _partidaCacheService.GetEscalacaoPartida(partida.Id, partida.Data);
                if (escalacaoOld == null)
                {
                    var escalacaoEvent = new PartidaEvent(partida, PartidaEventType.Escalacao, "Times escalados!")
                    {
                        Descricao = $"Veja a escalação para {partida.Mandante.Nome} x {partida.Visitante.Nome}"
                    };
                }

                var result = await _partidaCacheService.SetEscalacaoPartida(request.PartidaId, partidaData, request.EscalacaoMandante, request.EscalacaoVisitante);

                return result;
            }
        }

