            }
        }

        public class Handler : IRequestHandler<GetConfigContract, Result<GetConfigResponse>>
        {
            public Task<Result<GetConfigResponse>> Handle(GetConfigContract request, CancellationToken cancellationToken)
            {
                //var tabDays = _configuration.GetValue<int>("TabDays", 3);
                var tabDays = 3;

                var response = new GetConfigResponse();

                response.Tabs.Add("ontem");
                response.Tabs.Add("hoje");
