public class LoggingBehaviour<TRequest> : IRequestPreProcessor<TRequest>
{
    private readonly ILogger<LoggingBehaviour<object>> _logger;
    public LoggingBehaviour(ILogger<LoggingBehaviour<object>> logger)
    {
        _logger = logger;
    }

    public Task Process(TRequest request, CancellationToken cancellationToken)
    {
        var requestName = request.GetType().FullName.Split('.')[^1];

        _logger.LogDebug("Handling Request: {Name} {@Request}", requestName, request);

        return Task.CompletedTask;
    }
}

// File: Domain/RealtimeMatches.Commands/Common/Behaviours/UnhandledExceptionBehaviour.cs
// Namespace: RealtimeMatches.Application.Common.Behaviours
using MediatR;
using Microsoft.Extensions.Logging;
using System;
using System.Threading;
using System.Threading.Tasks;

public class UnhandledExceptionBehaviour<TRequest, TResponse> : IPipelineBehavior<TRequest, TResponse>
    {
        private readonly ILogger<TRequest> _logger;

        public UnhandledExceptionBehaviour(ILogger<TRequest> logger)
        {
            _logger = logger;
        }

        public async Task<TResponse> Handle(TRequest request, CancellationToken cancellationToken, RequestHandlerDelegate<TResponse> next)
        {
            var requestName = typeof(TRequest).Name;
            try
            {
                return await next();
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unhandled Exception for Request {Name} {@Request}", requestName, request);

                throw;
            }
        }
    }

