// Namespace: RealtimeMatches.Application.Common.Commands
using FluentValidation.Results;
using System;
using System.Linq;

public class CommandValidationException : Exception
{
    public CommandValidationException(string message) : base(message)
    {

    }

    public static CommandValidationException FromValidationResult(Command command, ValidationResult result)
    {
        var errorMessage = "Invalid Command " + command.GetType().Name + ": ";
        if (result?.Errors != null)
        {
            errorMessage += String.Join(' ', result.Errors.Select(x => x?.ErrorMessage));
        }

        return new CommandValidationException(errorMessage);
    }
}

