// File: Domain/RealtimeMatches.Commands/Common/Factories/PartidaRodadaFactory.cs
// Namespace: RealtimeMatches.Application.Common.Factories
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;
using RealtimeMatches.Domain.Entities.Aggregates.Times;
using RealtimeMatches.Domain.Enums;
using System.Linq;

public class PartidaRodadaFactory : IPartidaRodadaFactory
{
    public Rodada CreateRodadaGrupo(Temporada temporada, Time mandante, Time visitante)
    {
        foreach (var rodada in temporada.Rodadas.Where(x => x.IsGrupo))
        {
            if (rodada.Times.Any(x => x.TimeId == mandante.Id) && rodada.Times.Any(x => x.TimeId == visitante.Id))
            {
                return rodada;
            }
        }

        return null;
    }

    public Rodada CreateRodadaFase(Temporada temporada, MataMataChave chave)
        => temporada.Rodadas.FirstOrDefault(x => x.MataMata == chave);
}

