using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Domain.Entities.Aggregates.Tabelas.Fases.Grupos;
using RealtimeMatches.Domain.Entities.Aggregates.Temporadas;
using RealtimeMatches.Domain.Enums;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public interface ITemporadaRepository : IAggregateRepository<Temporada>
{
    DbSet<Temporada> Temporadas { get; }
    DbSet<Rodada> Rodadas { get; }

    Task<Temporada> FindTemporada(Guid campeonatoId, string nome, bool includeRodadas = false);
    Task<Rodada> FindRodada(Guid temporadaId, int? numero, string grupo, MataMataChave? mataMata, bool amistoso);

    Task<Temporada> GetTemporadaByRodadaId(Guid rodadaId, bool includeParticipantes = false)
    {
        var temporadaQuery = Temporadas.Include(x => x.Rodadas).AsQueryable();

        if (includeParticipantes)
        {
            temporadaQuery = temporadaQuery.Include(x => x.Participantes);
        }

        return temporadaQuery.FirstOrDefaultAsync(x => x.Rodadas.Any(x => x.Id == rodadaId));
    }

    Task<Temporada> GetTemporadaById(Guid temporadaId)
    {
        var temporada = Temporadas
            .Include(x => x.Rodadas)
            .Include(x => x.Participantes)
            .FirstAsync(x => x.Id == temporadaId);

        return temporada;
    }

    Task<Guid> GetTemporadaIdByRodada(Guid rodadaId)
        => Rodadas.Where(x => x.Id == rodadaId).Select(x => x.TemporadaId).FirstAsync();

    async Task<(bool, GrupoNome?)> IsRodadaGrupo(Guid rodadaId)
    {
        var rodadaGrupo = await Rodadas.Where(x => x.Id == rodadaId).Select(x => x.Grupo).FirstAsync();
        if (string.IsNullOrEmpty(rodadaGrupo))
        {
            return (false, null);
        }

        var grupo = Enum.Parse<GrupoNome>(rodadaGrupo.ToUpper());

        return (true, grupo);
    }

    Task<Rodada> GetRodadaById(Guid rodadaId)
        => Rodadas.IgnoreAutoIncludes().AsNoTracking().FirstAsync(x => x.Id == rodadaId);

    Task<List<Guid>> GetAllRodadasId(Guid temporadaId)
        => Rodadas.Where(x => x.TemporadaId == temporadaId).Select(x => x.Id).ToListAsync();

    Task<Guid> GetGrupoRodada(Guid temporadaId, GrupoNome grupo)
        => Rodadas.Where(x => x.TemporadaId == temporadaId && x.Grupo == grupo.ToString()).Select(x => x.Id).FirstAsync();
}

