using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Events;
using System;
using System.Collections.Generic;
using System.Threading.Tasks;

public class NotificationEventService : IPartidaEventService, IProviderEventService
    {
        private readonly IAlertService _alertService;

        public NotificationEventService(IAlertService alertService)
        {
            this._alertService = alertService;
        }

        public async Task Publish(PartidaEvent partidaEvent)
        {
            if (partidaEvent.Partida.Mandante.Id != Guid.Parse("3ca55ada-958b-eb35-c04f-3813a34cbedd") &&
                partidaEvent.Partida.Visitante.Id != Guid.Parse("3ca55ada-958b-eb35-c04f-3813a34cbedd"))
            {
                return;
            }

            if (partidaEvent.Partida.Status == PartidaStatus.Encerrada &&
                (
                    partidaEvent.EventType == PartidaEventType.Placar || 
                    partidaEvent.EventType == PartidaEventType.Escalacao
                ))
            {
                return;
            }

            await _alertService.SendAlert($"[{partidaEvent.EventType.ToString().ToUpper()}]\n\n\n" +
                $"{partidaEvent.Message}\n{partidaEvent.Descricao}", false);
        }

        public Task Publish(ProviderEvent providerEvent)
        {
            throw new NotImplementedException();
        }

        public async Task Publish(List<PartidaEvent> partidaEvents)
        {
            foreach (var @event in partidaEvents)
            {
                await Publish(@event);
            }
        }
    }

