        Mandante = new TimePartidaCache(partida.Mandante, partida.PlacarMandante, partida.PenaltiMandante);
        Visitante = new TimePartidaCache(partida.Visitante, partida.PlacarVisitante, partida.PenaltiVisitante);

        Estadio = partida.Estadio;
        EstadioImagem = partida.EstadioImagem;
        EstadioCidade = partida.EstadioCidade;
        EstadioCapacidade = partida.EstadioCapacidade;

        DestaqueMandante = partida.DestaqueMandante;
        DestaqueVisitante = partida.DestaqueVisitante;

        Importancia =
            (0 + 2 ^ (int)Campeonato.Importancia) +
            (3 + 2 ^ (int)Mandante.Importancia) +
            (6 + 2 ^ (int)Visitante.Importancia);

        Status = partida.Status switch
        {
            PartidaStatus.AoVivo => "ao vivo",
            PartidaStatus.Encerrada => "encerrada",
            _ => Data.ToString("HH:mm").Replace(":", "h")
        };

        StatusFixado = partida.StatusFixado;
    }

