public class GetOrAddCanalOperadora
    {
        public class Contract : ILockedRequest<CanalOperadora>
        {
            public CanalOperadora CanalOperadora { get; set; }

            public string LockKey => $"GetOrAddCanalOperadora_{CanalOperadora.OperadoraId}_{CanalOperadora.Nome}_{CanalOperadora.Numero}";

            public int TimeoutSeconds => 15;

            public Contract(CanalOperadora canalOperadora)
            {
                CanalOperadora = canalOperadora;
            }
        }

        public class Handler : IRequestHandler<Contract, CanalOperadora>
        {
            private readonly IApplicationContext _applicationContext;

            public Handler(IApplicationContext applicationContext)
            {
                _applicationContext = applicationContext;
            }

            public async Task<CanalOperadora> Handle(Contract request, CancellationToken cancellationToken)
            {
                var canalOperadora = request.CanalOperadora;

                var canalOperadoraDb = await _applicationContext
                                    .CanalOperadoras
                                    .Include(x => x.Canal)
                                    .Where(x => x.OperadoraId == canalOperadora.OperadoraId &&
                                                x.Numero == canalOperadora.Numero)
                                    .AsNoTracking()
                                    .FirstOrDefaultAsync(cancellationToken);

                if (canalOperadoraDb == null)
                {
                    _applicationContext.CanalOperadoras.Add(canalOperadora);
                    canalOperadoraDb = canalOperadora;

                    await _applicationContext.SaveChangesAsync(cancellationToken);
                }

                return canalOperadoraDb;
