// Namespace: RealtimeMatches.Application.Campeonatos.Commands
// Class: PartidaCollectionCommand.PartidaUpsertHandler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Application.Partidas.Commands;
using RealtimeMatches.Application.Times.Commands;
using RealtimeMatches.Domain.Entities;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var campeonatoId = request.Campeonato.ToGuid();

                var campeonato = await _applicationContext
                    .Campeonatos
                    .Include(c => c.Provider)
                    .FirstOrDefaultAsync(c => c.Id == campeonatoId, cancellationToken);
                if (campeonato == null)
                {
                    campeonato = new Campeonato(request.Campeonato, request.ProviderId)
                    {
                        Ano = request.Temporada.HasValue ? request.Temporada.Value : DateTime.UtcNow.Year,
                    };
                    _applicationContext.Campeonatos.Add(campeonato);

                    await _applicationContext.SaveChangesAsync(cancellationToken);
                }

                if (!campeonato.Ativo || campeonato.DeletedAt.HasValue)
                {
                    _logger.LogInformation($"Campeonato {request.Campeonato} desabilitado. Descartando...");
                    return Result.Success();
                }

                var rodadaAtual = request.Partidas
                    .Where(x => x.DataHorario.Date == DateTime.UtcNow.AddHours(-3).Date)
                    .OrderByDescending(x => x.Rodada)
                    .Select(x => x.Rodada)
                    .FirstOrDefault();

                if (!string.IsNullOrEmpty(rodadaAtual))
                {
                    if (rodadaAtual.Contains("Grupo"))
                    {
                        campeonato.RodadaAtual = "Fase de Grupos";
                    }
                    else
                    {
                        campeonato.RodadaAtual = rodadaAtual;
                    }
                }
                else
                    await _applicationContext.SaveChangesAsync(cancellationToken: cancellationToken);

                await _campeonatoCacheService.SetBaseCampeonato(campeonato);

                var partidaDias = new Dictionary<DateTime, List<PartidaAgregada>>();

                foreach (var partidaDto in request.Partidas)
                {
                    try
                    {
                        var mandanteRes = await _mediator.Send(new GetOrAddTimeCommand.Contract(request.ProviderId, partidaDto.TimeMandante), cancellationToken);

                        var visitanteRes = await _mediator.Send(new GetOrAddTimeCommand.Contract(request.ProviderId, partidaDto.TimeVisitante), cancellationToken);

                        if (mandanteRes.IsFailure || visitanteRes.IsFailure)
                        {
                            var error = string.Empty;

                            error += mandanteRes.IsFailure ? mandanteRes.Error : string.Empty;
                            error += visitanteRes.IsFailure ? visitanteRes.Error : string.Empty;

                            _logger.LogError($"Erro ao criar Partida do {campeonato.Nome}. " +
                                $"{partidaDto.TimeMandante} x {partidaDto.TimeVisitante} " +
                                $"{partidaDto.DataHorario:yyyy-MM-dd HH:mm}: {error}");

                            continue;
                        }

                        var partidaCommand = new CreateOrUpdatePartidaCommand.Contract(
                            partidaDto.Status,
                            mandanteRes.Value,
                            visitanteRes.Value,
                            campeonato,
                            partidaDto.DataHorario,
                            request.ProviderId)
                        {
                            PlacarMandante = partidaDto.TimeMandantePlacar,
                            PlacarVisitante = partidaDto.TimeVisitantePlacar,
                            PenaltiMandante = partidaDto.TimeMandantePenalti,
                            PenaltiVisitante = partidaDto.TimeVisitantePenalti,
                            Rodada = partidaDto.Rodada,
                            UrlTransmissao = partidaDto.UrlTransmissao,
                            TemHorario = partidaDto.TemHorario,
                            Estadio = partidaDto.Estadio
                        };

                        var partidaResult = await _mediator.Send(partidaCommand, cancellationToken);
                    }
                    catch (Exception e)
                    {
                        _logger.LogError(e, "Erro ao executar CreateOrUpdatePartidaCommand. Partida: {campeonato} {rodada} {mandante} x {visitante}", request.Campeonato, request.Rodada, partidaDto.TimeMandante, partidaDto.TimeVisitante);

                        continue;
                    }
                }

                return Result.Success();
            }

