public class CampeonatoEventsHandler : INotificationHandler<CampeonatoCriado>
{
    private readonly ICampeonatoRepository _repository;
    private readonly IReadModelRepository<CampeonatoProjection> _readModelRepository;
    private readonly IMapper _mapper;

    public CampeonatoEventsHandler(
        ICampeonatoRepository repository,
        IReadModelRepository<CampeonatoProjection> readModelRepository,
        IMapper mapper)
    {
        _repository = repository;
        _readModelRepository = readModelRepository;
        _mapper = mapper;
    }

    public async Task Handle(CampeonatoCriado notification, CancellationToken cancellationToken)
    {
        var campeonato = await _repository.GetAsync(notification.CampeonatoId);

        var projection = _mapper.Map<CampeonatoProjection>(campeonato);

        var locker = await _readModelRepository.AcquireLockAsync();

        await _readModelRepository.SaveAsync(locker, projection);

        await _readModelRepository.ReleaseLockAsync(locker);
    }
}

