// Namespace: RealtimeMatches.Application.Campeonatos.Queries
// Class: ListarCampeonatos.Handler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public async Task<Result<List<CampeonatoResponse>>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var campeonatos = await _cacheService.GetObjectAsync<List<CampeonatoResponse>>("RealtimeMatches:ListarCampeonatos");
                if (campeonatos != null)
                {
                    var response = new List<CampeonatoResponse>();

                    foreach (var camp in campeonatos)
                    {
                        var tabela = await _campeonatoCacheService.GetTabela(camp.Id);
                        if (tabela != null)
                            camp.Fases = tabela.Fases;

                        response.Add(camp);
                    }

                    return Result.Success(response);
                }

                var dateBefore = DateTime.UtcNow.AddHours(-3).AddDays(-1);
                var dateAfter = DateTime.UtcNow.AddHours(-3).AddDays(3);

                campeonatos = await _applicationContext
                    .Campeonatos
                    .Include(c => c.Partidas)
                    .Include(x => x.Classificacao)
                    .Where(c => c.Ativo &&
                                c.SempreMostrarTabela ||
                                (
                                    c.Partidas
                                    .Where(p =>
                                        p.Data > dateBefore &&
                                        p.Data < dateAfter
                                    ).Any()
                                )
                    )
                    .OrderByDescending(x => x.OrderingKey)
                    .ThenBy(x => x.Nome)
                    .AsNoTracking()
                    .Select(c => new CampeonatoResponse
                    {
                        Id = c.Id,
                        Nome = c.Nome,
                        Logo = c.Logo,
                        Ano = c.Ano,
                        Pais = c.Pais,
                        RodadaAtual = c.RodadaAtual,
                        Importancia = c.Importancia,
                        OrderKey = c.OrderingKey,
                        Partidas = c.Partidas.Where(p =>
                                        p.Data > dateBefore &&
                                        p.Data < dateAfter
                                    ).Count(),
                        ClassificacaoId = c.Classificacao == null ? null : c.Classificacao.Id
                    })
                    .ToListAsync(cancellationToken);

                foreach (var camp in campeonatos)
                {
                    if (!camp.ClassificacaoId.HasValue)
                        continue;

                    camp.Classificacao = await _campeonatoCacheService.GetClassificacao(camp.Id);
                }

                await _cacheService.SetObjectAsync("RealtimeMatches:ListarCampeonatos", campeonatos, TimeSpan.FromMinutes(5));

                return await Handle(request, cancellationToken);
            }

