using FluentValidation;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Commands;
using RealtimeMatches.Application.Common.Repositories;

public class CreateCampeonatoValidator : CommandValidator<CreateCampeonato>
{
    public CreateCampeonatoValidator(ICampeonatoRepository repository)
    {
        RuleFor(x => x.Nome).NotNull().NotEmpty();
        RuleFor(x => x.Slug).NotNull().NotEmpty();
        RuleFor(x => x.Organizacao).NotNull().IsInEnum();

        RuleFor(x => x.Nome).MustAsync(async (nome, cancellation) => 
        {
            var exists = await repository.Campeonatos.AnyAsync(x => x.Nome == nome, cancellation);
            return !exists;
        });

        RuleFor(x => x.Slug).MustAsync(async (slug, cancellation) =>
        {
            var exists = await repository.Campeonatos.AnyAsync(x => x.Slug == slug, cancellation);
            return !exists;
        });
    }
}

