public async Task<List<AgendaCobertura>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var agendas = await _context
                    .Agendas
                    .Where(a => a.Dia.Date == request.Date.Date)
                    .Include(a => a.Partida)
                        .ThenInclude(p => p.Mandante)
                    .Include(a => a.Partida)
                        .ThenInclude(p => p.Visitante)
                    .Include(x => x.Partida)
                        .ThenInclude(x => x.Campeonato)
                    .Include(p => p.Partida)
                        .ThenInclude(p => p.Provider)
                    .Include(p => p.Partida)
                        .ThenInclude(p => p.Campeonato)
                    .Include(a=>a.Cobertura)
                    .OrderByDescending(x => x.Partida.Campeonato.OrderingKey)
                    .Select(a => new AgendaCobertura
                    {
                        PartidaId = a.PartidaId,
                        UniqueKey = a.PartidaUniqueKey,
                        CampeonatoNome = a.Partida.Campeonato.Nome,
                        CampeonatoId = a.Partida.Campeonato.Id,
                        Rodada = a.Partida.Rodada,
                        Cobertura = a.Cobertura,
                        Mandante = a.Partida.Mandante.Nome,
                        MandanteId = a.Partida.Mandante.Id,
                        MandanteEscudo = a.Partida.Mandante.Escudo,
                        MandantePlacar = a.Partida.PlacarMandante,
                        Visitante = a.Partida.Visitante.Nome,
                        VisitanteId = a.Partida.Visitante.Id,
                        VisitanteEscudo = a.Partida.Visitante.Escudo,
                        VisitantePlacar = a.Partida.PlacarVisitante,
                        Provider = a.Partida.Provider,
                        PartidaStatus = a.Partida.Status,
                        Info = a.MotivoExibir,
                        Data = a.Dia
                    })
                    .AsNoTracking()
                    .ToListAsync(cancellationToken);

                foreach (var agenda in agendas)
                {
                    var coberturas = await _context
                        .Coberturas
                        .Include(x=>x.Provider)
                        .Where(x => x.PartidaUniqueKey == agenda.UniqueKey)
                        .AsNoTracking()
                        .ToListAsync(cancellationToken);

                    agenda.CoberturasDisponiveis = coberturas;
                }

                return agendas;
            }

