public static class ConfigureJobs
{
    public static WebApplication UseJobs(this WebApplication app)
    {
        using (var scope = app.Services.CreateScope())
        {
            var serviceProvider = scope.ServiceProvider;
            var scheduler = serviceProvider.GetService<ISchedulerFactory>().GetScheduler().Result;

            app.UseCrystalQuartz(() => scheduler);

            var job = JobBuilder.Create<PartidaDelaysAuditJob>().StoreDurably().WithIdentity(nameof(PartidaDelaysAuditJob)).Build();

            if (!scheduler.CheckExists(job.Key).Result)
            {
                scheduler.AddJob(job, true).Wait();

                var trigger = TriggerBuilder.Create()
                            .WithIdentity(nameof(PartidaDelaysAuditJob) + "Trigger")
                            .StartNow()
                            .WithSimpleSchedule(x => x
                                .WithInterval(TimeSpan.FromSeconds(20))
                                .RepeatForever()
                                .WithMisfireHandlingInstructionFireNow()
                            )
                            .ForJob(job)
                            .Build();

                scheduler.ScheduleJob(trigger).Wait();
            }

            var subsJob = JobBuilder.Create<SubscriptionsDiaJob>().StoreDurably().WithIdentity(nameof(SubscriptionsDiaJob)).Build();

            if (!scheduler.CheckExists(subsJob.Key).Result)
            {
                scheduler.AddJob(subsJob, true).Wait();

                var trigger = TriggerBuilder.Create()
                            .WithIdentity(nameof(SubscriptionsDiaJob) + "Trigger")
                            .StartNow()
                            .WithSimpleSchedule(x => x
                                .WithInterval(TimeSpan.FromHours(1))
                                .RepeatForever()
                                .WithMisfireHandlingInstructionFireNow()
                            )
                            .ForJob(subsJob)
                            .Build();

                scheduler.ScheduleJob(trigger).Wait();
            }
        }

        return app;
    }
}

