public PartidaDelaysAuditJob(
        IProviderMappingRepository mappingRepository,
        IReadModelRepository<PartidaProjection> readModel,
        IPartidaServiceFactory partidaServiceFactory,
        IReportService reportService,
        IApmService apmService)
    {
        _mappingRepository = mappingRepository;
        _readModel = readModel;
        _reportService = reportService;
        _apmService = apmService;

        _partidasProvider = DataProvider.ApiFootball;
        _partidasExternalIdMap ??= new Dictionary<Guid, string>();

        _partidaService = partidaServiceFactory.Create(_partidasProvider);
    }

