// Class: PartidaDelaysAuditJob
using Providers.Application.Abstractions.Services;
using Providers.Clients.Factories;
using Providers.Domain.Models.Enums;
using Quartz;
using RealtimeMatches.Application.Common.Repositories.ReadModels;
using RealtimeMatches.Application.Integrations.Profiles;
using RealtimeMatches.Application.Integrations.Repositories;
using RealtimeMatches.Audit.Api.Models.Reports.Partidas;
using RealtimeMatches.Audit.Api.Services;
using RealtimeMatches.Domain.Projections.Partidas;

public async Task Execute(IJobExecutionContext context)
    {
        var today = DateTime.UtcNow.AddHours(-3).Date;

        var sw = Stopwatch.StartNew();

        var findAllPartidasDomain = _readModel.FindAll(x => x.Data, today);
        var getPartidasProvider = _partidaService.GetPartidasDia(today, today.Year);

        await Task.WhenAll(findAllPartidasDomain, getPartidasProvider);

        var partidasDomain = await findAllPartidasDomain;
        var partidasProvider = await getPartidasProvider;

        foreach (var partidaDomain in partidasDomain)
        {
            var partidaDomainId = Guid.Parse(partidaDomain.Id);

            if (!_partidasExternalIdMap.ContainsKey(partidaDomainId))
            {
                var mapping = await _mappingRepository.GetByEntityId(_partidasProvider.ToString(), partidaDomainId);
                if (mapping == null)
                {
                    continue;
                }

                _partidasExternalIdMap[partidaDomainId] = mapping.ExternalId;
            }

            var partidaProvider = partidasProvider.First(x => x.Id == _partidasExternalIdMap[partidaDomainId]);

            var expectedSituacaoStatus = PartidasProfile.Map(partidaProvider.Status);

            if (partidaDomain.Situacao.Status != expectedSituacaoStatus)
            {
                var statusDelayed = new PartidaStatusDelayedAuditReport(partidaDomain, _partidasProvider, expectedSituacaoStatus);

                _reportService.Send(statusDelayed);
            }

            partidaDomain.Placar ??= new(0, 0);
            partidaProvider.Placar ??= new(0, 0);

            var (domainMandante, domainVisitante) = partidaDomain.Placar;
            var (providerMandante, providerVisitante) = partidaProvider.Placar;

            if (domainMandante != providerMandante || domainVisitante != providerVisitante)
            {
                var placarDelayed = new PartidaPlacarDelayedAuditReport(partidaDomain, _partidasProvider, new(providerMandante, providerVisitante));

                _reportService.Send(placarDelayed);
            }
        }

        sw.Stop();

        _apmService.RecordCustomEvent("PartidaDelaysAuditJobSummary", new()
        {
            { "PartidasDomain", partidasDomain.Count },
            { "PartidasProvider", partidasProvider.Count },
            { "Provider", _partidasProvider.ToString() },
            { "PartidasMapCached", _partidasExternalIdMap.Count },
            { "ProcessingMilliseconds", sw.ElapsedMilliseconds },
        });
    }

