using Quartz;
using RealtimeMatches.Application.Integrations.Clients;

public class SubscriptionsDiaJob : IJob
{
    private readonly IProviderClient _providerClient;

    public SubscriptionsDiaJob(IProviderClient providerClient)
    {
        _providerClient = providerClient;
    }

    public async Task Execute(IJobExecutionContext context)
    {
        var subscriptions = await _providerClient.GetDaysSubscriptions();
        var today = DateTime.UtcNow.AddHours(-3).Date;

        if (!subscriptions.Any(x => x.Day.Date == today))
        {
            var endDate = today.AddDays(1).AddHours(3);

            await _providerClient.Subscribe(new Providers.Shared.Requests.Subscriptions.TaskSubscriptionRequest
            {
                Provider = Providers.Domain.Models.Enums.DataProvider.ApiFootball,
                EndDate = endDate,
                IntervalSeconds = 20,
                Type = Providers.Domain.Models.Enums.ScheduleTaskType.PartidasDia,
                Data = new Dictionary<string, string>
                {
                    { "Day", today.ToString("yyyy-MM-dd") },
                    { "Season", today.Year.ToString() }
                }
            });
        }
    }
}

