using Providers.Domain.Models.Enums;
using RealtimeMatches.Domain.Projections.Partidas;

public abstract class PartidaBaseAuditReport : IAuditReport
{
    public string PartidaId { get; set; }
    public string Partida { get; set; }
    public DataProvider Provider { get; set; }
    public Guid RodadaId { get; set; }
    public Guid MandanteId { get; set; }
    public string MandanteNome { get; set; }
    public Guid VisitanteId { get; set; }
    public string VisitanteNome { get; set; }
    public DateTime Data { get; set; }

    public PartidaBaseAuditReport(PartidaProjection partida, DataProvider provider)
    {
        PartidaId = partida.Id;
        Partida = partida.GetReadableIdentifier();
        Provider = provider;
        RodadaId = partida.RodadaId;
        MandanteId = partida.Mandante.TimeId;
        MandanteNome = partida.Mandante.Nome;
        VisitanteId = partida.Visitante.TimeId;
        VisitanteNome = partida.Visitante.Nome;
        Data = partida.Data.GetValueOrDefault();
    }

    protected Dictionary<string, object> BaseAttributes => new()
    {
        { nameof(PartidaId), PartidaId},
        { nameof(Partida), Partida },
        { nameof(Provider), Provider.ToString() },
        { nameof(RodadaId), RodadaId },
        { nameof(MandanteId), MandanteId },
        { nameof(MandanteNome), MandanteNome },
        { nameof(VisitanteId), VisitanteId },
        { nameof(VisitanteNome), VisitanteNome },
        { nameof(Data), Data }
    };

    public abstract string ReportName { get; }
    public abstract Dictionary<string, object> Attributes { get; }
}

